export function localizedAgentGuidesPartL(en: Guides): Partial<Record<LandingLocaleCode, Guides>> {
  return {
    'nl': {
      'claude-code': {
        ...en['claude-code']!,
        title: "Claude Code voor design — Open Design",
        description: "Hoe designers Claude Code gebruiken voor UI- en webdesign, en hoe Open Design er een echte design-agent van maakt — local-first, BYOK, met een samengestelde bibliotheek van skills en design systems.",
        breadcrumb: "Claude Code",
        label: "Agent · Claude Code",
        heading: "Claude Code voor design.",
        lead: "Claude Code is de terminal-coding-agent van Anthropic. Mensen gebruiken hem al om UI's, design systems en landingspagina's te bouwen. Open Design koppelt hem aan een echte design-workflow — neem je Anthropic-key of Claude-abonnement mee en houd elk bestand lokaal.",
        rich: {"heroCtaLead": "Open Design maakt van Claude Code een local-first, open-source design-agent — je Anthropic-key of Claude-abonnement, je bestanden, en een samengestelde bibliotheek van skills en design systems eromheen.", "heroCtaActions": [{"label": "Gebruik Claude Code binnen Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Claude Code wordt algemeen beschouwd als de coding-agent met de beste frontend-smaak — hij redeneert met ongewone precisie over interfaces, noemt exacte hex-waarden, spacing en typeschalen, en refactort UI in een grote codebase zonder de draad kwijt te raken. Maar standaard neigt hij toch naar een generieke look, tenzij je hem een design system, skills en echte referenties aanreikt. Dit is een praktische, end-to-end gids voor het gebruik van Claude Code voor UI-, frontend- en design-system-werk, en voor het inbedden ervan in een gestructureerde workflow met Open Design.", "Het behandelt wat Claude Code precies is, waarom hij sterk is in frontend, hoe je hem vanaf nul opzet, de CLAUDE.md- en Skills-workflow, de officiële Figma-round-trip, hoe hij zich verhoudt tot Codex en Cursor, de valkuilen die AI-output generiek doen ogen, en hoe Open Design de kloof dicht als een open, local-first designlaag."], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "Feedbacklus van Claude Code-design: terminal-agent die specifieke designbeslissingen neemt, een browser die de UI rendert, en een werkruimte, met een feedbackpijl die terugloopt", "caption": "De kernlus: Claude Code redeneert specifieke UI-beslissingen uit in de terminal, rendert en verifieert ze in een echte browser, en convergeert naar je referenties."}, "tocLabel": "Op deze pagina", "toc": [{"id": "what-is-claude-code", "label": "Wat Claude Code precies is"}, {"id": "why-design", "label": "Waarom Claude Code goed is in design"}, {"id": "setup", "label": "Claude Code instellen voor design (vanaf nul)"}, {"id": "skills-workflow", "label": "De CLAUDE.md- en Skills-workflow"}, {"id": "figma", "label": "Claude Code + Figma-round-trip"}, {"id": "vs", "label": "Claude Code vs Codex vs Cursor"}, {"id": "pitfalls", "label": "Valkuilen en de “AI slop”-look"}, {"id": "open-design", "label": "Designen met Claude Code in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-claude-code", "heading": "Wat Claude Code precies is", "blocks": [{"kind": "p", "text": "Claude Code is de agentic coding-tool van Anthropic. Hij leest je codebase, bewerkt bestanden, voert commando's uit en integreert met je dev-tools — hij plant, schrijft en verifieert werk op basis van taken in natuurlijke taal in plaats van alleen regels aan te vullen."}, {"kind": "p", "text": "Hij komt in meerdere vormen die allemaal dezelfde engine delen: een terminal-CLI, IDE-extensies voor VS Code, Cursor en JetBrains, een desktop-app met visuele diff-review, en een web-ervaring voor langlopende taken. Je CLAUDE.md-bestanden, instellingen en MCP-servers reizen overal mee."}, {"kind": "steps", "items": [{"label": "Instructiebestand", "body": "Claude Code leest aan het begin van elke sessie een CLAUDE.md-bestand in je projectroot — de natuurlijke plek om je designconventies, tokens en review-checklists vast te leggen."}, {"label": "Skills", "body": "Agent Skills bundelen herbruikbare instructies, scripts en resources die Claude op aanvraag laadt, waaronder Anthropics officiële Frontend Design-skill voor smaak."}, {"label": "Plan en subagents", "body": "Hij kan plannen voordat hij handelt en subagents opstarten die parallel aan verschillende delen van een taak werken, wat grote UI-refactors coherent houdt."}]}, {"kind": "ul", "items": ["Leverancier: Anthropic", "Credential: Anthropic API-key (BYOK, via de Console) of een Claude-abonnement (Pro / Max)", "Vormen: terminal-CLI, VS Code- / Cursor- / JetBrains-extensies, desktop-app, web"]}]}, {"id": "why-design", "heading": "Waarom Claude Code goed is in design", "blocks": [{"kind": "p", "text": "Onder coding-agents heeft Claude Code een reputatie voor smaak in frontend-werk. Een paar dingen verklaren dat."}, {"kind": "steps", "items": [{"label": "Specifieke, niet vage, beslissingen", "body": "Claude Code neigt naar concrete keuzes — exacte hex-waarden, spacing-schalen, typeschalen en componenthiërarchie — in plaats van vaagheid, en dat is wat een echte interface onderscheidt van een placeholder."}, {"label": "Codebase-bewust redeneren", "body": "Met een grote werkcontext refactort hij UI over veel bestanden tegelijk en hergebruikt hij je bestaande componenten en tokens in plaats van eenmalige stijlen opnieuw uit te vinden."}, {"label": "Een officiële frontend-skill", "body": "Anthropic levert een Frontend Design-skill die Claude eerst een designrichting laat schrijven en bewust wegstuurt van generieke systeemlettertypen en voorspelbare paarse gradiënten."}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "Diagram dat laat zien hoe design system, skill en referentiebeeld samenkomen tot goede design-output", "caption": "Smaak komt voort uit drie inputs die jij aanlevert: een design system, een skill en echte referentiebeelden."}, {"kind": "p", "text": "De les is dezelfde die Anthropic over zijn eigen modellen maakt: Claude heeft standaard geen smaak — aan zichzelf overgelaten convergeert hij naar het statistische midden van webdesign (Inter, paarse gradiënten, zachte schaduwen). Hij levert goed design wanneer je hem beperkingen geeft. Open Design verpakt precies die inputs, en daarom passen de twee samen (meer hieronder)."}]}, {"id": "setup", "heading": "Claude Code voor designwerk opzetten, vanaf nul", "blocks": [{"kind": "p", "text": "Dit is het volledige pad van een schone machine naar een Claude Code die UI kan bouwen en verifiëren."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "Setupflow in vijf stappen: installeren, authenticeren, CLAUDE.md configureren, skill toevoegen, verifiëren", "caption": "De setup-volgorde: installeren → authenticeren → CLAUDE.md configureren → de Frontend Design-skill toevoegen → browserverificatie inschakelen."}, {"kind": "steps", "items": [{"label": "Leg je designregels vast", "body": "Zet je tokens, primitives en conventies in CLAUDE.md en wijs Claude erop, zodat de output bij een merk past in plaats van terug te vallen op een generieke look."}, {"label": "Voeg browserverificatie toe", "body": "Koppel een Playwright- of Chrome-MCP zodat Claude in een echte browser rendert en zijn output over breakpoints heen controleert, in plaats van alleen te bevestigen dat de build slaagt."}]}]}, {"id": "skills-workflow", "heading": "De CLAUDE.md- en Skills-workflow", "blocks": [{"kind": "p", "text": "De design-lus met de meeste hefboomwerking bij Claude Code is hem echte referenties plus je designcontext voeden en dan itereren tot de UI klopt — met CLAUDE.md en Skills die de beperkingen vasthouden, zodat je ze niet bij elke prompt opnieuw hoeft uit te leggen."}, {"kind": "ol", "items": ["Begin met de helderste visuele referenties die je hebt — en neem meerdere states mee (desktop en mobiel, hover, leeg, laden), niet alleen één hero-shot.", "Wees specifiek in de prompt; vage prompts leveren generieke UI op, zelfs met een sterke agent.", "Houd je design system en conventies in CLAUDE.md en vertel Claude waar de tokens en canonieke primitives staan.", "Voeg de Frontend Design-skill toe zodat Claude zich vastlegt op een echte esthetische richting voordat hij code schrijft.", "Koppel browserverificatie zodat Claude rendert, naar breakpoints herschaalt en terugvergelijkt met de referenties — niet alleen bevestigt dat het bouwt."]}, {"kind": "p", "text": "Sleep een referentiebeeld in de sessie en prompt met concrete beperkingen:"}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "Draai er een dev-server naast, houd prompts klein en gericht, en commit goede iteraties / draai slechte terug (vertel Claude wanneer je terugdraait) zodat elke ronde voortbouwt op een schone basis. Gebruik plan-mode voor grotere refactors zodat je de aanpak kunt beoordelen voordat er bestanden veranderen."}]}, {"id": "figma", "heading": "Claude Code + Figma: design ↔ code-round-trip", "blocks": [{"kind": "p", "text": "In februari 2026 leverden Anthropic en Figma een eersteklas, bidirectionele integratie via de Figma MCP-server. Hij werkt in beide richtingen."}, {"kind": "steps", "items": [{"label": "Design → Code", "body": "Selecteer een frame in Figma of plak een link in Claude Code, haal de designcontext op en vraag hem het design te implementeren met je bestaande componentbibliotheek. Code Connect houdt de output uitgelijnd met je echte componenten."}, {"label": "Code → Design", "body": "Bouw en bekijk een feature in de browser en zeg dan “Send this to Figma” om de draaiende UI vast te leggen als bewerkbare Figma-lagen — het hele scherm of een geselecteerd element."}]}, {"kind": "p", "text": "Installeer hem eenmalig met claude plugin install figma@claude-plugins-official (Dev Mode MCP vereist een betaald Figma-plan). Dezelfde Figma MCP is beschikbaar voor Claude Code, Codex, Cursor en VS Code — precies het soort draagbare, multi-agent-capaciteit dat Open Design is gebouwd om te orkestreren."}]}, {"id": "vs", "heading": "Claude Code vs Codex vs Cursor voor design", "blocks": [{"kind": "p", "text": "Er is geen enkele winnaar voor designwerk — elke agent heeft een andere kracht, en ervaren teams stapelen ze. Een eerlijke samenvatting:"}, {"kind": "table", "columns": ["Agent", "Design-kracht", "Beste voor"], "rows": [["Claude Code", "Specifieke designbeslissingen (hex, spacing, type) en codebase-bewust UX-redeneren", "Frontend-redeneren en refactors met grote context"], ["Codex", "Sterke visuele afwerking en beeldbegrip; gesandboxte async builds", "Gedelegeerde async builds en draagbare AGENTS.md-regels"], ["Cursor", "Visuele build-and-see-lus met live preview en inline edits", "Strak itereren-en-bekijken van UI-werk binnen een IDE"]]}, {"kind": "p", "text": "Het terugkerende oordeel van de community is dat smaak van mensen komt: alle drie vallen zonder skills, referenties en beperkingen terug op een generieke esthetiek. Dat is het echte probleem dat opgelost moet worden — en het heeft de vorm van een design-tool, niet van een model."}]}, {"id": "pitfalls", "heading": "Valkuilen, en hoe je de “AI slop”-look vermijdt", "blocks": [{"kind": "p", "text": "Zelfs met Claude Code's reputatie voor smaak is de meest voorkomende klacht over AI-gegenereerd design dat het generiek oogt — Inter-lettertypen, paarse gradiënten op wit, zachte schaduwen, te grote afgeronde hoeken, een esthetiek die “schreeuwt dat een AI dit maakte.” Anthropic zelf schrijft dit toe aan distributionele convergentie: veilige keuzes domineren de trainingsdata van het web. Andere gemelde problemen zijn kapotte mobiele layouts en instructies die in de UI-tekst lekken."}, {"kind": "steps", "items": [{"label": "Installeer de Frontend Design-skill", "body": "Hij dwingt Claude zich op een echte richting vast te leggen en vermijdt expliciet lettertypen en gradiënten die door AI worden overgebruikt."}, {"label": "Schakel browserverificatie in", "body": "Laat Claude renderen en zichzelf controleren over breakpoints heen, zodat layouts niet stilletjes breken op mobiel."}, {"label": "Lever tokens en referenties aan", "body": "Echte design-tokens en referentie-screenshots zijn de grootste hefboom op de outputkwaliteit."}, {"label": "Leg regels vast in CLAUDE.md", "body": "Zet stijlregels als “geen hero cards, maximaal twee lettertypen, merk-eerste hiërarchie” daar waar de agent ze elke ronde leest."}]}, {"kind": "p", "text": "Merk op dat elke remedie draait om het geven van een samengestelde designcontext aan de agent. Die context met de hand onderhouden, per project, is precies het sleurwerk dat Open Design wegneemt."}]}, {"id": "open-design", "heading": "Designen met Claude Code binnen Open Design", "blocks": [{"kind": "p", "text": "Open Design is de open-source designlaag waar de workflow hierboven steeds om vraagt. Het behandelt Claude Code als een first-party adapter en omhult hem met een samengestelde bibliotheek van skills en design systems, een gestructureerde render-pipeline en een lokale desktop-UI — zodat de designcontext die Claude Code goed maakt er vanaf de eerste run is, niet elke keer met de hand samengesteld."}, {"kind": "ol", "items": ["Installeer Open Design en kies Claude Code als je agent.", "Authenticeer met je Anthropic API-key (BYOK) of Claude-abonnement — credentials blijven op je machine en worden nooit via ons doorgesluisd.", "Kies een design system en een skill, en genereer vervolgens decks, prototypes en landingspagina's met consistente smaak.", "Elk artefact en DESIGN.md-bestand staat in je eigen repo, niet in een gehoste cloud."]}, {"kind": "p", "text": "Dezelfde Claude Code-agent, dezelfde key — plus een echte, draagbare, open-source design-workflow eromheen. Het is local-first en Apache-2.0, dus niets over je werk of je credentials verlaat je machine."}]}], "faqTitle": "Veelgestelde vragen", "faq": [{"name": "Is Claude Code goed voor designwerk?", "text": "Ja — hij wordt algemeen beschouwd als de coding-agent met de beste frontend-smaak, die specifieke, codebase-bewuste beslissingen neemt over hex-waarden, spacing en typeschalen. Met de Frontend Design-skill, een design system en echte referentiebeelden in context produceert hij responsieve UI van productiekwaliteit en kan hij die in een browser verifiëren. Zonder die context neigt hij naar een generieke look, en dat is de kloof die Open Design dicht."}, {"name": "Heb ik een Claude-abonnement nodig om te designen met Claude Code?", "text": "Je kunt zowel een Anthropic API-key (BYOK, via de Console) als een Claude-abonnement (Pro / Max) gebruiken. Hoe dan ook sluist Open Design je credentials nooit door — ze worden direct gebruikt door je agent op je machine."}, {"name": "Claude Code of Codex voor frontend-design?", "text": "Beide zijn sterk. Claude Code staat bekend om specifieke, codebase-bewuste designbeslissingen en frontend-redeneren; Codex heeft sterke visuele afwerking en blinkt uit in gedelegeerde, gesandboxte builds. Veel teams gebruiken beide — met Open Design wissel je van agent zonder je design-workflow te veranderen."}, {"name": "Hoe verbind ik Claude Code met Figma?", "text": "Installeer de officiële Figma-plugin met claude plugin install figma@claude-plugins-official. Je kunt dan Figma-frames in code implementeren met de designcontext, en een draaiende UI terugduwen naar bewerkbare Figma-frames met “Send this to Figma.” Dev Mode MCP vereist een betaald Figma-plan."}, {"name": "Wat zijn Skills en CLAUDE.md?", "text": "CLAUDE.md is een markdown-bestand in je projectroot dat Claude Code aan het begin van elke sessie leest — de plek om je designconventies vast te leggen. Skills bundelen herbruikbare instructies en resources die Claude op aanvraag laadt, waaronder Anthropics officiële Frontend Design-skill. Open Design levert een samengestelde bibliotheek van beide, zodat je de setup per project overslaat."}, {"name": "Hoe vermijd ik de generieke “AI slop”-esthetiek?", "text": "Installeer de Frontend Design-skill, lever echte design-tokens en referentie-screenshots aan, leg merkregels vast in CLAUDE.md en schakel browserverificatie in. Open Design levert deze als een samengestelde bibliotheek, zodat je de setup per project overslaat."}, {"name": "Is Open Design gelieerd aan Anthropic?", "text": "Nee. Claude Code is een product van Anthropic; Open Design is een onafhankelijk open-source project dat hem ondersteunt als first-party adapter. Claude en Claude Code zijn handelsmerken van Anthropic."}, {"name": "Zijn mijn bestanden en credentials veilig?", "text": "Ja — Open Design is local-first en Apache-2.0. Je bestanden, artefacten en DESIGN.md blijven in je eigen repo, en je Anthropic-credentials worden direct gebruikt door je agent, nooit via Open Design-servers geleid."}], "ctaTitle": "Design met Claude Code, op de open manier.", "ctaBody": "Neem je eigen Anthropic-key of Claude-abonnement mee, houd elk bestand lokaal, en krijg een samengestelde design-bibliotheek rondom de agent die je al gebruikt.", "ctaActions": [{"label": "Gebruik Claude Code binnen Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Bekijk alle ondersteunde agents"},
      },
      'codex': {
        ...en['codex']!,
        title: "Codex voor design — Open Design",
        description: "Hoe mensen OpenAI Codex gebruiken voor UI- en webdesign — de Product Design-plugin, Figma-integratie, frontend-skills — en hoe Open Design er een local-first, open-source design-agent van maakt.",
        breadcrumb: "Codex",
        label: "Agent · Codex",
        heading: "Codex voor design.",
        lead: "Codex is de coding-agent van OpenAI. Met de Product Design-plugin en Figma-integratie is het een serieuze design-tool geworden. Open Design koppelt Codex aan een open-source design-workflow — je OpenAI-key of ChatGPT-abonnement, je bestanden, local-first.",
        rich: {"heroCtaLead": "Open Design maakt van Codex een local-first, open-source design-agent — je OpenAI-key, je bestanden, en een samengestelde bibliotheek van skills en design systems eromheen.", "heroCtaActions": [{"label": "Gebruik Codex binnen Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenAI Codex begon als codegenerator, maar werd in 2026 een geloofwaardige tool voor het ontwerpen van echte interfaces — zodra je hem de juiste referenties, skills en verificatielus geeft. Dit is een praktische, end-to-end gids voor het gebruik van Codex voor UI-, frontend- en design-system-werk, en voor het inbedden ervan in een gestructureerde design-workflow met Open Design.", "Het behandelt wat Codex vandaag is, waarom hij plotseling goed is in frontend, hoe je hem vanaf nul opzet, de screenshot-naar-UI-lus, de officiële Figma-round-trip, hoe hij zich verhoudt tot Cursor en Claude Code, de valkuilen die AI-output generiek doen ogen, en hoe Open Design de kloof dicht als een open, local-first designlaag."], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "Feedbacklus van Codex-design: terminal-agent, browser die de UI rendert, en een werkruimte, met een feedbackpijl die terugloopt", "caption": "De kernlus: Codex bouwt UI in de terminal, rendert en verifieert die in een echte browser, en itereert tegen je referenties."}, "tocLabel": "Op deze pagina", "toc": [{"id": "what-is-codex", "label": "Wat OpenAI Codex precies is"}, {"id": "why-design", "label": "Waarom Codex nu goed is in design"}, {"id": "setup", "label": "Codex instellen voor design (vanaf nul)"}, {"id": "screenshot-workflow", "label": "De screenshot-naar-UI-workflow"}, {"id": "figma", "label": "Codex + Figma-round-trip"}, {"id": "vs", "label": "Codex vs Cursor vs Claude Code"}, {"id": "pitfalls", "label": "Valkuilen en de “AI slop”-look"}, {"id": "open-design", "label": "Designen met Codex in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-codex", "heading": "Wat OpenAI Codex precies is (en wat niet)", "blocks": [{"kind": "p", "text": "Eerst een verduidelijking die bijna iedereen die op “Codex” zoekt op het verkeerde been zet. De oorspronkelijke OpenAI Codex was een code-completion-model uit 2021 dat de vroege GitHub Copilot aandreef en in 2023 werd uitgefaseerd. Daar gaat deze pagina niet over. De Codex van vandaag is de agentic coding-tool van OpenAI — hij plant, schrijft, draait en verifieert code op basis van taken in natuurlijke taal."}, {"kind": "p", "text": "De moderne Codex komt in vier vormen: een terminal-CLI (herschreven in Rust, gelicentieerd onder Apache-2.0), een IDE-extensie voor VS Code, Cursor en Windsurf, een cloud-/web-ervaring voor gedelegeerde async-taken, en een desktop-app met een ingebouwde browser en Computer Use."}, {"kind": "steps", "items": [{"label": "Standaardmodel", "body": "Vanaf medio 2026 is het aanbevolen model gpt-5.5, waarbij gpt-5.4 het model is dat OpenAI expliciet trainde voor frontend en computer use."}, {"label": "Instructiebestand", "body": "Codex leest een AGENTS.md-bestand in je project (een cross-tool-standaard) voor projectregels — de natuurlijke plek om je designconventies vast te leggen."}, {"label": "Sandbox", "body": "Hij draait in een sandbox op kernelniveau (standaard workspace-write), zodat een agent die je UI bewerkt niet buiten het project kan dwalen."}]}, {"kind": "ul", "items": ["Leverancier: OpenAI", "Credential: OpenAI API-key (BYOK) of ChatGPT-abonnement (Free / Go / Plus / Pro / Business / Enterprise)", "Licentie van de CLI: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Waarom Codex nu goed is in design", "blocks": [{"kind": "p", "text": "Begin 2026 kwamen drie dingen samen die van Codex een echte design-tool maakten in plaats van een generieke codegenerator."}, {"kind": "steps", "items": [{"label": "Een frontend-getraind model", "body": "OpenAI leverde GPT-5.4, het eerste mainline-model getraind voor frontend en computer use, met veel beter beeldbegrip over de hele design-workflow en sterkere zelfverificatie. Het kan zelfs mood boards en visuele opties genereren voordat het zich vastlegt op de definitieve assets."}, {"label": "Een officiële frontend-skill", "body": "De openai/skills-catalogus levert een samengestelde frontend-skill die echte smaak afdwingt: cardloze layouts, full-bleed hero's, merk-eerste hiërarchie, ingetogen beweging, hooguit twee lettertypen en één accentkleur — en laat Codex een visuele these schrijven voordat hij bouwt."}, {"label": "Browserverificatie", "body": "Met de Playwright-skill opent Codex een echte browser, herschaalt naar breakpoints en vergelijkt zijn output terug met de referentie in plaats van alleen te controleren of de build slaagt."}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "Diagram dat laat zien hoe design system, skill en referentiebeeld samenkomen tot goede design-output", "caption": "Smaak komt voort uit drie inputs die jij aanlevert: een design system, een skill en echte referentiebeelden."}, {"kind": "p", "text": "De les achter alle drie: Codex heeft standaard geen smaak. Hij levert goed design wanneer je hem beperkingen geeft — een design system, een esthetische skill en concrete referenties. Open Design verpakt precies die inputs, en daarom passen de twee samen (meer hieronder)."}]}, {"id": "setup", "heading": "Codex voor designwerk opzetten, vanaf nul", "blocks": [{"kind": "p", "text": "Dit is het volledige pad van een schone machine naar een Codex die UI kan bouwen en verifiëren."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "Setupflow in vijf stappen: installeren, authenticeren, configureren, skill installeren, verifiëren", "caption": "De setup-volgorde: installeren → authenticeren → AGENTS.md configureren → de frontend-skill installeren → browserverificatie inschakelen."}, {"kind": "steps", "items": [{"label": "Leg je designregels vast", "body": "Zet je tokens, primitives en conventies in AGENTS.md of een DESIGN.md en wijs Codex erop, zodat de output bij een merk past in plaats van terug te vallen op een generieke look."}, {"label": "Kies het juiste reasoning-niveau", "body": "OpenAI merkt op dat laag-tot-gemiddelde reasoning-niveaus vaak sterkere frontend-resultaten opleveren dan de hoogste instelling."}]}]}, {"id": "screenshot-workflow", "heading": "De screenshot-naar-UI-workflow", "blocks": [{"kind": "p", "text": "De design-lus met de meeste hefboomwerking bij Codex is een referentiebeeld omzetten in werkende, responsieve UI en itereren tot het klopt. OpenAI's eigen richtlijnen komen neer op vijf stappen."}, {"kind": "ol", "items": ["Begin met de helderste visuele referenties die je hebt — en neem meerdere states mee (desktop en mobiel, hover, leeg, laden), niet alleen één hero-shot.", "Wees specifiek in de prompt; vage prompts leveren generieke UI op.", "Bereid een design system voor en vertel Codex waar de tokens en canonieke primitives staan.", "Schakel de interactieve Playwright-skill in zodat Codex in een echte browser rendert en naar breakpoints herschaalt.", "Itereer door Codex zijn implementatie terug te laten vergelijken met de screenshots — niet alleen te bevestigen dat het bouwt."]}, {"kind": "p", "text": "Voer beelden in door een screenshot in de terminal te slepen of met de image-flag, en prompt dan met concrete beperkingen:"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "Draai een dev-server in een tweede terminal, houd prompts klein en gericht, en commit goede iteraties / draai slechte terug (vertel Codex wanneer je terugdraait) zodat elke ronde voortbouwt op een schone basis."}]}, {"id": "figma", "heading": "Codex + Figma: design ↔ code-round-trip", "blocks": [{"kind": "p", "text": "In februari 2026 kondigden OpenAI en Figma een officieel partnerschap aan, waarmee de eerdere Figma MCP-bèta een eersteklas, bidirectionele integratie werd. Hij werkt in beide richtingen."}, {"kind": "steps", "items": [{"label": "Design → Code", "body": "Kopieer de “link to selection” van een frame in Figma, plak die in Codex met get_design_context en vraag hem het design te implementeren met je bestaande componentbibliotheek."}, {"label": "Code → Design", "body": "De generate_figma_design-tool (“Code to Canvas”) zet een live, draaiende UI terug om in bewerkbare Figma-frames — het hele scherm, een geselecteerd element of een heel bestand."}]}, {"kind": "p", "text": "De Figma MCP draait als een remote server en is vrijgesteld van rate limits. Voeg hem eenmalig toe en hij is beschikbaar voor Codex, Claude Code, Cursor, VS Code en meer — precies het soort draagbare, multi-agent-capaciteit dat Open Design is gebouwd om te orkestreren."}]}, {"id": "vs", "heading": "Codex vs Cursor vs Claude Code voor design", "blocks": [{"kind": "p", "text": "Er is geen enkele winnaar voor designwerk — elke agent heeft een andere kracht, en ervaren teams stapelen ze. Een eerlijke samenvatting:"}, {"kind": "table", "columns": ["Agent", "Design-kracht", "Beste voor"], "rows": [["Codex", "Sterke visuele afwerking na GPT-5.4 + frontend-skill; beeldbegrip", "Gedelegeerde async builds, gesandboxte runs, draagbare AGENTS.md-regels"], ["Cursor", "Visuele build-and-see-lus met live preview en inline edits", "Strak itereren-en-bekijken van UI-werk binnen een IDE"], ["Claude Code", "Specifieke designbeslissingen (hex, spacing, type) en codebase-bewuste UX", "Frontend-redeneren en refactors met grote context"]]}, {"kind": "p", "text": "Het terugkerende oordeel van de community is dat smaak van mensen komt: alle drie vallen zonder skills, referenties en beperkingen terug op een generieke esthetiek. Dat is het echte probleem dat opgelost moet worden — en het heeft de vorm van een design-tool, niet van een model."}]}, {"id": "pitfalls", "heading": "Valkuilen, en hoe je de “AI slop”-look vermijdt", "blocks": [{"kind": "p", "text": "De meest voorkomende klacht over door Codex gegenereerd design is dat het generiek oogt — zachte gradiënten, zwevende panelen, te grote afgeronde hoeken, dramatische schaduwen, een Inter-en-paars-sfeer die “schreeuwt dat een AI dit maakte.” Andere gemelde problemen zijn kapotte mobiele layouts, instructies die in de UI-tekst lekken en het snel bereiken van gebruikslimieten."}, {"kind": "steps", "items": [{"label": "Installeer een frontend-skill", "body": "Een samengestelde esthetische skill dwingt Codex zich op een echte richting vast te leggen in plaats van de standaard look."}, {"label": "Schakel Playwright-verificatie in", "body": "Laat Codex renderen en zichzelf controleren over breakpoints heen, zodat layouts niet stilletjes breken op mobiel."}, {"label": "Lever tokens en referenties aan", "body": "Echte design-tokens en referentie-screenshots zijn de grootste hefboom op de outputkwaliteit."}, {"label": "Leg regels vast in AGENTS.md", "body": "Zet stijlregels als “geen hero cards, maximaal twee lettertypen, merk-eerste hiërarchie” daar waar de agent ze elke ronde leest."}]}, {"kind": "p", "text": "Merk op dat elke remedie draait om het geven van een samengestelde designcontext aan de agent. Die context met de hand onderhouden, per project, is precies het sleurwerk dat Open Design wegneemt."}]}, {"id": "open-design", "heading": "Designen met Codex binnen Open Design", "blocks": [{"kind": "p", "text": "Open Design is de open-source designlaag waar de workflow hierboven steeds om vraagt. Het behandelt Codex als een first-party adapter en omhult hem met een samengestelde bibliotheek van skills en design systems, een gestructureerde render-pipeline en een lokale desktop-UI — zodat de designcontext die Codex goed maakt er vanaf de eerste run is, niet elke keer met de hand samengesteld."}, {"kind": "ol", "items": ["Installeer Open Design en kies Codex als je agent.", "Authenticeer met je OpenAI API-key (BYOK) of ChatGPT-abonnement — credentials blijven op je machine en worden nooit via ons doorgesluisd.", "Kies een design system en een skill, en genereer vervolgens decks, prototypes en landingspagina's met consistente smaak.", "Elk artefact en DESIGN.md-bestand staat in je eigen repo, niet in een gehoste cloud."]}, {"kind": "p", "text": "Dezelfde Codex-agent, dezelfde key — plus een echte, draagbare, open-source design-workflow eromheen. Het is local-first en Apache-2.0, dus niets over je werk of je credentials verlaat je machine."}]}], "faqTitle": "Veelgestelde vragen", "faq": [{"name": "Kan OpenAI Codex echt designwerk doen?", "text": "Ja — met een frontend-skill, een design system en echte referentiebeelden in context produceert Codex (zeker op GPT-5.4) responsieve UI van productiekwaliteit en kan hij die in een browser verifiëren. Zonder die context neigt hij naar een generieke look, en dat is de kloof die Open Design dicht."}, {"name": "Is dit de OpenAI Codex Product Design-plugin?", "text": "Nee. Open Design is een onafhankelijk open-source project dat Codex integreert als agent. Het vult OpenAI's eigen tooling aan met een local-first, open bibliotheek van skills en design systems."}, {"name": "Heb ik een ChatGPT-abonnement nodig om te designen met Codex?", "text": "Je kunt zowel een OpenAI API-key (BYOK) als je ChatGPT-abonnement gebruiken. Inloggen met ChatGPT geeft doorgaans ruimere limieten; Open Design sluist je credentials hoe dan ook nooit door."}, {"name": "Codex of Claude Code voor frontend-design?", "text": "Beide zijn sterk. Claude Code staat bekend om specifieke, codebase-bewuste designbeslissingen; Codex heeft sterke visuele afwerking na GPT-5.4 en blinkt uit in gedelegeerde, gesandboxte builds. Veel teams gebruiken beide — met Open Design wissel je van agent zonder je design-workflow te veranderen."}, {"name": "Hoe verbind ik Codex met Figma?", "text": "Voeg de officiële Figma MCP-server toe (codex mcp add figma --url https://mcp.figma.com/mcp). Je kunt dan Figma-frames in code implementeren met get_design_context en een draaiende UI terugduwen naar bewerkbare Figma-frames met generate_figma_design."}, {"name": "Hoe vermijd ik de generieke “AI slop”-esthetiek?", "text": "Installeer een frontend-skill, lever echte design-tokens en referentie-screenshots aan, leg merkregels vast in AGENTS.md en schakel Playwright-verificatie in. Open Design levert deze als een samengestelde bibliotheek, zodat je de setup per project overslaat."}, {"name": "Is Open Design gelieerd aan OpenAI?", "text": "Nee. Codex is een product van OpenAI; Open Design is een onafhankelijk open-source project dat hem ondersteunt als first-party adapter. OpenAI en Codex zijn handelsmerken van OpenAI."}, {"name": "Zijn mijn bestanden en credentials veilig?", "text": "Ja — Open Design is local-first. Je bestanden, artefacten en DESIGN.md blijven in je eigen repo, en je OpenAI-credentials worden direct gebruikt door je agent, nooit via Open Design-servers geleid."}], "ctaTitle": "Design met Codex, op de open manier.", "ctaBody": "Neem je eigen OpenAI-key mee, houd elk bestand lokaal, en krijg een samengestelde design-bibliotheek rondom de agent die je al gebruikt.", "ctaActions": [{"label": "Gebruik Codex binnen Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Bekijk alle ondersteunde agents"},
      },
      'cursor': {
        ...en['cursor']!,
        title: "Cursor voor designers — Open Design",
        description: "Hoe designers Cursor gebruiken voor UI- en webdesign — Design Mode, Figma-naar-code, de Figma MCP — en hoe Open Design er een local-first, open-source design-agent van maakt.",
        breadcrumb: "Cursor Agent",
        label: "Agent · Cursor",
        heading: "Cursor voor designers.",
        lead: "Cursor is de AI-code-editor, nu met een visuele Design Mode. Designers gebruiken hem om UI te bewerken door aan te wijzen en te tekenen, en om Figma in code om te zetten. Open Design koppelt Cursor Agent aan een open-source design-workflow die je bestanden lokaal houdt.",
        rich: {"heroCtaLead": "Open Design maakt van Cursor een local-first, open-source design-agent — je Cursor-account of model-keys, je bestanden, en een samengestelde bibliotheek van skills en design systems eromheen.", "heroCtaActions": [{"label": "Gebruik Cursor binnen Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Cursor is de AI-first code-editor die van “bouw het en zie het renderen” de standaardmanier maakte om UI te leveren. Met Agent-mode, inline edits, een preview in de editor en Figma via MCP is het een echte design-tool geworden — zodra je hem de juiste referenties, regels en een verificatielus geeft. Dit is een praktische, end-to-end gids voor het gebruik van Cursor voor UI-, frontend- en design-system-werk, en voor het inbedden ervan in een gestructureerde design-workflow met Open Design.", "Het behandelt wat Cursor precies is, waarom zijn strakke itereren-en-bekijken-lus goed is voor design, hoe je hem vanaf nul opzet, de screenshot-en-preview-naar-UI-lus, de Figma-round-trip via MCP, hoe hij zich verhoudt tot Codex en Claude Code, de valkuilen die AI-output generiek doen ogen, en hoe Open Design de kloof dicht als een open, local-first designlaag."], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "Cursor-design-convergentie: editor links, een samengestelde hub met skills en design systems in het midden met het Cursor-merk centraal, en een gerenderde UI rechts", "caption": "Het kernidee: Cursor bewerkt en rendert UI in de editor, terwijl een samengestelde design-hub hem het system, de skills en de referenties voedt die de output intentioneel doen ogen."}, "tocLabel": "Op deze pagina", "toc": [{"id": "what-is-cursor", "label": "Wat Cursor precies is"}, {"id": "why-design", "label": "Waarom Cursor goed is in design"}, {"id": "setup", "label": "Cursor instellen voor design (vanaf nul)"}, {"id": "preview-workflow", "label": "De preview-naar-UI-workflow"}, {"id": "figma", "label": "Cursor + Figma via MCP"}, {"id": "vs", "label": "Cursor vs Codex vs Claude Code"}, {"id": "pitfalls", "label": "Valkuilen en de “AI slop”-look"}, {"id": "open-design", "label": "Designen met Cursor in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-cursor", "heading": "Wat Cursor precies is", "blocks": [{"kind": "p", "text": "Cursor is een AI-first code-editor gebouwd door Anysphere. Het is een fork van VS Code, dus de vertrouwde editor, extensies en keybindings blijven behouden, maar de workflow is heropgebouwd rond een AI-agent die je hele project kan lezen, meerdere bestanden kan bewerken, commando's kan uitvoeren en met jou in de lus kan itereren."}, {"kind": "p", "text": "Voor designwerk zijn de belangrijke vormen Agent-mode (je beschrijft een uitkomst en Cursor plant en bewerkt over bestanden heen), inline edits en Tab-completions voor snelle aanpassingen, een preview / browser in de editor zodat je de draaiende UI ziet zonder het venster te verlaten, en MCP-ondersteuning waarmee hij externe context kan binnenhalen, zoals een live Figma-bestand."}, {"kind": "steps", "items": [{"label": "Project-regels", "body": "Cursor leest project-instructiebestanden — geversioneerde `.mdc`-regels onder `.cursor/rules`, en een gewone `AGENTS.md` — zodat je je designconventies kunt vastleggen waar de agent ze elke ronde leest."}, {"label": "Modellen", "body": "Cursor is model-flexibel: hij wordt geleverd met frontier-modellen via je abonnement en ondersteunt ook het meebrengen van je eigen model-keys, zodat je de engine achter dezelfde editor-workflow kiest."}, {"label": "MCP", "body": "Hij spreekt het Model Context Protocol, zodat externe servers — meest relevant de Figma MCP-server — eersteklas context worden voor de agent."}]}, {"kind": "ul", "items": ["Leverancier: Anysphere", "Credential: Cursor-account / -abonnement (Hobby / Pro / Business) of je eigen model-keys (BYOK)", "Vorm: AI-first code-editor (VS Code-fork) met een agent en preview in de editor"]}]}, {"id": "why-design", "heading": "Waarom Cursor goed is in design", "blocks": [{"kind": "p", "text": "Cursors design-voorsprong is geen enkele feature — het is de strakheid van de build-and-see-lus. Drie dingen laten het aanvoelen als een design-tool in plaats van een generieke codegenerator."}, {"kind": "steps", "items": [{"label": "Een strakke itereren-en-bekijken-lus", "body": "Je prompt, Cursor bewerkt over bestanden heen, en de preview in de editor rendert het resultaat meteen — zodat je spacing, hiërarchie en beweging in seconden aanpast in plaats van heen en weer te gaan tussen een aparte terminal en browser."}, {"label": "Direct visueel bewerken", "body": "Naast chat laat Cursor je elementen in de preview selecteren en stijlen bijstellen, zodat kleine visuele correcties aanvoelen als design-edits in plaats van code-archeologie."}, {"label": "Project-regels en MCP-context", "body": "Met `.cursor/rules` (of `AGENTS.md`) en de Figma MCP-server werkt de agent tegen je tokens, componenten en echte design-specs in plaats van te gokken."}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "Diagram dat laat zien hoe design system, skill en referentiebeeld samenkomen tot goede design-output", "caption": "Smaak komt voort uit drie inputs die jij aanlevert: een design system, een skill en echte referentiebeelden."}, {"kind": "p", "text": "De les is dezelfde die elke agent leert: Cursor heeft standaard geen smaak. Hij levert goed design wanneer je hem beperkingen geeft — een design system, een esthetische skill en concrete referenties. Open Design verpakt precies die inputs, en daarom passen de twee samen (meer hieronder)."}]}, {"id": "setup", "heading": "Cursor voor designwerk opzetten, vanaf nul", "blocks": [{"kind": "p", "text": "Dit is het volledige pad van een schone machine naar een Cursor die UI kan bouwen, previewen en verifiëren tegen je design system."}, {"kind": "ol", "items": ["Installeer Cursor vanaf cursor.com en log in met je Cursor-account, of configureer je eigen model-keys (BYOK) in Settings.", "Open je project en kies een model in het chat- / Agent-paneel.", "Voeg project-regels toe: maak `.cursor/rules/*.mdc` voor gestructureerde, glob-scoped conventies, of een gewone `AGENTS.md` voor eenvoudige, leesbare instructies.", "Verbind de Figma MCP-server (optioneel) zodat de agent live designcontext kan lezen.", "Draai je dev-server en gebruik de preview in de editor om de UI te zien en te verifiëren terwijl je itereert."]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "Setupflow in vijf stappen: installeren, authenticeren, regels configureren, skill toevoegen, verifiëren", "caption": "De setup-volgorde: installeren → authenticeren → project-regels configureren → een skill toevoegen → preview-verificatie inschakelen."}, {"kind": "p", "text": "Een minimaal project-regelbestand laat de agent designen naar een merk in plaats van terug te vallen op een generieke look. Zet het waar Cursor het elke ronde leest:"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "Leg je designregels vast", "body": "Zet je tokens, primitives en conventies in `.cursor/rules` of `AGENTS.md` en wijs Cursor erop, zodat de output bij een merk past in plaats van terug te vallen op een generieke look."}, {"label": "Houd prompts klein", "body": "Cursors strakke lus beloont gerichte vragen — itereer één component of state tegelijk en bekijk de preview tussen de rondes."}]}]}, {"id": "preview-workflow", "heading": "De preview-naar-UI-workflow", "blocks": [{"kind": "p", "text": "De design-lus met de meeste hefboomwerking bij Cursor is een referentie omzetten in werkende, responsieve UI en in de editor itereren tot het klopt — terwijl je de hele tijd naar de live preview kijkt in plaats van te gokken."}, {"kind": "ol", "items": ["Begin met de helderste visuele referenties die je hebt — en neem meerdere states mee (desktop en mobiel, hover, leeg, laden), niet alleen één hero-shot.", "Wees specifiek in de prompt; vage prompts leveren generieke UI op.", "Bereid een design system voor en vertel Cursor waar de tokens en canonieke primitives staan.", "Houd de preview in de editor open en je dev-server draaiend zodat elke edit meteen rendert op de breakpoints die voor jou belangrijk zijn.", "Itereer door de gerenderde UI terug te vergelijken met de referenties — en gebruik directe elementselectie in de preview voor kleine visuele correcties."]}, {"kind": "p", "text": "Voer referenties in door een beeld aan de chat te koppelen en prompt dan met concrete beperkingen:"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "Commit goede iteraties en draai slechte terug (vertel Cursor wanneer je terugdraait) zodat elke ronde voortbouwt op een schone basis — dezelfde discipline die elke agent-lus tegen afdrijven beschermt."}]}, {"id": "figma", "heading": "Cursor + Figma: design ↔ code via MCP", "blocks": [{"kind": "p", "text": "Cursor verbindt met Figma via de officiële Figma MCP-server, die de agent gestructureerde toegang geeft tot een live Figma-bestand in plaats van een platte screenshot. Dat haalt het giswerk uit de handoff."}, {"kind": "steps", "items": [{"label": "Design → Code", "body": "Kopieer de link van een frame in Figma, plak die in Cursor en vraag hem het design te implementeren. De MCP-server stelt echte designcontext beschikbaar — componenten, variabelen, layout-data, tokens — zodat de gegenereerde code de bron evenaart in plaats van benadert."}, {"label": "Blijf uitgelijnd", "body": "Met design-tokens, stijlen en componenten consistent gebruikt in Figma (en Code Connect waar beschikbaar) blijft Cursors output gekoppeld aan je echte design system in plaats van primitives opnieuw uit te vinden."}]}, {"kind": "p", "text": "Stel de remote Figma MCP-server eenmalig in en hij is beschikbaar voor Cursor als eersteklas context. Omdat MCP een open standaard is, is dezelfde server herbruikbaar over Cursor, Claude Code, Codex en VS Code — precies het soort draagbare, multi-agent-capaciteit dat Open Design is gebouwd om te orkestreren."}]}, {"id": "vs", "heading": "Cursor vs Codex vs Claude Code voor design", "blocks": [{"kind": "p", "text": "Er is geen enkele winnaar voor designwerk — elke agent heeft een andere kracht, en ervaren teams stapelen ze. Een eerlijke samenvatting:"}, {"kind": "table", "columns": ["Agent", "Design-kracht", "Beste voor"], "rows": [["Cursor", "Visuele build-and-see-lus met live preview in de editor en direct elementen bewerken", "Strak itereren-en-bekijken van UI-werk binnen een IDE"], ["Codex", "Sterke visuele afwerking met een frontend-skill; beeldbegrip en gesandboxte runs", "Gedelegeerde async builds en draagbare AGENTS.md-regels"], ["Claude Code", "Specifieke designbeslissingen (hex, spacing, type) en codebase-bewuste UX", "Frontend-redeneren en refactors met grote context"]]}, {"kind": "p", "text": "Het terugkerende oordeel van de community is dat smaak van mensen komt: alle drie vallen zonder skills, referenties en beperkingen terug op een generieke esthetiek. Dat is het echte probleem dat opgelost moet worden — en het heeft de vorm van een design-tool, niet van een model."}]}, {"id": "pitfalls", "heading": "Valkuilen, en hoe je de “AI slop”-look vermijdt", "blocks": [{"kind": "p", "text": "De meest voorkomende klacht over door Cursor gegenereerd design is dat het generiek oogt — zachte gradiënten, zwevende panelen, te grote afgeronde hoeken, dramatische schaduwen, een Inter-en-paars-sfeer die “schreeuwt dat een AI dit maakte.” Andere gemelde problemen zijn layouts die breken op mobiel en instructies die in de UI-tekst lekken."}, {"kind": "steps", "items": [{"label": "Voeg een design-skill toe", "body": "Een samengestelde esthetische skill dwingt Cursor zich op een echte richting vast te leggen in plaats van de standaard look."}, {"label": "Gebruik de preview om te verifiëren", "body": "Render en controleer jezelf over breakpoints heen in de preview in de editor, zodat layouts niet stilletjes breken op mobiel."}, {"label": "Lever tokens en referenties aan", "body": "Echte design-tokens en referentie-screenshots zijn de grootste hefboom op de outputkwaliteit."}, {"label": "Leg regels vast in `.cursor/rules`", "body": "Zet stijlregels als “geen hero cards, maximaal twee lettertypen, merk-eerste hiërarchie” daar waar de agent ze elke ronde leest."}]}, {"kind": "p", "text": "Merk op dat elke remedie draait om het geven van een samengestelde designcontext aan de agent. Die context met de hand onderhouden, per project, is precies het sleurwerk dat Open Design wegneemt."}]}, {"id": "open-design", "heading": "Designen met Cursor binnen Open Design", "blocks": [{"kind": "p", "text": "Open Design is de open-source designlaag waar de workflow hierboven steeds om vraagt. Het behandelt Cursor als een first-party adapter en omhult hem met een samengestelde bibliotheek van skills en design systems, een gestructureerde render-pipeline en een lokale desktop-UI — zodat de designcontext die Cursor goed maakt er vanaf de eerste run is, niet elke keer met de hand samengesteld."}, {"kind": "ol", "items": ["Installeer Open Design en kies Cursor als je agent.", "Authenticeer met je Cursor-account of je eigen model-keys (BYOK) — credentials blijven op je machine en worden nooit via ons doorgesluisd.", "Kies een design system en een skill, en genereer vervolgens decks, prototypes en landingspagina's met consistente smaak.", "Elk artefact en DESIGN.md-bestand staat in je eigen repo, niet in een gehoste cloud."]}, {"kind": "p", "text": "Dezelfde Cursor-agent, dezelfde key — plus een echte, draagbare, open-source design-workflow eromheen. Het is local-first en Apache-2.0, dus niets over je werk of je credentials verlaat je machine."}]}], "faqTitle": "Veelgestelde vragen", "faq": [{"name": "Kan Cursor echt designwerk doen?", "text": "Ja — met een design-skill, een design system en echte referentiebeelden in context produceert Cursor responsieve UI van productiekwaliteit, en met de preview in de editor kun je die visueel verifiëren en verfijnen. Zonder die context neigt hij naar een generieke look, en dat is de kloof die Open Design dicht."}, {"name": "Is dit een officieel Cursor-product?", "text": "Nee. Open Design is een onafhankelijk open-source project dat Cursor integreert als agent. Het vult Cursor aan met een local-first, open bibliotheek van skills en design systems."}, {"name": "Heb ik een Cursor-abonnement nodig om te designen met Cursor?", "text": "Je kunt een Cursor-account / -abonnement gebruiken of je eigen model-keys meebrengen (BYOK). Open Design sluist je credentials hoe dan ook nooit door — ze worden direct gebruikt door je agent."}, {"name": "Cursor of Claude Code voor frontend-design?", "text": "Beide zijn sterk. Claude Code staat bekend om specifieke, codebase-bewuste designbeslissingen; Cursors voorsprong is zijn strakke build-and-see-lus met een live preview in de editor. Veel teams gebruiken beide — met Open Design wissel je van agent zonder je design-workflow te veranderen."}, {"name": "Hoe verbind ik Cursor met Figma?", "text": "Voeg de officiële Figma MCP-server toe in Cursor, plak dan een Figma-frame-link in de chat en vraag Cursor die te implementeren. De server stelt echte componenten, variabelen en layout-data beschikbaar zodat de gegenereerde code het brondesign evenaart."}, {"name": "Hoe vermijd ik de generieke “AI slop”-esthetiek?", "text": "Voeg een design-skill toe, lever echte design-tokens en referentie-screenshots aan, leg merkregels vast in `.cursor/rules` of `AGENTS.md`, en verifieer over breakpoints heen in de preview. Open Design levert deze als een samengestelde bibliotheek, zodat je de setup per project overslaat."}, {"name": "Is Open Design gelieerd aan Cursor of Anysphere?", "text": "Nee. Cursor is een product van Anysphere; Open Design is een onafhankelijk open-source project dat hem ondersteunt als first-party adapter. Cursor en Anysphere zijn handelsmerken van Anysphere, Inc."}, {"name": "Zijn mijn bestanden en credentials veilig?", "text": "Ja — Open Design is local-first. Je bestanden, artefacten en DESIGN.md blijven in je eigen repo, en je Cursor- of model-credentials worden direct gebruikt door je agent, nooit via Open Design-servers geleid."}], "ctaTitle": "Design met Cursor, op de open manier.", "ctaBody": "Neem je eigen Cursor-account of model-keys mee, houd elk bestand lokaal, en krijg een samengestelde design-bibliotheek rondom de agent die je al gebruikt.", "ctaActions": [{"label": "Gebruik Cursor binnen Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Bekijk alle ondersteunde agents"},
      },
      'opencode': {
        ...en['opencode']!,
        title: "OpenCode voor design — Open Design",
        description: "Hoe mensen OpenCode gebruiken voor UI- en webdesign — design.md-bestanden, UI/UX-skills, Figma MCP — en hoe Open Design er een local-first, open-source design-agent van maakt.",
        breadcrumb: "OpenCode",
        label: "Agent · OpenCode",
        heading: "OpenCode voor design.",
        lead: "OpenCode is de open-source terminal-AI-coding-agent. Designers schroeven er design-skills en DESIGN.md-bestanden op om echte UI te genereren. Open Design maakt daar een gestructureerde, open-source workflow van — neem je provider-keys mee en houd alles lokaal.",
        rich: {"heroCtaLead": "Open Design maakt van OpenCode een local-first, open-source design-agent — elk model dat je kiest met je eigen provider-key, je bestanden, en een samengestelde bibliotheek van skills en design systems eromheen.", "heroCtaActions": [{"label": "Gebruik OpenCode binnen Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenCode is een open-source, terminal-first AI-coding-agent die bewust modelonafhankelijk is: je neemt je eigen provider-key mee en draait welk model je maar wilt achter dezelfde workflow. Die openheid maakt hem een natuurlijke basis voor designwerk — maar zoals elke agent levert hij alleen goede UI wanneer je hem de juiste referenties, skills en een verificatielus geeft. Dit is een praktische, end-to-end gids voor het gebruik van OpenCode voor UI-, frontend- en design-system-werk, en voor het inbedden ervan in een gestructureerde design-workflow met Open Design.", "Het behandelt wat OpenCode precies is, waarom een modelonafhankelijke open agent goed past bij design, hoe je hem vanaf nul opzet, de screenshot-naar-UI-lus, hoe AGENTS.md en MCP hem uitbreiden, hoe hij zich verhoudt tot Codex, Claude Code en Cursor, de valkuilen die AI-output generiek doen ogen, en hoe Open Design de kloof dicht als een open, local-first designlaag — een natuurlijke combinatie, want beide projecten zijn open-source en draaien op je eigen machine."], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "Feedbacklus van OpenCode-design: een terminal-TUI-agent, een browser die de UI rendert, en een werkruimte, met een feedbackpijl die terugloopt", "caption": "De kernlus: OpenCode bouwt UI in de terminal, rendert en verifieert die in een echte browser, en itereert tegen je referenties — op welk model je ook kiest."}, "tocLabel": "Op deze pagina", "toc": [{"id": "what-is-opencode", "label": "Wat OpenCode precies is"}, {"id": "why-design", "label": "Waarom een open, elk-model-agent past bij design"}, {"id": "setup", "label": "OpenCode instellen voor design (vanaf nul)"}, {"id": "screenshot-workflow", "label": "De screenshot-naar-UI-workflow"}, {"id": "extend", "label": "AGENTS.md, MCP en deelbare sessies"}, {"id": "vs", "label": "OpenCode vs Codex vs Claude Code vs Cursor"}, {"id": "pitfalls", "label": "Valkuilen en de “AI slop”-look"}, {"id": "open-design", "label": "Designen met OpenCode in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-opencode", "heading": "Wat OpenCode precies is", "blocks": [{"kind": "p", "text": "OpenCode is een open-source AI-coding-agent gebouwd voor de terminal, onderhouden door het team achter SST (Anomaly Innovations). Hij leest je repository, voert commando's uit, bewerkt bestanden en praat met een large language model — maar anders dan leverancier-gebonden agents levert hij geen eigen model. Je richt hem op welke provider en welk model je maar wilt en neemt je eigen key mee."}, {"kind": "p", "text": "Hij draait als een terminal-UI (TUI), met een desktop-app en IDE-extensies bovenop dezelfde engine. Onder de motorkap gebruikt hij een client/server-architectuur, zodat de agent die het werk doet losgekoppeld is van de vorm waarmee je hem aanstuurt. Twee ingebouwde agents — build en plan — wissel je met de Tab-toets."}, {"kind": "steps", "items": [{"label": "Modelonafhankelijk", "body": "Modellen en providers komen van models.dev, een open catalogus. Je configureert ze in opencode.json met een provider/model-id-string en kunt providers die je niet geladen wilt hebben uitschakelen — zodat dezelfde design-workflow draait op Anthropic, OpenAI, Google, OpenRouter, lokale modellen en meer."}, {"label": "Instructiebestand", "body": "OpenCode leest een AGENTS.md-bestand in je project (de cross-tool-standaard, ook compatibel met CLAUDE.md) voor projectregels — de natuurlijke plek om je designconventies vast te leggen. Draai /init om er een te genereren."}, {"label": "Uitbreidbaar", "body": "Hij ondersteunt LSP-integratie, MCP-servers, thema's, keybinds en custom commando's, plus deelbare sessielinks voor samenwerking."}]}, {"kind": "ul", "items": ["Maintainer: SST / Anomaly Innovations (open-source project)", "Credential: je eigen API-key(s) voor model-providers — BYOK, geen vendor lock-in", "Licentie: MIT, open source"]}]}, {"id": "why-design", "heading": "Waarom een open, elk-model-agent past bij designwerk", "blocks": [{"kind": "p", "text": "OpenCode heeft geen enkel “design-model” zoals een leverancier-agent dat heeft — en dat is precies het punt. Omdat hij modelonafhankelijk en open is, kun je dezelfde design-workflow draaien op welk model op dit moment het best is in frontend, hem later vervangen, of terugvallen op een lokaal model, allemaal zonder je setup te veranderen."}, {"kind": "p", "text": "Maar modelkeuze alleen koopt geen smaak. Zoals elke coding-agent produceert OpenCode generieke UI tenzij je hem beperkingen geeft. Goede design-output komt voort uit drie inputs die jij aanlevert."}, {"kind": "steps", "items": [{"label": "Een design system", "body": "Echte tokens, primitives en conventies die de agent hergebruikt, zodat de output bij een merk past in plaats van terug te vallen op een generieke look."}, {"label": "Een esthetische skill", "body": "Een samengestelde skill die echte smaak afdwingt — ingetogen beweging, merk-eerste hiërarchie, hooguit twee lettertypen en één accentkleur — en de agent zich op een richting laat vastleggen voordat hij bouwt."}, {"label": "Concrete referenties", "body": "Echte referentiebeelden en meerdere states (desktop en mobiel, hover, leeg, laden), niet één enkele hero-shot."}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "Diagram dat laat zien hoe design system, skill en referentiebeeld samenkomen tot goede design-output", "caption": "Smaak komt voort uit drie inputs die jij aanlevert: een design system, een skill en echte referentiebeelden — onafhankelijk van welk model je draait."}, {"kind": "p", "text": "De les: OpenCode geeft je modelvrijheid, maar smaak komt nog steeds voort uit een samengestelde designcontext. Open Design verpakt precies die inputs, en daarom passen de twee samen — beide zijn open-source en local-first (meer hieronder)."}]}, {"id": "setup", "heading": "OpenCode voor designwerk opzetten, vanaf nul", "blocks": [{"kind": "p", "text": "Dit is het volledige pad van een schone machine naar een OpenCode die UI kan bouwen en verifiëren."}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "Setupflow in vijf stappen: installeren, authenticeren met je provider-key, AGENTS.md configureren, een skill toevoegen, verifiëren", "caption": "De setup-volgorde: installeren → authenticeren (je provider-key) → AGENTS.md configureren → een skill toevoegen → verifiëren in een echte browser."}, {"kind": "steps", "items": [{"label": "Leg je designregels vast", "body": "Zet je tokens, primitives en conventies in AGENTS.md (of een DESIGN.md die daaruit wordt aangehaald) zodat de output bij een merk past in plaats van terug te vallen op een generieke look. De instructions-optie in opencode.json kan via globs naar extra regelbestanden verwijzen."}, {"label": "Kies een capabel model", "body": "Omdat OpenCode modelonafhankelijk is, kies je welke provider/model op dit moment het sterkst is in frontend voor de design-ronde — en houd je de rest van je workflow onveranderd."}]}]}, {"id": "screenshot-workflow", "heading": "De screenshot-naar-UI-workflow", "blocks": [{"kind": "p", "text": "De design-lus met de meeste hefboomwerking bij elke agent is een referentiebeeld omzetten in werkende, responsieve UI en itereren tot het klopt. Dezelfde vijfstappenvorm geldt in OpenCode."}, {"kind": "ol", "items": ["Begin met de helderste visuele referenties die je hebt — en neem meerdere states mee (desktop en mobiel, hover, leeg, laden), niet alleen één hero-shot.", "Wees specifiek in de prompt; vage prompts leveren generieke UI op.", "Bereid een design system voor en vertel OpenCode waar de tokens en canonieke primitives staan (in AGENTS.md).", "Draai een dev-server en laat de agent in een echte browser renderen, met herschaling naar breakpoints om het resultaat te controleren.", "Itereer door OpenCode zijn implementatie terug te laten vergelijken met de screenshots — niet alleen te bevestigen dat het bouwt."]}, {"kind": "p", "text": "Verwijs naar bestanden met @ in de TUI voor een fuzzy-zoekopdracht in je werkmap, voer shell-commando's inline uit met een voorafgaande !, en stuur acties aan met /-commando's. Prompt dan met concrete beperkingen:"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "Houd prompts klein en gericht, commit goede iteraties en draai slechte terug (vertel OpenCode wanneer je terugdraait), zodat elke ronde voortbouwt op een schone basis."}]}, {"id": "extend", "heading": "AGENTS.md, MCP en deelbare sessies", "blocks": [{"kind": "p", "text": "Drie uitbreidingspunten maken OpenCode praktisch voor langdurig designwerk, en alle drie sluiten naadloos aan op een open design-workflow."}, {"kind": "steps", "items": [{"label": "AGENTS.md-regels", "body": "Projectregels staan in een AGENTS.md in de repo-root (of globale regels in ~/.config/opencode/AGENTS.md). Het is de duurzame thuisbasis voor je designconventies, gelezen bij elke ronde, en compatibel met de CLAUDE.md-bestanden die andere agents gebruiken."}, {"label": "MCP-servers", "body": "OpenCode ondersteunt zowel lokale (command) als remote (URL) MCP-servers, geconfigureerd onder de mcp-sleutel — de draagbare manier om designcontext en externe tools binnen te halen die over agents heen werken, niet alleen in OpenCode."}, {"label": "Deelbare sessies", "body": "Het /share-commando maakt een publieke link naar een gesprek voor samenwerking of review, en /unshare trekt die in — handig om feedback te krijgen op een design-ronde."}]}, {"kind": "p", "text": "Dit zijn draagbare, multi-agent-capaciteiten — precies het soort dingen die Open Design is gebouwd om te orkestreren, in plaats van per project opnieuw te creëren."}]}, {"id": "vs", "heading": "OpenCode vs Codex vs Claude Code vs Cursor voor design", "blocks": [{"kind": "p", "text": "Er is geen enkele winnaar voor designwerk — elke agent heeft een andere kracht, en ervaren teams stapelen ze. Een eerlijke samenvatting:"}, {"kind": "table", "columns": ["Agent", "Design-kracht", "Beste voor"], "rows": [["OpenCode", "Open-source en modelonafhankelijk; draai elke provider achter één terminal-workflow", "BYOK-vrijheid, modellen wisselen, volledig open en local-first setups"], ["Codex", "Sterke visuele afwerking met een frontend-skill; beeldbegrip", "Gedelegeerd async, gesandboxte builds, draagbare AGENTS.md-regels"], ["Claude Code", "Specifieke designbeslissingen (hex, spacing, type) en codebase-bewuste UX", "Frontend-redeneren en refactors met grote context"], ["Cursor", "Visuele build-and-see-lus met live preview en inline edits", "Strak itereren-en-bekijken van UI-werk binnen een IDE"]]}, {"kind": "p", "text": "Het terugkerende oordeel van de community is dat smaak van mensen komt: ze vallen allemaal zonder skills, referenties en beperkingen terug op een generieke esthetiek. Dat is het echte probleem dat opgelost moet worden — en het heeft de vorm van een design-tool, niet van een model, en precies daarom past een open agent als OpenCode zo goed bij een open designlaag."}]}, {"id": "pitfalls", "heading": "Valkuilen, en hoe je de “AI slop”-look vermijdt", "blocks": [{"kind": "p", "text": "De meest voorkomende klacht over AI-gegenereerd design is dat het generiek oogt — zachte gradiënten, zwevende panelen, te grote afgeronde hoeken, dramatische schaduwen, een Inter-en-paars-sfeer die “schreeuwt dat een AI dit maakte.” Andere gemelde problemen zijn kapotte mobiele layouts en instructies die in de UI-tekst lekken. Geen van deze is uniek voor OpenCode; ze zijn wat er gebeurt wanneer welke agent dan ook draait zonder een samengestelde designcontext."}, {"kind": "steps", "items": [{"label": "Voeg een esthetische skill toe", "body": "Een samengestelde design-skill dwingt de agent zich op een echte richting vast te leggen in plaats van de standaard look."}, {"label": "Verifieer in een echte browser", "body": "Render en controleer jezelf over breakpoints heen, zodat layouts niet stilletjes breken op mobiel."}, {"label": "Lever tokens en referenties aan", "body": "Echte design-tokens en referentie-screenshots zijn de grootste hefboom op de outputkwaliteit."}, {"label": "Leg regels vast in AGENTS.md", "body": "Zet stijlregels als “geen hero cards, maximaal twee lettertypen, merk-eerste hiërarchie” daar waar de agent ze elke ronde leest."}]}, {"kind": "p", "text": "Merk op dat elke remedie draait om het geven van een samengestelde designcontext aan de agent — ongeacht welk model je draait. Die context met de hand onderhouden, per project, is precies het sleurwerk dat Open Design wegneemt."}]}, {"id": "open-design", "heading": "Designen met OpenCode binnen Open Design", "blocks": [{"kind": "p", "text": "Open Design is de open-source designlaag waar de workflow hierboven steeds om vraagt. Het behandelt OpenCode als een first-party adapter en omhult hem met een samengestelde bibliotheek van skills en design systems, een gestructureerde render-pipeline en een lokale desktop-UI — zodat de designcontext die elke agent goed maakt er vanaf de eerste run is, niet elke keer met de hand samengesteld. Beide projecten zijn open-source en local-first, wat de combinatie een natuurlijke match maakt."}, {"kind": "ol", "items": ["Installeer Open Design en kies OpenCode als je agent.", "Authenticeer met je eigen API-key voor model-providers (BYOK) — credentials blijven op je machine en worden nooit via ons doorgesluisd.", "Kies een willekeurige provider en model, plus een design system en een skill, en genereer vervolgens decks, prototypes en landingspagina's met consistente smaak.", "Elk artefact en DESIGN.md-bestand staat in je eigen repo, niet in een gehoste cloud."]}, {"kind": "p", "text": "Dezelfde OpenCode-agent, dezelfde modelvrijheid — plus een echte, draagbare, open-source design-workflow eromheen. Het is local-first en Apache-2.0, dus niets over je werk of je credentials verlaat je machine."}]}], "faqTitle": "Veelgestelde vragen", "faq": [{"name": "Kan OpenCode echt designwerk doen?", "text": "Ja — met een esthetische skill, een design system en echte referentiebeelden in context produceert OpenCode responsieve UI van productiekwaliteit en kan hij die in een browser verifiëren. Omdat hij modelonafhankelijk is, draai je welk model op dit moment het best is in frontend. Zonder die samengestelde context neigt hij naar een generieke look, en dat is de kloof die Open Design dicht."}, {"name": "Welk model moet ik gebruiken met OpenCode voor design?", "text": "Welk je maar wilt — OpenCode is provider-onafhankelijk via models.dev, dus je kunt Anthropic, OpenAI, Google, OpenRouter of lokale modellen achter dezelfde workflow draaien en op elk moment wisselen. De kwaliteit van de design-output hangt veel meer af van je skill, design system en referenties dan van het model alleen."}, {"name": "Is Open Design gemaakt door het OpenCode-team (SST)?", "text": "Nee. Open Design is een onafhankelijk open-source project dat OpenCode integreert als agent. Het vult OpenCode aan met een local-first, open bibliotheek van skills en design systems."}, {"name": "Heb ik een speciaal abonnement nodig om te designen met OpenCode?", "text": "Nee — OpenCode is BYOK. Je neemt je eigen API-key voor model-providers mee, en Open Design sluist je credentials nooit door. Er is geen vendor lock-in."}, {"name": "OpenCode of Codex of Claude Code voor frontend-design?", "text": "Alle zijn sterk, en veel teams stapelen ze. OpenCode's voorsprong is dat hij volledig open-source en modelonafhankelijk is; Codex blinkt uit in gedelegeerde, gesandboxte builds; Claude Code staat bekend om specifieke, codebase-bewuste designbeslissingen. Met Open Design wissel je van agent zonder je design-workflow te veranderen."}, {"name": "Hoe breid ik OpenCode uit voor designcontext?", "text": "Leg regels vast in AGENTS.md, voeg MCP-servers toe onder de mcp-sleutel voor draagbare tools en designcontext, en gebruik deelbare sessies voor review. Open Design levert een samengestelde bibliotheek van skills en design systems zodat je de setup per project overslaat."}, {"name": "Is Open Design gelieerd aan OpenCode of SST?", "text": "Nee. OpenCode is een open-source project onderhouden door SST (Anomaly Innovations); Open Design is een onafhankelijk open-source project dat hem ondersteunt als first-party adapter."}, {"name": "Zijn mijn bestanden en credentials veilig?", "text": "Ja — Open Design is local-first. Je bestanden, artefacten en DESIGN.md blijven in je eigen repo, en je credentials voor model-providers worden direct gebruikt door je agent, nooit via Open Design-servers geleid."}], "ctaTitle": "Design met OpenCode, op de open manier.", "ctaBody": "Neem je eigen key voor model-providers mee, houd elk bestand lokaal, en krijg een samengestelde design-bibliotheek rondom de open agent die je al gebruikt.", "ctaActions": [{"label": "Gebruik OpenCode binnen Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Bekijk alle ondersteunde agents"},
      },
      'gemini': {
        ...en['gemini']!,
        title: "Gemini CLI voor design — Open Design",
        description: "Hoe mensen Google’s Gemini CLI gebruiken voor UI- en webdesign — het multimodale beeldbegrip, de context van 1M tokens, GEMINI.md en MCP — en hoe Open Design Gemini CLI omzet in een local-first, open-source design-agent.",
        breadcrumb: "Gemini CLI",
        label: "Agent · Gemini CLI",
        heading: "Gemini CLI voor design.",
        lead: "Gemini CLI is Google’s open-source terminal-agent. De multimodale modellen lezen schermafbeeldingen en de context van 1M tokens houdt een heel design system vast, wat het tot een echt design-tool maakt — zodra je het referenties, conventies en een verificatielus geeft. Open Design verbindt het met een open-source design-workflow: je Google-account of API-sleutel, je bestanden, local-first.",
        rich: {"heroCtaLead": "Open Design zet Gemini CLI om in een local-first, open-source design-agent — je Google-account of Gemini API-sleutel, je bestanden, met een gecureerde skill- en design-system-bibliotheek eromheen.", "heroCtaActions": [{"label": "Gebruik Gemini CLI binnen Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Gemini CLI is Google’s open-source AI-agent voor de terminal. Twee dingen maken het specifiek voor design interessant: de modellen zijn sterk multimodaal, dus het leest een schermafbeelding en redeneert over layout, spacing en hiërarchie; en het contextvenster van 1M tokens kan een heel design system en een complete codebase in één keer vasthouden. Gekoppeld aan de juiste referenties, conventies en een verificatielus bouwt het echte, responsieve UI — en je kunt er gratis mee beginnen met een Google-account. Dit is een praktische, end-to-end gids om Gemini CLI in te zetten voor UI-, frontend- en design-system-werk, en om het te verbinden met een gestructureerde design-workflow met Open Design.", "Het behandelt wat Gemini CLI eigenlijk is, waarom de multimodale modellen en enorme context bij design passen, hoe je het vanaf nul opzet, de schermafbeelding-naar-UI-lus, hoe GEMINI.md en MCP het uitbreiden, hoe het zich verhoudt tot Codex, Claude Code en Cursor, de valkuilen die AI-output generiek doen lijken, en hoe Open Design de kloof dicht als een open, local-first design-laag — een natuurlijke combinatie, want beide zijn open-source en draaien op je eigen machine."], "heroImage": {"src": "/agents/gemini-design/gemini-design-hero.webp", "alt": "Gemini CLI design-feedbacklus: een terminal-agent die een referentieafbeelding leest, een browser die de UI rendert, en een werkruimte, met een feedbackpijl die terugloopt", "caption": "De kernlus: Gemini CLI leest je referenties in de terminal, bouwt en verifieert de UI in een echte browser, en itereert daartegen — met een heel design system in context."}, "tocLabel": "Op deze pagina", "toc": [{"id": "what-is-gemini-cli", "label": "Wat Gemini CLI eigenlijk is"}, {"id": "why-design", "label": "Waarom multimodaal + enorme context bij design passen"}, {"id": "setup", "label": "Gemini CLI opzetten voor design (vanaf nul)"}, {"id": "screenshot-workflow", "label": "De schermafbeelding-naar-UI-workflow"}, {"id": "extend", "label": "GEMINI.md, MCP en extensies"}, {"id": "vs", "label": "Gemini CLI vs Codex vs Claude Code vs Cursor"}, {"id": "pitfalls", "label": "Valkuilen en de “AI slop”-look"}, {"id": "open-design", "label": "Ontwerpen met Gemini CLI in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-gemini-cli", "heading": "Wat Gemini CLI eigenlijk is", "blocks": [{"kind": "p", "text": "Gemini CLI is een open-source (Apache-2.0) AI-agent die Google levert voor de terminal. Het leest je repository, bewerkt bestanden, voert shell-commando’s uit, haalt content van het web op en kan antwoorden onderbouwen met Google Search — het plant en verifieert werk op basis van taken in natuurlijke taal in plaats van slechts regels af te maken. Dezelfde engine drijft ook de Gemini Code Assist-agent binnen VS Code aan."}, {"kind": "p", "text": "Voor design-werk springen twee eigenschappen eruit. De modellen zijn van nature multimodaal, dus je kunt het een schermafbeelding geven en het redeneert over de daadwerkelijke layout. En het contextvenster reikt tot 1M tokens, groot genoeg om je hele design system, componentenbibliotheek en referentieset in één keer vast te houden in plaats van ze samen te vatten en weg te laten."}, {"kind": "steps", "items": [{"label": "Contextbestanden", "body": "Gemini CLI leest een GEMINI.md-bestand voor persistente projectcontext — de natuurlijke plek om je design-conventies, tokens en review-checklists vast te leggen. Persoonlijke en team-instellingen komen daar bovenop."}, {"label": "Ingebouwde tools + MCP", "body": "Het levert standaard file-, shell-, web-fetch- en Google Search-tools, en ondersteunt MCP-servers (geconfigureerd in ~/.gemini/settings.json) om externe context toe te voegen, zoals een live Figma-bestand."}, {"label": "Gratis te beginnen", "body": "Inloggen met een persoonlijk Google-account geeft een royale gratis laag aan Gemini-requests; je kunt ook een eigen Gemini API-sleutel meenemen of Vertex AI gebruiken."}]}, {"kind": "ul", "items": ["Leverancier: Google", "Credential: Google-account (gratis laag) of Gemini API-sleutel van AI Studio (BYOK) of Vertex AI", "Licentie: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Waarom multimodale modellen en een enorme context bij design passen", "blocks": [{"kind": "p", "text": "Het design-voordeel van Gemini CLI komt voort uit twee modeleigenschappen — maar, zoals bij elke agent, moet smaak nog steeds worden aangeleverd."}, {"kind": "steps", "items": [{"label": "Sterk multimodaal begrip", "body": "Omdat Gemini-modellen van nature multimodaal zijn, leest de agent referentie-schermafbeeldingen goed — het vergelijkt zijn gerenderde output met een afbeelding in plaats van te gokken op basis van een tekstuele beschrijving."}, {"label": "Een contextvenster van 1M tokens", "body": "Een grote context betekent dat het hele design system, de tokens en veel referentiestaten tegelijk passen, zodat de agent je echte primitieven hergebruikt in plaats van eenmalige stijlen te verzinnen."}, {"label": "Conventies in GEMINI.md", "body": "Een GEMINI.md (plus de Figma MCP-server) wijst de agent naar je tokens, componenten en echte specs, zodat het tegen een merk werkt in plaats van tegen een standaard look."}]}, {"kind": "image", "src": "/agents/gemini-design/gemini-design-taste-triangle.webp", "alt": "Diagram dat laat zien hoe design system, skill en referentieafbeelding samenkomen tot goede design-output", "caption": "Smaak komt uit drie inputs die jij aanlevert: een design system, een skill en echte referentieafbeeldingen."}, {"kind": "p", "text": "De les is dezelfde die elke agent leert: Gemini CLI heeft standaard geen smaak. Het produceert goed design wanneer je het beperkingen geeft — een design system, een esthetische skill en concrete referenties. Open Design bundelt precies die inputs, en daarom passen de twee zo goed samen (meer hieronder)."}]}, {"id": "setup", "heading": "Gemini CLI opzetten voor design-werk, vanaf nul", "blocks": [{"kind": "p", "text": "Hier is het volledige pad van een schone machine naar een Gemini CLI die UI kan bouwen en verifiëren."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Gemini CLI (Node 20+)\nnpm install -g @google/gemini-cli\n# or run without installing: npx https://github.com/google-gemini/gemini-cli\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\ngemini            # sign in with your Google account, or set GEMINI_API_KEY\n\n# 3. Generate project context\n/init             # scaffolds a GEMINI.md for this project\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add it under \"mcpServers\" in ~/.gemini/settings.json"}, {"kind": "image", "src": "/agents/gemini-design/gemini-design-setup-flow.webp", "alt": "Setup-flow in vijf stappen: installeren, authenticeren, GEMINI.md configureren, een skill toevoegen, verifiëren", "caption": "De setup-volgorde: installeren → authenticeren → GEMINI.md configureren → een skill toevoegen → browserverificatie inschakelen."}, {"kind": "steps", "items": [{"label": "Leg je design-regels vast", "body": "Zet je tokens, primitieven en conventies in GEMINI.md en wijs Gemini ernaar, zodat de output bij een merk past in plaats van terug te vallen op een generieke look."}, {"label": "Voeg browserverificatie toe", "body": "Verbind een Playwright- of browser-MCP zodat Gemini in een echte browser rendert en zijn output over breakpoints controleert, in plaats van alleen te bevestigen dat de build slaagt."}]}]}, {"id": "screenshot-workflow", "heading": "De schermafbeelding-naar-UI-workflow", "blocks": [{"kind": "p", "text": "De design-lus met de meeste hefboomwerking bij Gemini CLI is het omzetten van een referentieafbeelding in werkende, responsieve UI en daarop itereren tot het overeenkomt — leunend op het multimodale model om output met de referentie te vergelijken."}, {"kind": "ol", "items": ["Begin met de helderste visuele referenties die je hebt — en neem meerdere staten op (desktop en mobiel, hover, leeg, laden), niet slechts één hero-shot.", "Wees specifiek in de prompt; vage prompts produceren generieke UI, zelfs met een sterk model.", "Houd je design system en conventies in GEMINI.md, en vertel Gemini waar de tokens en canonieke primitieven zich bevinden.", "Draai een dev-server en laat Gemini in een echte browser renderen, met aanpassing van de grootte naar breakpoints om het resultaat te controleren.", "Itereer door Gemini zijn implementatie met de schermafbeeldingen te laten vergelijken — niet alleen te bevestigen dat het bouwt."]}, {"kind": "p", "text": "Verwijs met @ naar een afbeelding om die aan de prompt toe te voegen, en geef vervolgens concrete beperkingen:"}, {"kind": "code", "lang": "bash", "code": "gemini\n# in the prompt:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from GEMINI.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Houd prompts klein en gefocust, commit goede iteraties en draai slechte terug (en vertel Gemini wanneer je terugdraait), zodat elke ronde voortbouwt op een schone basis."}]}, {"id": "extend", "heading": "GEMINI.md, MCP en extensies", "blocks": [{"kind": "p", "text": "Drie uitbreidingspunten maken Gemini CLI praktisch voor aanhoudend design-werk, en alle drie passen schoon op een open design-workflow."}, {"kind": "steps", "items": [{"label": "GEMINI.md-context", "body": "Projectregels staan in een GEMINI.md in de repo-root (met globale en team-lagen). Het is de duurzame thuisbasis voor je design-conventies, gelezen bij elke run."}, {"label": "MCP-servers", "body": "Configureer MCP-servers onder ~/.gemini/settings.json — de draagbare manier om design-context en externe tools binnen te halen, het meest relevant de Figma MCP-server, die werken over agents heen, niet alleen Gemini."}, {"label": "Extensies en ingebouwde tools", "body": "Gemini CLI-extensies en de ingebouwde Google Search-, file-, shell- en web-fetch-tools laten het referenties verzamelen en de verificatielus draaien zonder de terminal te verlaten."}]}, {"kind": "p", "text": "Dit zijn draagbare, multi-agent-mogelijkheden — precies het soort dingen dat Open Design is gebouwd om te orkestreren, in plaats van per project opnieuw te creëren."}]}, {"id": "vs", "heading": "Gemini CLI vs Codex vs Claude Code vs Cursor voor design", "blocks": [{"kind": "p", "text": "Er is geen enkele winnaar voor design-werk — elke agent heeft een andere kracht, en ervaren teams stapelen ze. Een eerlijke samenvatting:"}, {"kind": "table", "columns": ["Agent", "Design-kracht", "Het best voor"], "rows": [["Gemini CLI", "Sterk multimodaal beeldbegrip en een context van 1M tokens; open-source met een gratis laag", "Schermafbeelding-intensief werk en een heel design system in context houden"], ["Codex", "Sterke visuele afwerking met een frontend-skill; gesandboxte async builds", "Gedelegeerde async builds en draagbare AGENTS.md-regels"], ["Claude Code", "Specifieke design-beslissingen (hex, spacing, type) en codebase-bewuste UX", "Frontend-redenering en refactors met grote context"], ["Cursor", "Visuele bouw-en-zie-lus met live preview en inline edits", "Strak itereer-en-kijk UI-werk binnen een IDE"]]}, {"kind": "p", "text": "Het terugkerende oordeel van de community is dat smaak van mensen komt: ze vallen allemaal terug op een generieke esthetiek zonder skills, referenties en beperkingen. Dat is het echte probleem om op te lossen — en het is design-tool-vormig, niet model-vormig."}]}, {"id": "pitfalls", "heading": "Valkuilen, en hoe je de “AI slop”-look vermijdt", "blocks": [{"kind": "p", "text": "De meest voorkomende klacht over AI-gegenereerd design is dat het generiek oogt — zachte gradiënten, zwevende panelen, overdreven grote afgeronde hoeken, dramatische schaduwen, een Inter-en-paars-sfeer die “schreeuwt dat een AI dit heeft gemaakt.” Andere gemelde problemen zijn kapotte mobiele layouts en instructies die in UI-teksten terechtkomen. Geen van deze is uniek voor Gemini CLI; het is wat er gebeurt wanneer een willekeurige agent draait zonder een gecureerde design-context."}, {"kind": "steps", "items": [{"label": "Voeg een esthetische skill toe", "body": "Een gecureerde design-skill dwingt de agent zich aan een echte richting te committeren in plaats van aan de standaard look."}, {"label": "Verifieer in een echte browser", "body": "Gebruik het multimodale model om te renderen en zelf te controleren over breakpoints, zodat layouts niet stilletjes kapotgaan op mobiel."}, {"label": "Lever tokens en referenties aan", "body": "Echte design-tokens en referentie-schermafbeeldingen zijn de grootste hefboom op de kwaliteit van de output."}, {"label": "Leg regels vast in GEMINI.md", "body": "Zet regels in de stijl van “geen hero-cards, maximaal twee lettertypen, merk-eerst hiërarchie” waar de agent ze bij elke run leest."}]}, {"kind": "p", "text": "Merk op dat elke mitigatie gaat over het geven van een gecureerde design-context aan de agent. Die context handmatig onderhouden, per project, is precies het gepriegel dat Open Design wegneemt."}]}, {"id": "open-design", "heading": "Ontwerpen met Gemini CLI binnen Open Design", "blocks": [{"kind": "p", "text": "Open Design is de open-source design-laag waar de bovenstaande workflow steeds om vraagt. Het behandelt Gemini CLI als een first-party adapter en omhult het met een gecureerde skill- en design-system-bibliotheek, een gestructureerde render-pipeline en een lokale desktop-UI — zodat de design-context die Gemini goed maakt er vanaf de eerste run is, niet telkens met de hand samengesteld. Beide zijn open-source en local-first, wat de combinatie een natuurlijke match maakt."}, {"kind": "ol", "items": ["Installeer Open Design en selecteer Gemini CLI als je agent.", "Authenticeer met je Google-account of Gemini API-sleutel (BYOK) — credentials blijven op je machine en worden nooit via ons doorgesluisd.", "Kies een design system en een skill, en genereer vervolgens decks, prototypes en landingspagina’s met consistente smaak.", "Elk artefact en DESIGN.md-bestand leeft in je eigen repo, niet in een gehoste cloud."]}, {"kind": "p", "text": "Dezelfde Gemini CLI-agent, dezelfde sleutel — plus een echte, draagbare, open-source design-workflow eromheen. Het is local-first en Apache-2.0, dus niets over je werk of je credentials verlaat je machine."}]}], "faqTitle": "Veelgestelde vragen", "faq": [{"name": "Kan Gemini CLI echt design-werk doen?", "text": "Ja — met een esthetische skill, een design system en echte referentieafbeeldingen in context produceert Gemini CLI productiekwalitatieve, responsieve UI, en de sterke multimodale modellen verifiëren de output tegen referenties. Zonder die context neigt het naar een generieke look, en dat is de kloof die Open Design dicht."}, {"name": "Moet ik betalen om met Gemini CLI te ontwerpen?", "text": "Nee — inloggen met een Google-account geeft een royale gratis laag, en je kunt ook een eigen Gemini API-sleutel meenemen (BYOK) of Vertex AI gebruiken. Open Design sluist je credentials in beide gevallen nooit door."}, {"name": "Wat maakt Gemini CLI specifiek goed voor design?", "text": "Twee dingen: de modellen zijn sterk multimodaal, dus het leest referentie-schermafbeeldingen goed, en de context van 1M tokens kan een heel design system en referentieset in één keer vasthouden. Beide helpen — maar smaak komt nog steeds uit het design system, de skill en de referenties die jij aanlevert."}, {"name": "Gemini CLI of Claude Code voor frontend-design?", "text": "Beide zijn sterk. Claude Code staat bekend om specifieke, codebase-bewuste design-beslissingen; het voordeel van Gemini CLI is multimodaal begrip plus een enorme context en een gratis laag. Veel teams gebruiken beide — met Open Design kun je van agent wisselen zonder je design-workflow te veranderen."}, {"name": "Hoe verbind ik Gemini CLI met Figma?", "text": "Voeg de Figma MCP-server toe onder mcpServers in ~/.gemini/settings.json. Gemini kan dan echte design-context ophalen — componenten, variabelen, layout-data — zodat de gegenereerde code overeenkomt met de bron in plaats van die te benaderen."}, {"name": "Is Open Design gelieerd aan Google?", "text": "Nee. Gemini CLI is een product van Google; Open Design is een onafhankelijk open-source project dat het ondersteunt als first-party adapter. Gemini is een handelsmerk van Google."}, {"name": "Zijn mijn bestanden en credentials veilig?", "text": "Ja — Open Design is local-first en Apache-2.0. Je bestanden, artefacten en DESIGN.md blijven in je eigen repo, en je Google-credentials worden rechtstreeks door je agent gebruikt, nooit via Open Design-servers geleid."}], "ctaTitle": "Ontwerp met Gemini CLI, op de open manier.", "ctaBody": "Neem je eigen Google-account of Gemini API-sleutel mee, houd elk bestand lokaal, en krijg een gecureerde design-bibliotheek rond de agent die je al gebruikt.", "ctaActions": [{"label": "Gebruik Gemini CLI binnen Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Bekijk alle ondersteunde agents"},
      },
      'copilot': {
        ...en['copilot']!,
        title: "GitHub Copilot CLI voor design — Open Design",
        description: "Hoe mensen GitHub Copilot CLI gebruiken voor UI- en webdesign — de terminal-native coding agent, eigen instructiebestanden, MCP-ondersteuning en keuze uit meerdere modellen — en hoe Open Design van Copilot CLI een local-first, open-source design agent maakt.",
        breadcrumb: "GitHub Copilot CLI",
        label: "Agent · GitHub Copilot CLI",
        heading: "GitHub Copilot CLI voor design.",
        lead: "GitHub Copilot CLI is de terminal-native coding agent van GitHub. Hij plant en bewerkt door je hele repo, kiest uit frontier-modellen zoals Claude en GPT en leest je repository-instructies — waardoor het een echt designtool wordt zodra je het referenties, conventies en een verificatielus geeft. Open Design verbindt het met een open-source designworkflow: je GitHub Copilot-abonnement, je bestanden, local-first.",
        rich: {"heroCtaLead": "Open Design maakt van GitHub Copilot CLI een local-first, open-source design agent — je GitHub Copilot-abonnement, je bestanden, een zorgvuldig samengestelde skill- en design-systeembibliotheek eromheen.", "heroCtaActions": [{"label": "Gebruik Copilot CLI in Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["GitHub Copilot CLI is de terminal-native coding agent van GitHub — dezelfde agentic harness die de Copilot coding agent aandrijft, nu naar je command line gebracht. Twee dingen maken het juist voor design interessant: het leest je repository-instructies en AGENTS.md, zodat je designconventies bij elke run met de agent meereizen; en het laat je per taak kiezen uit frontier-modellen van Anthropic, OpenAI en Google, zodat je het model kunt nemen dat het beste redeneert over een bepaalde UI. Gekoppeld aan de juiste referenties, conventies en een verificatielus bouwt het echte, responsive UI — en het draait op het Copilot-abonnement dat je misschien al hebt. Dit is een praktische, end-to-end-gids voor het gebruik van Copilot CLI voor UI-, frontend- en design-systeemwerk, en voor het inbedden ervan in een gestructureerde designworkflow met Open Design.", "Het behandelt wat Copilot CLI echt is, waarom repository-instructies en modelkeuze bij design passen, hoe je het vanaf nul instelt, de screenshot-naar-UI-lus, hoe eigen instructies en MCP het uitbreiden, hoe het zich verhoudt tot Codex, Claude Code, Cursor en Gemini CLI, de valkuilen die AI-output generiek doen lijken, en hoe Open Design het gat dicht als een open, local-first designlaag — je abonnement en credentials blijven op je machine, je artefacten blijven in je eigen repo."], "heroImage": {"src": "/agents/copilot-design/copilot-design-hero.webp", "alt": "Feedbacklus van GitHub Copilot CLI-design: een terminal-agent die een referentieafbeelding leest, een browser die de UI rendert en een werkruimte, met een feedbackpijl die terugkoppelt", "caption": "De kernlus: Copilot CLI leest je referenties in de terminal, bouwt en verifieert de UI in een echte browser en itereert eraan — met je designconventies in repository-instructies."}, "tocLabel": "Op deze pagina", "toc": [{"id": "what-is-copilot", "label": "Wat GitHub Copilot CLI eigenlijk is"}, {"id": "why-design", "label": "Waarom instructies + modelkeuze bij design passen"}, {"id": "setup", "label": "Copilot CLI voor design instellen (vanaf nul)"}, {"id": "screenshot-workflow", "label": "De screenshot-naar-UI-workflow"}, {"id": "extend", "label": "Eigen instructies, MCP en uitbreidingen"}, {"id": "vs", "label": "Copilot CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Valkuilen en de “AI slop”-look"}, {"id": "open-design", "label": "Ontwerpen met Copilot CLI in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-copilot", "heading": "Wat GitHub Copilot CLI eigenlijk is", "blocks": [{"kind": "p", "text": "GitHub Copilot CLI is de terminal-native coding agent van GitHub. Hij leest je repository, bewerkt bestanden, voert shell-commando's uit en werkt rechtstreeks met je GitHub-context — issues, pull requests en repositories — geauthenticeerd met je bestaande GitHub-account. Hij wordt aangedreven door dezelfde agentic harness als de Copilot coding agent van GitHub, dus hij plant complexe taken en itereert in plaats van alleen regels af te maken. Hij werd in februari 2026 algemeen beschikbaar, na een public preview die in september 2025 openging."}, {"kind": "p", "text": "Voor designwerk springen twee eigenschappen eruit. Het leest eigen instructiebestanden — repository-brede regels in .github/copilot-instructions.md plus AGENTS.md — zodat je designconventies bij elke run automatisch worden meegenomen. En het ondersteunt meerdere foundation-modelaanbieders, zodat je per taak met het /model-commando kunt wisselen naar het model dat het beste redeneert over een bepaalde UI."}, {"kind": "steps", "items": [{"label": "Instructiebestanden", "body": "Copilot CLI leest repository-instructies in .github/copilot-instructions.md, padspecifieke bestanden onder .github/instructions en AGENTS.md — de natuurlijke plek om je designconventies, tokens en reviewchecklists vast te leggen."}, {"label": "Ingebouwde tools + MCP", "body": "Het wordt geleverd met de MCP-server van GitHub ingebouwd en draait bestands- en shell-tools, en je kunt eigen MCP-servers toevoegen met /mcp add (opgeslagen in mcp-config.json onder ~/.copilot) voor externe context zoals een live Figma-bestand."}, {"label": "Modelkeuze", "body": "Gebruik het /model-commando om te kiezen uit frontier-modellen van Anthropic, OpenAI en Google — per taak wisselen, allemaal op je bestaande Copilot-abonnement."}]}, {"kind": "ul", "items": ["Leverancier: GitHub", "Credential: een actief GitHub Copilot-abonnement (Pro, Pro+, Business of Enterprise)", "Installeren: npm install -g @github/copilot, voer daarna copilot uit"]}]}, {"id": "why-design", "heading": "Waarom repository-instructies en modelkeuze bij design passen", "blocks": [{"kind": "p", "text": "Het designvoordeel van Copilot CLI komt voort uit twee eigenschappen — maar, zoals bij elke agent, moet smaak nog steeds worden aangeleverd."}, {"kind": "steps", "items": [{"label": "Conventies die met de repo meereizen", "body": "Omdat Copilot CLI .github/copilot-instructions.md en AGENTS.md automatisch leest, zitten je tokens, primitives en reviewregels bij elke run in context — de agent werkt tegen een merk in plaats van een standaardlook."}, {"label": "Kies het juiste model per taak", "body": "Modelkeuze over Anthropic, OpenAI en Google betekent dat je kunt grijpen naar het model dat het beste redeneert over een bepaalde layout, en dan voor de volgende taak wisselen — zonder je workflow te veranderen."}, {"label": "Echte specs via MCP", "body": "De ingebouwde GitHub MCP-server plus een Figma MCP-server wijzen de agent naar je tokens, componenten en echte specs, zodat het vanuit de bron bouwt in plaats van te benaderen."}]}, {"kind": "image", "src": "/agents/copilot-design/copilot-design-taste-triangle.webp", "alt": "Diagram dat laat zien hoe design-systeem, skill en referentieafbeelding samenkomen tot goede designoutput", "caption": "Smaak komt uit drie inputs die jij aanlevert: een design-systeem, een skill en echte referentieafbeeldingen."}, {"kind": "p", "text": "De les is dezelfde die elke agent leert: Copilot CLI heeft standaard geen smaak. Het levert goed design als je het beperkingen geeft — een design-systeem, een esthetische skill en concrete referenties. Open Design verpakt precies die inputs, en daarom passen de twee samen (meer hieronder)."}]}, {"id": "setup", "heading": "Copilot CLI voor designwerk instellen, vanaf nul", "blocks": [{"kind": "p", "text": "Hier is het volledige pad van een schone machine naar een Copilot CLI die UI kan bouwen en verifiëren."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Copilot CLI (Node.js required)\nnpm install -g @github/copilot\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\ncopilot           # run /login and follow the prompts to sign in\n\n# 3. Choose a model for the task\n#    inside the session:\n/model            # pick a frontier model from Anthropic, OpenAI, or Google\n\n# 4. Add custom instructions and the Figma MCP server (optional)\n#    write .github/copilot-instructions.md or AGENTS.md\n/mcp add          # add the Figma MCP server for design handoff"}, {"kind": "image", "src": "/agents/copilot-design/copilot-design-setup-flow.webp", "alt": "Setupstroom in vijf stappen: installeren, authenticeren, een model kiezen, instructies configureren, verifiëren", "caption": "De setupvolgorde: installeren → authenticeren → een model kiezen → instructies schrijven → browserverificatie inschakelen."}, {"kind": "steps", "items": [{"label": "Leg je designregels vast", "body": "Zet je tokens, primitives en conventies in .github/copilot-instructions.md of AGENTS.md, zodat de output bij een merk past in plaats van standaard naar een generieke look te vallen."}, {"label": "Voeg browserverificatie toe", "body": "Koppel een Playwright- of browser-MCP zodat Copilot in een echte browser rendert en zijn output over breekpunten controleert in plaats van alleen te bevestigen dat de build slaagt."}]}]}, {"id": "screenshot-workflow", "heading": "De screenshot-naar-UI-workflow", "blocks": [{"kind": "p", "text": "De designlus met de meeste hefboomwerking bij Copilot CLI is een referentieafbeelding omzetten in werkende, responsive UI en itereren tot het overeenkomt — leunend op een sterk multimodaal model om de output terug te vergelijken met de referentie."}, {"kind": "ol", "items": ["Begin met de duidelijkste visuele referenties die je hebt — en neem meerdere toestanden mee (desktop en mobiel, hover, leeg, laden), niet alleen één hero-shot.", "Wees specifiek in de prompt; vage prompts leveren generieke UI op, zelfs met een sterk model.", "Houd je design-systeem en conventies in .github/copilot-instructions.md of AGENTS.md, en vertel Copilot waar de tokens en canonieke primitives zich bevinden.", "Draai een dev-server en laat Copilot in een echte browser renderen, met formaatwijziging naar breekpunten om het resultaat te controleren.", "Itereer door Copilot zijn implementatie terug te laten vergelijken met de screenshots — niet alleen bevestigen dat het bouwt."]}, {"kind": "p", "text": "Wijs Copilot naar je referentieafbeeldingen en geef concrete beperkingen; het toont een voorbeeld van elke bestandsbewerking of elk commando ter goedkeuring voordat het uitvoert:"}, {"kind": "code", "lang": "bash", "code": "copilot\n# in the prompt:\n> Implement the design in reference-desktop.png and reference-mobile.png\n  in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens described in\n  .github/copilot-instructions.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Houd prompts klein en gericht, commit goede iteraties en draai slechte terug (en vertel Copilot wanneer je terugdraait), zodat elke ronde voortbouwt op een schone basis."}]}, {"id": "extend", "heading": "Eigen instructies, MCP en uitbreidingen", "blocks": [{"kind": "p", "text": "Drie uitbreidingspunten maken Copilot CLI praktisch voor langdurig designwerk, en alle drie sluiten ze netjes aan op een open designworkflow."}, {"kind": "steps", "items": [{"label": "Eigen instructies", "body": "Repositoryregels staan in .github/copilot-instructions.md (met padspecifieke bestanden onder .github/instructions en AGENTS.md). Het zijn het duurzame thuis voor je designconventies, automatisch meegenomen bij elke run."}, {"label": "MCP-servers", "body": "Copilot CLI wordt geleverd met de MCP-server van GitHub ingebouwd en laat je eigen servers toevoegen via /mcp add (opgeslagen in mcp-config.json onder ~/.copilot) — de draagbare manier om designcontext in te brengen, het meest relevant de Figma MCP-server, die over agents heen werkt, niet alleen Copilot."}, {"label": "Gespecialiseerde agents en ingebouwde tools", "body": "De gespecialiseerde modi van Copilot CLI — voor codebase-verkenning, het draaien van builds en tests, change review en planning — plus de bestands- en shell-tools laten het referenties verzamelen en de verificatielus draaien zonder de terminal te verlaten."}]}, {"kind": "p", "text": "Dit zijn draagbare, multi-agent-mogelijkheden — precies het soort dingen dat Open Design is gebouwd om te orkestreren, in plaats van per project opnieuw te maken."}]}, {"id": "vs", "heading": "Copilot CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI voor design", "blocks": [{"kind": "p", "text": "Er is geen enkele winnaar voor designwerk — elke agent heeft een andere sterkte, en ervaren teams stapelen ze. Een eerlijke samenvatting:"}, {"kind": "table", "columns": ["Agent", "Designsterkte", "Het best voor"], "rows": [["Copilot CLI", "Keuze uit meerdere modellen (Anthropic, OpenAI, Google) en diepe GitHub-integratie op je Copilot-abonnement", "Het beste model per taak kiezen en instructiegedreven werk gekoppeld aan je GitHub-repo"], ["Codex", "Sterke visuele afwerking met een frontend-skill; sandboxed async builds", "Gedelegeerde async builds en draagbare AGENTS.md-regels"], ["Claude Code", "Specifieke designbeslissingen (hex, spacing, type) en codebase-bewuste UX", "Frontend-redenering en refactors met grote context"], ["Cursor", "Visuele bouw-en-zie-lus met live preview en inline-bewerkingen", "Strak itereren-en-meekijken UI-werk binnen een IDE"], ["Gemini CLI", "Sterk multimodaal beeldbegrip en een context van 1M tokens; open-source met een gratis laag", "Screenshot-zwaar werk en een heel design-systeem in context houden"]]}, {"kind": "p", "text": "Het terugkerende oordeel van de community is dat smaak van mensen komt: ze vallen allemaal standaard terug op een generieke esthetiek zonder skills, referenties en beperkingen. Dat is het echte probleem dat moet worden opgelost — en het heeft de vorm van een designtool, niet van een model."}]}, {"id": "pitfalls", "heading": "Valkuilen, en hoe je de “AI slop”-look vermijdt", "blocks": [{"kind": "p", "text": "De meest voorkomende klacht over AI-gegenereerd design is dat het er generiek uitziet — zachte verlopen, zwevende panelen, overdreven afgeronde hoeken, dramatische schaduwen, een Inter-en-paars-vibe die “schreeuwt dat een AI dit heeft gemaakt.” Andere gemelde problemen zijn kapotte mobiele layouts en instructies die in de UI-tekst lekken. Geen daarvan is uniek voor Copilot CLI; ze zijn wat er gebeurt wanneer welke agent dan ook draait zonder een zorgvuldig samengestelde designcontext."}, {"kind": "steps", "items": [{"label": "Voeg een esthetische skill toe", "body": "Een zorgvuldig samengestelde designskill dwingt de agent zich vast te leggen op een echte richting in plaats van de standaardlook."}, {"label": "Verifieer in een echte browser", "body": "Render en controleer jezelf over breekpunten met een browser-MCP zodat layouts niet stilletjes breken op mobiel."}, {"label": "Lever tokens en referenties aan", "body": "Echte design-tokens en referentiescreenshots zijn de grootste enkele hefboom op outputkwaliteit."}, {"label": "Leg regels vast in eigen instructies", "body": "Zet stijlregels als “geen hero-kaarten, maximaal twee lettertypes, merk-eerst hiërarchie” in .github/copilot-instructions.md of AGENTS.md, waar de agent ze elke run leest."}]}, {"kind": "p", "text": "Merk op dat elke mitigatie draait om het geven van een zorgvuldig samengestelde designcontext aan de agent. Die context handmatig onderhouden, per project, is het monnikenwerk dat Open Design wegneemt."}]}, {"id": "open-design", "heading": "Ontwerpen met Copilot CLI in Open Design", "blocks": [{"kind": "p", "text": "Open Design is de open-source designlaag waar de bovenstaande workflow steeds om vraagt. Het behandelt GitHub Copilot CLI als een first-party adapter en omhult het met een zorgvuldig samengestelde skill- en design-systeembibliotheek, een gestructureerde render-pipeline en een lokale desktop-UI — zodat de designcontext die Copilot goed maakt er vanaf de eerste run is, niet elke keer met de hand samengesteld. Open Design is onafhankelijk, open-source (Apache-2.0) en local-first, en daarom past de combinatie: de agent doet het werk, je bestanden en credentials blijven van jou."}, {"kind": "ol", "items": ["Installeer Open Design en selecteer GitHub Copilot CLI als je agent.", "Authenticeer met je GitHub Copilot-abonnement — credentials blijven op je machine en worden nooit via ons doorgesluisd.", "Kies een design-systeem en een skill, en genereer dan decks, prototypes en landingspagina's met consistente smaak.", "Elk artefact en elk DESIGN.md-bestand leeft in je eigen repo, niet in een gehoste cloud."]}, {"kind": "p", "text": "Dezelfde Copilot CLI-agent, hetzelfde abonnement — plus een echte, draagbare, open-source designworkflow eromheen. Open Design is local-first en Apache-2.0, dus niets over je werk of je credentials verlaat je machine."}]}], "faqTitle": "Veelgestelde vragen", "faq": [{"name": "Kan GitHub Copilot CLI echt designwerk doen?", "text": "Ja — met een esthetische skill, een design-systeem en echte referentieafbeeldingen in context produceert Copilot CLI productiekwaliteit, responsive UI, en je kunt het model kiezen dat de output het beste verifieert tegen referenties. Zonder die context neigt het standaard naar een generieke look, en dat is het gat dat Open Design opvult."}, {"name": "Heb ik een abonnement nodig om met Copilot CLI te ontwerpen?", "text": "Ja — Copilot CLI draait op een actief GitHub Copilot-abonnement (Pro, Pro+, Business of Enterprise); het is geen bring-your-own-key. Je authenticeert met je GitHub-account. Open Design sluist je credentials nooit door — je abonnement wordt rechtstreeks door je agent gebruikt."}, {"name": "Wat maakt Copilot CLI specifiek goed voor design?", "text": "Twee dingen: het leest repository-instructies en AGENTS.md automatisch, zodat je designconventies met de repo meereizen; en het laat je per taak wisselen tussen frontier-modellen van Anthropic, OpenAI en Google. Beide helpen — maar smaak komt nog steeds uit het design-systeem, de skill en de referenties die jij aanlevert."}, {"name": "Copilot CLI of Claude Code voor frontend-design?", "text": "Beide zijn sterk. Claude Code staat bekend om specifieke, codebase-bewuste designbeslissingen; het voordeel van Copilot CLI is modelkeuze over aanbieders heen en diepe GitHub-integratie op een abonnement dat je misschien al hebt. Veel teams gebruiken beide — met Open Design kun je van agent wisselen zonder je designworkflow te veranderen."}, {"name": "Hoe verbind ik Copilot CLI met Figma?", "text": "Voeg de Figma MCP-server toe met het /mcp add-commando; instellingen worden opgeslagen in mcp-config.json onder ~/.copilot. Copilot kan dan echte designcontext ophalen — componenten, variabelen, layoutdata — zodat de gegenereerde code overeenkomt met de bron in plaats van die te benaderen."}, {"name": "Is Open Design verbonden met GitHub of Microsoft?", "text": "Nee. GitHub Copilot CLI is een product van GitHub; Open Design is een onafhankelijk open-source project dat het ondersteunt als first-party adapter. GitHub Copilot is een handelsmerk van GitHub, Inc. en Microsoft."}, {"name": "Zijn mijn bestanden en credentials veilig?", "text": "Ja — Open Design is local-first en Apache-2.0. Je bestanden, artefacten en DESIGN.md blijven in je eigen repo, en je GitHub Copilot-credentials worden rechtstreeks door je agent gebruikt, nooit via Open Design-servers gerouteerd."}], "ctaTitle": "Ontwerp met GitHub Copilot CLI, op de open manier.", "ctaBody": "Breng je GitHub Copilot-abonnement mee, houd elk bestand lokaal en krijg een zorgvuldig samengestelde designbibliotheek rond de agent die je al gebruikt.", "ctaActions": [{"label": "Gebruik Copilot CLI in Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Bekijk alle ondersteunde agents"},
      },
      'qwen': {
        ...en['qwen']!,
        title: "Qwen Code voor design — Open Design",
        description: "Hoe mensen Alibaba's open-source Qwen Code CLI gebruiken voor UI- en webdesign — de Qwen3-Coder-modellen, groot contextvenster, QWEN.md en MCP — en hoe Open Design van Qwen Code een local-first, open-source design agent maakt.",
        breadcrumb: "Qwen Code",
        label: "Agent · Qwen Code",
        heading: "Qwen Code voor design.",
        lead: "Qwen Code is Alibaba's open-source terminal-agent, aangepast van Gemini CLI en afgestemd op de Qwen3-Coder-modellen. Het grote contextvenster houdt een heel design-systeem in één keer vast, waardoor het een echt designtool wordt — zodra je het referenties, conventies en een verificatielus geeft. Open Design verbindt het met een open-source designworkflow: je DashScope- of Qwen-API-sleutel, je bestanden, local-first.",
        rich: {"heroCtaLead": "Open Design maakt van Qwen Code een local-first, open-source design agent — je DashScope- of Qwen-API-sleutel, je bestanden, een zorgvuldig samengestelde skill- en design-systeembibliotheek eromheen.", "heroCtaActions": [{"label": "Gebruik Qwen Code in Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Qwen Code is Alibaba's open-source AI-agent voor de terminal. Het is aangepast van Google's Gemini CLI, met aanpassingen op parserniveau en in de prompts die het maximale uit de Qwen3-Coder-modellen halen. Twee dingen maken het juist voor design interessant: het is een sterk agentic coding-model, dus het plant, bewerkt bestanden en draait de build- en verificatielus vanuit een taak in natuurlijke taal; en het grote contextvenster kan een heel design-systeem en een hele codebase in één keer vasthouden. Gekoppeld aan de juiste referenties, conventies en een verificatielus bouwt het echte, responsive UI — en het is open-source en BYOK, dus je brengt je eigen sleutel mee. Dit is een praktische, end-to-end-gids voor het gebruik van Qwen Code voor UI-, frontend- en design-systeemwerk, en voor het inbedden ervan in een gestructureerde designworkflow met Open Design.", "Het behandelt wat Qwen Code echt is, waarom een sterk coder-model plus een grote context bij design passen, hoe je het vanaf nul instelt, de referentie-naar-UI-lus, hoe QWEN.md en MCP het uitbreiden, hoe het zich verhoudt tot Codex, Claude Code, Cursor en Gemini CLI, de valkuilen die AI-output generiek doen lijken, en hoe Open Design het gat dicht als een open, local-first designlaag — een natuurlijke combinatie, aangezien beide open-source zijn en op je eigen machine draaien."], "heroImage": {"src": "/agents/qwen-design/qwen-design-hero.webp", "alt": "Feedbacklus van Qwen Code-design: een terminal-agent die een referentieafbeelding leest, een browser die de UI rendert en een werkruimte, met een feedbackpijl die terugkoppelt", "caption": "De kernlus: Qwen Code leest je referenties in de terminal, bouwt en verifieert de UI in een echte browser en itereert eraan — met een heel design-systeem in context."}, "tocLabel": "Op deze pagina", "toc": [{"id": "what-is-qwen", "label": "Wat Qwen Code eigenlijk is"}, {"id": "why-design", "label": "Waarom een sterk coder-model + grote context bij design passen"}, {"id": "setup", "label": "Qwen Code voor design instellen (vanaf nul)"}, {"id": "screenshot-workflow", "label": "De referentie-naar-UI-workflow"}, {"id": "extend", "label": "QWEN.md, MCP en uitbreidingen"}, {"id": "vs", "label": "Qwen Code vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Valkuilen en de “AI slop”-look"}, {"id": "open-design", "label": "Ontwerpen met Qwen Code in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-qwen", "heading": "Wat Qwen Code eigenlijk is", "blocks": [{"kind": "p", "text": "Qwen Code is een open-source (Apache-2.0) AI-agent die Alibaba uitbrengt voor de terminal. Het leest je repository, bewerkt bestanden, voert shell-commando's uit en werkt op het web — werk plannend en verifiërend vanuit taken in natuurlijke taal in plaats van alleen regels af te maken. Het is aangepast van Google's Gemini CLI, met aanpassingen op parserniveau en in de prompts die zijn afgestemd om de Qwen3-Coder-modellen te ontsluiten voor agentic coding-taken."}, {"kind": "p", "text": "Voor designwerk springen twee eigenschappen eruit. Het is een capabele agentic coder, dus het kan een referentie en een duidelijke briefing nemen en responsive UI bouwen, draaien en zelf corrigeren. En de Qwen3-Coder-modellen dragen een groot contextvenster, groot genoeg om je hele design-systeem, componentenbibliotheek en referentieset in één keer vast te houden in plaats van ze samen te vatten."}, {"kind": "steps", "items": [{"label": "Contextbestanden", "body": "Qwen Code leest een QWEN.md-bestand voor persistente projectcontext — de natuurlijke plek om je designconventies, tokens en reviewchecklists vast te leggen. Persoonlijke en projectinstellingen komen daar bovenop."}, {"label": "Ingebouwde tools + MCP", "body": "Het levert standaard bestands-, shell- en webtools, en ondersteunt MCP-servers (geconfigureerd onder mcpServers in ~/.qwen/settings.json) om externe context toe te voegen zoals een live Figma-bestand."}, {"label": "BYOK om te beginnen", "body": "Je brengt je eigen sleutel mee — een DashScope (Alibaba Cloud Model Studio) API-sleutel, of een willekeurig OpenAI-compatibel eindpunt of ModelScope — en configureert die in settings.json."}]}, {"kind": "ul", "items": ["Leverancier: Alibaba", "Credential: DashScope / Qwen API-sleutel (BYOK), of OpenAI-compatibel eindpunt / ModelScope", "Licentie: Apache-2.0, open source (aangepast van Gemini CLI)"]}]}, {"id": "why-design", "heading": "Waarom een sterk coder-model en een grote context bij design passen", "blocks": [{"kind": "p", "text": "Het designvoordeel van Qwen Code komt voort uit twee eigenschappen — maar, zoals bij elke agent, moet smaak nog steeds worden aangeleverd."}, {"kind": "steps", "items": [{"label": "Sterke agentic coding", "body": "De Qwen3-Coder-modellen zijn afgestemd op agentic taken, dus de agent plant, bewerkt, draait de build en corrigeert zichzelf — en zet een duidelijke referentie en briefing om in responsive markup in plaats van een one-shot gok."}, {"label": "Een groot contextvenster", "body": "De grote context van Qwen3-Coder betekent dat het hele design-systeem, de tokens en veel referentietoestanden in één keer passen, zodat de agent je echte primitives hergebruikt in plaats van eenmalige stijlen te verzinnen."}, {"label": "Conventies in QWEN.md", "body": "Een QWEN.md (plus de Figma MCP-server) wijst de agent naar je tokens, componenten en echte specs, zodat het tegen een merk werkt in plaats van een standaardlook."}]}, {"kind": "image", "src": "/agents/qwen-design/qwen-design-taste-triangle.webp", "alt": "Diagram dat laat zien hoe design-systeem, skill en referentieafbeelding samenkomen tot goede designoutput", "caption": "Smaak komt uit drie inputs die jij aanlevert: een design-systeem, een skill en echte referentieafbeeldingen."}, {"kind": "p", "text": "De les is dezelfde die elke agent leert: Qwen Code heeft standaard geen smaak. Het levert goed design als je het beperkingen geeft — een design-systeem, een esthetische skill en concrete referenties. Open Design verpakt precies die inputs, en daarom passen de twee samen (meer hieronder)."}]}, {"id": "setup", "heading": "Qwen Code voor designwerk instellen, vanaf nul", "blocks": [{"kind": "p", "text": "Hier is het volledige pad van een schone machine naar een Qwen Code die UI kan bouwen en verifiëren."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Qwen Code (Node 22+)\nnpm install -g @qwen-code/qwen-code@latest\n# or: brew install qwen-code\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\nqwen              # run /auth, or set a key in ~/.qwen/settings.json\n\n# 3. Configure a DashScope (OpenAI-compatible) key in settings.json\n#    baseUrl: https://dashscope.aliyuncs.com/compatible-mode/v1\n#    model:   qwen3-coder-plus   (set DASHSCOPE_API_KEY)\n\n# 4. Add a QWEN.md and wire the Figma MCP server (optional)\n#    add MCP under \"mcpServers\" in ~/.qwen/settings.json"}, {"kind": "image", "src": "/agents/qwen-design/qwen-design-setup-flow.webp", "alt": "Setupstroom in vijf stappen: installeren, authenticeren, QWEN.md configureren, een skill toevoegen, verifiëren", "caption": "De setupvolgorde: installeren → authenticeren → QWEN.md configureren → een skill toevoegen → browserverificatie inschakelen."}, {"kind": "steps", "items": [{"label": "Leg je designregels vast", "body": "Zet je tokens, primitives en conventies in QWEN.md en wijs Qwen Code ernaar, zodat de output bij een merk past in plaats van standaard naar een generieke look te vallen."}, {"label": "Voeg browserverificatie toe", "body": "Koppel een Playwright- of browser-MCP zodat Qwen Code in een echte browser rendert en zijn output over breekpunten controleert in plaats van alleen te bevestigen dat de build slaagt."}]}]}, {"id": "screenshot-workflow", "heading": "De referentie-naar-UI-workflow", "blocks": [{"kind": "p", "text": "De designlus met de meeste hefboomwerking bij Qwen Code is een referentie omzetten in werkende, responsive UI en itereren tot het overeenkomt — leunend op de agent om zijn output te bouwen, te renderen en terug te vergelijken met de referentie."}, {"kind": "ol", "items": ["Begin met de duidelijkste visuele referenties die je hebt — en beschrijf meerdere toestanden (desktop en mobiel, hover, leeg, laden), niet alleen één hero-shot.", "Wees specifiek in de prompt; vage prompts leveren generieke UI op, zelfs met een sterk model.", "Houd je design-systeem en conventies in QWEN.md, en vertel Qwen Code waar de tokens en canonieke primitives zich bevinden.", "Draai een dev-server en laat Qwen Code in een echte browser renderen, met formaatwijziging naar breekpunten om het resultaat te controleren.", "Itereer door Qwen Code zijn implementatie terug te laten vergelijken met de referenties — niet alleen bevestigen dat het bouwt."]}, {"kind": "p", "text": "Verwijs naar een bestand met @ om het aan de prompt te koppelen, en geef dan concrete beperkingen:"}, {"kind": "code", "lang": "bash", "code": "qwen\n# in the prompt:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from QWEN.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Houd prompts klein en gericht, commit goede iteraties en draai slechte terug (en vertel Qwen Code wanneer je terugdraait), zodat elke ronde voortbouwt op een schone basis."}]}, {"id": "extend", "heading": "QWEN.md, MCP en uitbreidingen", "blocks": [{"kind": "p", "text": "Drie uitbreidingspunten maken Qwen Code praktisch voor langdurig designwerk, en alle drie sluiten ze netjes aan op een open designworkflow."}, {"kind": "steps", "items": [{"label": "QWEN.md-context", "body": "Projectregels staan in een QWEN.md in de root van de repo (met globale en projectlagen). Het is het duurzame thuis voor je designconventies, gelezen bij elke run."}, {"label": "MCP-servers", "body": "Configureer MCP-servers onder mcpServers in ~/.qwen/settings.json — de draagbare manier om designcontext en externe tools in te brengen, het meest relevant de Figma MCP-server, die over agents heen werkt, niet alleen Qwen Code."}, {"label": "Skills en ingebouwde tools", "body": "Qwen Code-skills en de ingebouwde bestands-, shell- en webtools laten het referenties verzamelen en de verificatielus draaien zonder de terminal te verlaten."}]}, {"kind": "p", "text": "Dit zijn draagbare, multi-agent-mogelijkheden — precies het soort dingen dat Open Design is gebouwd om te orkestreren, in plaats van per project opnieuw te maken."}]}, {"id": "vs", "heading": "Qwen Code vs Codex vs Claude Code vs Cursor vs Gemini CLI voor design", "blocks": [{"kind": "p", "text": "Er is geen enkele winnaar voor designwerk — elke agent heeft een andere sterkte, en ervaren teams stapelen ze. Een eerlijke samenvatting:"}, {"kind": "table", "columns": ["Agent", "Designsterkte", "Het best voor"], "rows": [["Qwen Code", "Sterke agentic coding op de open Qwen3-Coder-modellen met een grote context; open-source en BYOK", "Open-source, sleutel-flexibele builds die een heel design-systeem in context houden"], ["Codex", "Sterke visuele afwerking met een frontend-skill; sandboxed async builds", "Gedelegeerde async builds en draagbare AGENTS.md-regels"], ["Claude Code", "Specifieke designbeslissingen (hex, spacing, type) en codebase-bewuste UX", "Frontend-redenering en refactors met grote context"], ["Cursor", "Visuele bouw-en-zie-lus met live preview en inline-bewerkingen", "Strak itereren-en-meekijken UI-werk binnen een IDE"], ["Gemini CLI", "Sterk multimodaal beeldbegrip en een context van 1M tokens; de agent waarvan Qwen Code is aangepast", "Screenshot-zwaar werk en zeer grote context"]]}, {"kind": "p", "text": "Het terugkerende oordeel van de community is dat smaak van mensen komt: ze vallen allemaal standaard terug op een generieke esthetiek zonder skills, referenties en beperkingen. Dat is het echte probleem dat moet worden opgelost — en het heeft de vorm van een designtool, niet van een model."}]}, {"id": "pitfalls", "heading": "Valkuilen, en hoe je de “AI slop”-look vermijdt", "blocks": [{"kind": "p", "text": "De meest voorkomende klacht over AI-gegenereerd design is dat het er generiek uitziet — zachte verlopen, zwevende panelen, overdreven afgeronde hoeken, dramatische schaduwen, een Inter-en-paars-vibe die “schreeuwt dat een AI dit heeft gemaakt.” Andere gemelde problemen zijn kapotte mobiele layouts en instructies die in de UI-tekst lekken. Geen daarvan is uniek voor Qwen Code; ze zijn wat er gebeurt wanneer welke agent dan ook draait zonder een zorgvuldig samengestelde designcontext."}, {"kind": "steps", "items": [{"label": "Voeg een esthetische skill toe", "body": "Een zorgvuldig samengestelde designskill dwingt de agent zich vast te leggen op een echte richting in plaats van de standaardlook."}, {"label": "Verifieer in een echte browser", "body": "Laat de agent renderen en zichzelf controleren over breekpunten zodat layouts niet stilletjes breken op mobiel."}, {"label": "Lever tokens en referenties aan", "body": "Echte design-tokens en referentiescreenshots zijn de grootste enkele hefboom op outputkwaliteit."}, {"label": "Leg regels vast in QWEN.md", "body": "Zet stijlregels als “geen hero-kaarten, maximaal twee lettertypes, merk-eerst hiërarchie” waar de agent ze elke run leest."}]}, {"kind": "p", "text": "Merk op dat elke mitigatie draait om het geven van een zorgvuldig samengestelde designcontext aan de agent. Die context handmatig onderhouden, per project, is het monnikenwerk dat Open Design wegneemt."}]}, {"id": "open-design", "heading": "Ontwerpen met Qwen Code in Open Design", "blocks": [{"kind": "p", "text": "Open Design is de open-source designlaag waar de bovenstaande workflow steeds om vraagt. Het behandelt Qwen Code als een first-party adapter en omhult het met een zorgvuldig samengestelde skill- en design-systeembibliotheek, een gestructureerde render-pipeline en een lokale desktop-UI — zodat de designcontext die Qwen Code goed maakt er vanaf de eerste run is, niet elke keer met de hand samengesteld. Beide zijn open-source en local-first, wat de combinatie een natuurlijke match maakt."}, {"kind": "ol", "items": ["Installeer Open Design en selecteer Qwen Code als je agent.", "Authenticeer met je DashScope- of Qwen-API-sleutel (BYOK) — credentials blijven op je machine en worden nooit via ons doorgesluisd.", "Kies een design-systeem en een skill, en genereer dan decks, prototypes en landingspagina's met consistente smaak.", "Elk artefact en elk DESIGN.md-bestand leeft in je eigen repo, niet in een gehoste cloud."]}, {"kind": "p", "text": "Dezelfde Qwen Code-agent, dezelfde sleutel — plus een echte, draagbare, open-source designworkflow eromheen. Het is local-first en Apache-2.0, dus niets over je werk of je credentials verlaat je machine."}]}], "faqTitle": "Veelgestelde vragen", "faq": [{"name": "Kan Qwen Code echt designwerk doen?", "text": "Ja — met een esthetische skill, een design-systeem en echte referentieafbeeldingen in context produceert Qwen Code productiekwaliteit, responsive UI, en de agentic lus bouwt, rendert en verifieert de output tegen referenties. Zonder die context neigt het standaard naar een generieke look, en dat is het gat dat Open Design opvult."}, {"name": "Moet ik betalen om met Qwen Code te ontwerpen?", "text": "Qwen Code is gratis en open-source, maar het is BYOK — je brengt een DashScope (Alibaba Cloud Model Studio) API-sleutel, een OpenAI-compatibel eindpunt of ModelScope mee. Alibaba biedt ook een coding-plan met vaste prijs aan. Open Design sluist je credentials hoe dan ook nooit door."}, {"name": "Wat maakt Qwen Code specifiek goed voor design?", "text": "Twee dingen: de Qwen3-Coder-modellen zijn afgestemd op agentic coding, zodat de agent responsive UI bouwt en zichzelf corrigeert, en hun grote context kan een heel design-systeem en referentieset in één keer vasthouden. Beide helpen — maar smaak komt nog steeds uit het design-systeem, de skill en de referenties die jij aanlevert."}, {"name": "Is Qwen Code hetzelfde als Gemini CLI?", "text": "Nee. Qwen Code is aangepast van Google's Gemini CLI — dezelfde open-source afstamming — met aanpassingen op parserniveau en in de prompts die het afstemmen op de Qwen3-Coder-modellen. Open Design ondersteunt beide, dus je kunt van agent wisselen zonder je designworkflow te veranderen."}, {"name": "Hoe verbind ik Qwen Code met Figma?", "text": "Voeg de Figma MCP-server toe onder mcpServers in ~/.qwen/settings.json. Qwen Code kan dan echte designcontext ophalen — componenten, variabelen, layoutdata — zodat de gegenereerde code overeenkomt met de bron in plaats van die te benaderen."}, {"name": "Is Open Design verbonden met Alibaba of Qwen?", "text": "Nee. Qwen Code is een product van Alibaba; Open Design is een onafhankelijk open-source project dat het ondersteunt als first-party adapter. Qwen is een handelsmerk van Alibaba."}, {"name": "Zijn mijn bestanden en credentials veilig?", "text": "Ja — Open Design is local-first en Apache-2.0. Je bestanden, artefacten en DESIGN.md blijven in je eigen repo, en je DashScope- of Qwen-credentials worden rechtstreeks door je agent gebruikt, nooit via Open Design-servers gerouteerd."}], "ctaTitle": "Ontwerp met Qwen Code, op de open manier.", "ctaBody": "Breng je eigen DashScope- of Qwen-API-sleutel mee, houd elk bestand lokaal en krijg een zorgvuldig samengestelde designbibliotheek rond de agent die je al gebruikt.", "ctaActions": [{"label": "Gebruik Qwen Code in Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Bekijk alle ondersteunde agents"},
      },
      'grok': {
        ...en['grok']!,
        title: "Grok Build voor design — Open Design",
        description: "Hoe mensen xAI's Grok Build (Grok Build) gebruiken voor UI- en webdesign — de planmodus, AGENTS.md en MCP, beeldbewuste Grok-modellen en grote context — en hoe Open Design van Grok Build een local-first, open-source design agent maakt.",
        breadcrumb: "Grok Build",
        label: "Agent · Grok Build",
        heading: "Grok Build voor design.",
        lead: "Grok Build is de terminal-coding-agent van xAI. Hij plant werk in meerdere stappen voordat hij je bestanden aanraakt, leest afbeeldingen naast code en draait de bouw-en-verifieer-lus in je repo — waardoor het een echt designtool wordt zodra je het referenties, conventies en een verificatiestap geeft. Open Design verbindt het met een open-source designworkflow: je SuperGrok-login of xAI-API-sleutel, je bestanden, local-first.",
        rich: {"heroCtaLead": "Open Design maakt van Grok Build een local-first, open-source design agent — je SuperGrok-login of xAI-API-sleutel, je bestanden, een zorgvuldig samengestelde skill- en design-systeembibliotheek eromheen.", "heroCtaActions": [{"label": "Gebruik Grok Build in Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Grok Build — de terminal-coding-agent van xAI, uitgebracht als Grok Build — is een agentic tool dat in je terminal leeft. Twee dingen maken het juist voor design interessant: het plant riskant werk voordat het handelt, zodat je een voorgestelde aanpak kunt beoordelen voordat er bestanden veranderen; en de Grok-modellen accepteren beeldinvoer, zodat het kan redeneren over een referentiescreenshot naast de code die het schrijft. Gekoppeld aan de juiste referenties, conventies en een verificatielus bouwt het echte, responsive UI — geauthenticeerd rechtstreeks via je SuperGrok- of X Premium+-account, zonder gejongleer met API-sleutels. Dit is een praktische, end-to-end-gids voor het gebruik van Grok Build voor UI-, frontend- en design-systeemwerk, en voor het inbedden ervan in een gestructureerde designworkflow met Open Design.", "Het behandelt wat Grok Build echt is, waarom de planmodus en beeldbewuste modellen bij design passen, hoe je het vanaf nul instelt, de screenshot-naar-UI-lus, hoe AGENTS.md en MCP het uitbreiden, hoe het zich verhoudt tot Codex, Claude Code, Cursor en Gemini CLI, de valkuilen die AI-output generiek doen lijken, en hoe Open Design het gat dicht als een open, local-first designlaag — je credentials en artefacten verlaten nooit je machine."], "heroImage": {"src": "/agents/grok-design/grok-design-hero.webp", "alt": "Feedbacklus van Grok Build-design: een terminal-agent die plant vanuit een referentieafbeelding, een browser die de UI rendert en een werkruimte, met een feedbackpijl die terugkoppelt", "caption": "De kernlus: Grok Build plant vanuit je referenties in de terminal, bouwt en verifieert de UI in een echte browser en itereert eraan — met je conventies in AGENTS.md."}, "tocLabel": "Op deze pagina", "toc": [{"id": "what-is-grok", "label": "Wat Grok Build eigenlijk is"}, {"id": "why-design", "label": "Waarom planmodus + beeldinvoer bij design passen"}, {"id": "setup", "label": "Grok Build voor design instellen (vanaf nul)"}, {"id": "screenshot-workflow", "label": "De screenshot-naar-UI-workflow"}, {"id": "extend", "label": "AGENTS.md, MCP en subagents"}, {"id": "vs", "label": "Grok Build vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Valkuilen en de “AI slop”-look"}, {"id": "open-design", "label": "Ontwerpen met Grok Build in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-grok", "heading": "Wat Grok Build eigenlijk is", "blocks": [{"kind": "p", "text": "Grok Build is de terminal-coding-agent van xAI, uitgebracht onder de naam Grok Build. Hij leest je repository, bewerkt bestanden, voert shell-commando's uit en plant engineeringwerk in meerdere stappen vanuit taken in natuurlijke taal in plaats van alleen regels af te maken. Hij is gebouwd rond xAI's Grok-modellen — beschikbaar op de xAI-API als de grok-build-modelfamilie — en authenticeert via je xAI-account, zodat de agent en de modellen van dezelfde leverancier komen."}, {"kind": "p", "text": "Voor designwerk springen twee eigenschappen eruit. Het heeft een planmodus die een gestructureerde aanpak opstelt die je kunt goedkeuren, becommentariëren of herschrijven voordat er een wijziging landt — een nuttige poort wanneer je itereert op UI. En de Grok-modellen accepteren beeldinvoer, zodat je het een referentiescreenshot kunt geven en het redeneert over de daadwerkelijke layout in plaats van te gokken vanuit een prozabeschrijving."}, {"kind": "steps", "items": [{"label": "Contextbestanden", "body": "Grok Build leest een AGENTS.md-bestand voor persistente projectcontext — de natuurlijke plek om je designconventies, tokens en reviewchecklists vast te leggen. Het volgt dezelfde open AGENTS.md-conventie die Codex en andere agents gebruiken."}, {"label": "Tools, MCP + subagents", "body": "Het bewerkt bestanden, voert shell-commando's uit en ondersteunt MCP-servers om externe context toe te voegen zoals een live Figma-bestand; voor grotere taken kan het delegeren aan parallelle subagents die tegelijk onderzoeken, bouwen en reviewen."}, {"label": "Meld je aan met je account", "body": "Je authenticeert door je via je browser aan te melden met een SuperGrok- of X Premium+-abonnement; je kunt ook een xAI-API-sleutel meebrengen voor headless en CI-gebruik."}]}, {"kind": "ul", "items": ["Leverancier: xAI", "Credential: xAI SuperGrok OAuth (`grok login`), of een xAI-API-sleutel (BYOK) voor headless gebruik", "Modellen: xAI Grok-modellen (de grok-build-familie op de xAI-API), met beeldinvoer"]}]}, {"id": "why-design", "heading": "Waarom planmodus en beeldbewuste modellen bij design passen", "blocks": [{"kind": "p", "text": "Het designvoordeel van Grok Build komt voort uit twee eigenschappen — maar, zoals bij elke agent, moet smaak nog steeds worden aangeleverd."}, {"kind": "steps", "items": [{"label": "Beeldbewuste redenering", "body": "Omdat Grok-modellen beeldinvoer accepteren, leest de agent referentiescreenshots — en vergelijkt zijn gerenderde output terug met een afbeelding in plaats van te gokken vanuit een prozabeschrijving."}, {"label": "Planmodus voordat wijzigingen landen", "body": "De planmodus stelt een gestructureerde aanpak op die je goedkeurt voordat er bestanden veranderen, zodat de designintentie vooraf wordt beoordeeld in plaats van na de diff te worden ontdekt."}, {"label": "Conventies in AGENTS.md", "body": "Een AGENTS.md (plus de Figma MCP-server) wijst de agent naar je tokens, componenten en echte specs, zodat het tegen een merk werkt in plaats van een standaardlook."}]}, {"kind": "image", "src": "/agents/grok-design/grok-design-taste-triangle.webp", "alt": "Diagram dat laat zien hoe design-systeem, skill en referentieafbeelding samenkomen tot goede designoutput", "caption": "Smaak komt uit drie inputs die jij aanlevert: een design-systeem, een skill en echte referentieafbeeldingen."}, {"kind": "p", "text": "De les is dezelfde die elke agent leert: Grok Build heeft standaard geen smaak. Het levert goed design als je het beperkingen geeft — een design-systeem, een esthetische skill en concrete referenties. Open Design verpakt precies die inputs, en daarom passen de twee samen (meer hieronder)."}]}, {"id": "setup", "heading": "Grok Build voor designwerk instellen, vanaf nul", "blocks": [{"kind": "p", "text": "Hier is het volledige pad van een schone machine naar een Grok Build die UI kan bouwen en verifiëren."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Grok Build (Grok Build) on macOS/Linux\ncurl -fsSL https://x.ai/cli/install.sh | bash\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\ngrok login   # opens your browser; sign in with SuperGrok / X Premium+\n#   or, for headless / CI use, set an xAI API key:\n#   export XAI_API_KEY=xai-...\n\n# 3. Add project context\n#    create an AGENTS.md at the repo root with your design conventions\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add it to your MCP server configuration"}, {"kind": "image", "src": "/agents/grok-design/grok-design-setup-flow.webp", "alt": "Setupstroom in vijf stappen: installeren, authenticeren, AGENTS.md configureren, een skill toevoegen, verifiëren", "caption": "De setupvolgorde: installeren → authenticeren → AGENTS.md configureren → een skill toevoegen → browserverificatie inschakelen."}, {"kind": "steps", "items": [{"label": "Leg je designregels vast", "body": "Zet je tokens, primitives en conventies in AGENTS.md en wijs Grok ernaar, zodat de output bij een merk past in plaats van standaard naar een generieke look te vallen."}, {"label": "Voeg browserverificatie toe", "body": "Koppel een Playwright- of browser-MCP zodat Grok in een echte browser rendert en zijn output over breekpunten controleert in plaats van alleen te bevestigen dat de build slaagt."}]}]}, {"id": "screenshot-workflow", "heading": "De screenshot-naar-UI-workflow", "blocks": [{"kind": "p", "text": "De designlus met de meeste hefboomwerking bij Grok Build is een referentieafbeelding omzetten in werkende, responsive UI en itereren tot het overeenkomt — leunend op de planmodus om het over de aanpak eens te worden en op het beeldbewuste model om de output terug te vergelijken met de referentie."}, {"kind": "ol", "items": ["Begin met de duidelijkste visuele referenties die je hebt — en neem meerdere toestanden mee (desktop en mobiel, hover, leeg, laden), niet alleen één hero-shot.", "Wees specifiek in de prompt; vage prompts leveren generieke UI op, zelfs met een sterk model.", "Houd je design-systeem en conventies in AGENTS.md, en vertel Grok waar de tokens en canonieke primitives zich bevinden.", "Gebruik de planmodus om de aanpak te beoordelen, draai dan een dev-server en laat Grok in een echte browser renderen, met formaatwijziging naar breekpunten om het resultaat te controleren.", "Itereer door Grok zijn implementatie terug te laten vergelijken met de screenshots — niet alleen bevestigen dat het bouwt."]}, {"kind": "p", "text": "Voeg je referentieafbeeldingen toe en geef concrete beperkingen:"}, {"kind": "code", "lang": "bash", "code": "grok\n# in the prompt (attach reference-desktop.png and reference-mobile.png):\n> Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Show me the plan first, then render it in the browser and iterate\n  until it matches the references across breakpoints."}, {"kind": "p", "text": "Houd prompts klein en gericht, commit goede iteraties en draai slechte terug (en vertel Grok wanneer je terugdraait), zodat elke ronde voortbouwt op een schone basis."}]}, {"id": "extend", "heading": "AGENTS.md, MCP en subagents", "blocks": [{"kind": "p", "text": "Drie uitbreidingspunten maken Grok Build praktisch voor langdurig designwerk, en alle drie sluiten ze netjes aan op een open designworkflow."}, {"kind": "steps", "items": [{"label": "AGENTS.md-context", "body": "Projectregels staan in een AGENTS.md in de root van de repo. Het is het duurzame thuis voor je designconventies, gelezen bij elke run — en het is hetzelfde open formaat dat andere agents begrijpen, zodat de regels met je meereizen."}, {"label": "MCP-servers", "body": "Configureer MCP-servers om designcontext en externe tools in te brengen, het meest relevant de Figma MCP-server — de draagbare manier om echte specs in code te voeden, die over agents heen werkt, niet alleen Grok."}, {"label": "Subagents en ingebouwde tools", "body": "Grok Build kan parallelle subagents starten om tegelijk te onderzoeken, te bouwen en te reviewen, en de bestands-, shell- en zoektools laten het referenties verzamelen en de verificatielus draaien zonder de terminal te verlaten."}]}, {"kind": "p", "text": "Dit zijn draagbare, multi-agent-mogelijkheden — precies het soort dingen dat Open Design is gebouwd om te orkestreren, in plaats van per project opnieuw te maken."}]}, {"id": "vs", "heading": "Grok Build vs Codex vs Claude Code vs Cursor vs Gemini CLI voor design", "blocks": [{"kind": "p", "text": "Er is geen enkele winnaar voor designwerk — elke agent heeft een andere sterkte, en ervaren teams stapelen ze. Een eerlijke samenvatting:"}, {"kind": "table", "columns": ["Agent", "Designsterkte", "Het best voor"], "rows": [["Grok Build", "Planmodus-review voordat wijzigingen landen, beeldbewuste Grok-modellen en parallelle subagents; meldt zich aan met je SuperGrok-account", "Beoordeelde, plan-eerst UI-builds met xAI-modellen in de lus"], ["Codex", "Sterke visuele afwerking met een frontend-skill; sandboxed async builds", "Gedelegeerde async builds en draagbare AGENTS.md-regels"], ["Claude Code", "Specifieke designbeslissingen (hex, spacing, type) en codebase-bewuste UX", "Frontend-redenering en refactors met grote context"], ["Cursor", "Visuele bouw-en-zie-lus met live preview en inline-bewerkingen", "Strak itereren-en-meekijken UI-werk binnen een IDE"], ["Gemini CLI", "Sterk multimodaal beeldbegrip en een zeer grote context; open-source met een gratis laag", "Screenshot-zwaar werk en een heel design-systeem in context houden"]]}, {"kind": "p", "text": "Het terugkerende oordeel van de community is dat smaak van mensen komt: ze vallen allemaal standaard terug op een generieke esthetiek zonder skills, referenties en beperkingen. Dat is het echte probleem dat moet worden opgelost — en het heeft de vorm van een designtool, niet van een model."}]}, {"id": "pitfalls", "heading": "Valkuilen, en hoe je de “AI slop”-look vermijdt", "blocks": [{"kind": "p", "text": "De meest voorkomende klacht over AI-gegenereerd design is dat het er generiek uitziet — zachte verlopen, zwevende panelen, overdreven afgeronde hoeken, dramatische schaduwen, een Inter-en-paars-vibe die “schreeuwt dat een AI dit heeft gemaakt.” Andere gemelde problemen zijn kapotte mobiele layouts en instructies die in de UI-tekst lekken. Geen daarvan is uniek voor Grok Build; ze zijn wat er gebeurt wanneer welke agent dan ook draait zonder een zorgvuldig samengestelde designcontext."}, {"kind": "steps", "items": [{"label": "Voeg een esthetische skill toe", "body": "Een zorgvuldig samengestelde designskill dwingt de agent zich vast te leggen op een echte richting in plaats van de standaardlook."}, {"label": "Verifieer in een echte browser", "body": "Render en controleer jezelf over breekpunten zodat layouts niet stilletjes breken op mobiel."}, {"label": "Lever tokens en referenties aan", "body": "Echte design-tokens en referentiescreenshots zijn de grootste enkele hefboom op outputkwaliteit."}, {"label": "Leg regels vast in AGENTS.md", "body": "Zet stijlregels als “geen hero-kaarten, maximaal twee lettertypes, merk-eerst hiërarchie” waar de agent ze elke run leest."}]}, {"kind": "p", "text": "Merk op dat elke mitigatie draait om het geven van een zorgvuldig samengestelde designcontext aan de agent. Die context handmatig onderhouden, per project, is het monnikenwerk dat Open Design wegneemt."}]}, {"id": "open-design", "heading": "Ontwerpen met Grok Build in Open Design", "blocks": [{"kind": "p", "text": "Open Design is de open-source designlaag waar de bovenstaande workflow steeds om vraagt. Het behandelt Grok Build als een first-party adapter en omhult het met een zorgvuldig samengestelde skill- en design-systeembibliotheek, een gestructureerde render-pipeline en een lokale desktop-UI — zodat de designcontext die Grok goed maakt er vanaf de eerste run is, niet elke keer met de hand samengesteld. Open Design is onafhankelijk en Apache-2.0, en het draait op je eigen machine, wat de combinatie een natuurlijke match maakt."}, {"kind": "ol", "items": ["Installeer Open Design en selecteer Grok Build als je agent.", "Authenticeer met je SuperGrok-account of een xAI-API-sleutel (BYOK) — credentials blijven op je machine en worden nooit via ons doorgesluisd.", "Kies een design-systeem en een skill, en genereer dan decks, prototypes en landingspagina's met consistente smaak.", "Elk artefact en elk DESIGN.md-bestand leeft in je eigen repo, niet in een gehoste cloud."]}, {"kind": "p", "text": "Dezelfde Grok Build-agent, dezelfde credentials — plus een echte, draagbare, open-source designworkflow eromheen. Het is local-first en Apache-2.0, dus niets over je werk of je credentials verlaat je machine."}]}], "faqTitle": "Veelgestelde vragen", "faq": [{"name": "Kan Grok Build echt designwerk doen?", "text": "Ja — met een esthetische skill, een design-systeem en echte referentieafbeeldingen in context produceert Grok Build productiekwaliteit, responsive UI, en de beeldbewuste Grok-modellen helpen de output te verifiëren tegen referenties. Zonder die context neigt het standaard naar een generieke look, en dat is het gat dat Open Design opvult."}, {"name": "Hoe authenticeer ik Grok Build?", "text": "Je meldt je via je browser aan met een SuperGrok- of X Premium+-abonnement (`grok login`), dus er is geen API-sleutel om te beheren. Voor headless of CI-gebruik kun je in plaats daarvan een xAI-API-sleutel meebrengen. Open Design sluist je credentials hoe dan ook nooit door."}, {"name": "Wat maakt Grok Build specifiek goed voor design?", "text": "Twee dingen: de planmodus laat je de aanpak beoordelen voordat er een wijziging landt, en de Grok-modellen accepteren beeldinvoer, zodat het referentiescreenshots goed leest. Beide helpen — maar smaak komt nog steeds uit het design-systeem, de skill en de referenties die jij aanlevert."}, {"name": "Grok Build of Claude Code voor frontend-design?", "text": "Beide zijn sterk. Claude Code staat bekend om specifieke, codebase-bewuste designbeslissingen; het voordeel van Grok Build is planmodus-review en beeldbewuste xAI-modellen. Veel teams gebruiken beide — met Open Design kun je van agent wisselen zonder je designworkflow te veranderen."}, {"name": "Hoe verbind ik Grok Build met Figma?", "text": "Voeg de Figma MCP-server toe aan je MCP-configuratie. Grok kan dan echte designcontext ophalen — componenten, variabelen, layoutdata — zodat de gegenereerde code overeenkomt met de bron in plaats van die te benaderen."}, {"name": "Is Open Design verbonden met xAI?", "text": "Nee. Grok Build is een product van xAI; Open Design is een onafhankelijk open-source project dat het ondersteunt als first-party adapter. Grok is een handelsmerk van xAI."}, {"name": "Zijn mijn bestanden en credentials veilig?", "text": "Ja — Open Design is local-first en Apache-2.0. Je bestanden, artefacten en DESIGN.md blijven in je eigen repo, en je xAI-credentials worden rechtstreeks door je agent gebruikt, nooit via Open Design-servers gerouteerd."}], "ctaTitle": "Ontwerp met Grok Build, op de open manier.", "ctaBody": "Breng je eigen SuperGrok-account of xAI-API-sleutel mee, houd elk bestand lokaal en krijg een zorgvuldig samengestelde designbibliotheek rond de agent die je al gebruikt.", "ctaActions": [{"label": "Gebruik Grok Build in Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Bekijk alle ondersteunde agents"},
      },
      'kimi': {
        ...en['kimi']!,
        title: "Kimi CLI voor design — Open Design",
        description: "Hoe mensen Moonshot AI's Kimi CLI gebruiken voor UI- en webdesign — de Kimi K2 agentic modellen, grote context, AGENTS.md en MCP — en hoe Open Design van Kimi CLI een local-first, open-source design agent maakt.",
        breadcrumb: "Kimi CLI",
        label: "Agent · Kimi CLI",
        heading: "Kimi CLI voor design.",
        lead: "Kimi CLI is Moonshot AI's open-source terminal-agent, aangedreven door de Kimi K2-modelreeks. De sterke agentic coding en het grote contextvenster laten het een heel design-systeem vasthouden en itereren tegen referenties — zodra je het conventies en een verificatielus geeft, wordt het een echt designtool. Open Design verbindt het met een open-source designworkflow: je Moonshot-API-sleutel, je bestanden, local-first.",
        rich: {"heroCtaLead": "Open Design maakt van Kimi CLI een local-first, open-source design agent — je Moonshot-API-sleutel, je bestanden, een zorgvuldig samengestelde skill- en design-systeembibliotheek eromheen.", "heroCtaActions": [{"label": "Gebruik Kimi CLI in Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Kimi CLI is Moonshot AI's open-source AI-agent voor de terminal. Twee dingen maken het juist voor design interessant: het wordt aangedreven door de Kimi K2-reeks — een mixture-of-experts-model met een biljoen parameters, zorgvuldig geoptimaliseerd voor agentic coding en tool-gebruik; en dat model draagt een groot contextvenster (256k tokens op recente K2-releases), groot genoeg om een heel design-systeem en een hele codebase in één keer vast te houden. Gekoppeld aan de juiste referenties, conventies en een verificatielus bouwt het echte, responsive UI — en je kunt beginnen met een OAuth-login of je eigen Moonshot-API-sleutel. Dit is een praktische, end-to-end-gids voor het gebruik van Kimi CLI voor UI-, frontend- en design-systeemwerk, en voor het inbedden ervan in een gestructureerde designworkflow met Open Design.", "Het behandelt wat Kimi CLI echt is, waarom de agentic Kimi K2-modellen en de grote context bij design passen, hoe je het vanaf nul instelt, de referentie-naar-UI-lus, hoe AGENTS.md, MCP en subagents het uitbreiden, hoe het zich verhoudt tot Codex, Claude Code, Cursor en Gemini CLI, de valkuilen die AI-output generiek doen lijken, en hoe Open Design het gat dicht als een open, local-first designlaag — een natuurlijke combinatie, aangezien beide open-source zijn en op je eigen machine draaien."], "heroImage": {"src": "/agents/kimi-design/kimi-design-hero.webp", "alt": "Feedbacklus van Kimi CLI-design: een terminal-agent die een referentieafbeelding leest, een browser die de UI rendert en een werkruimte, met een feedbackpijl die terugkoppelt", "caption": "De kernlus: Kimi CLI leest je referenties in de terminal, bouwt en verifieert de UI in een echte browser en itereert eraan — met een heel design-systeem in context."}, "tocLabel": "Op deze pagina", "toc": [{"id": "what-is-kimi", "label": "Wat Kimi CLI eigenlijk is"}, {"id": "why-design", "label": "Waarom agentic K2 + grote context bij design passen"}, {"id": "setup", "label": "Kimi CLI voor design instellen (vanaf nul)"}, {"id": "screenshot-workflow", "label": "De referentie-naar-UI-workflow"}, {"id": "extend", "label": "AGENTS.md, MCP en subagents"}, {"id": "vs", "label": "Kimi CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Valkuilen en de “AI slop”-look"}, {"id": "open-design", "label": "Ontwerpen met Kimi CLI in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-kimi", "heading": "Wat Kimi CLI eigenlijk is", "blocks": [{"kind": "p", "text": "Kimi CLI is een open-source (Apache-2.0) AI-agent die Moonshot AI uitbrengt voor de terminal. Het leest je repository, bewerkt bestanden, voert shell-commando's uit, zoekt bestanden, haalt webpagina's op en kiest zijn volgende stap op basis van de feedback die het krijgt — werk plannend en verifiërend vanuit taken in natuurlijke taal in plaats van alleen regels af te maken. Het is een Python-tool, geïnstalleerd met uv, en het drijft de Kimi K2-modelfamilie achter de schermen aan."}, {"kind": "p", "text": "Voor designwerk springen twee eigenschappen eruit. De Kimi K2-modellen zijn expliciet afgestemd op agentic, langdurige coding en tool-gebruik, zodat de agent een meerstapsbuild kan doorvoeren tot een werkend resultaat. En het contextvenster reikt tot 256k tokens op recente K2-releases, groot genoeg om je hele design-systeem, componentenbibliotheek en referentieset in één keer vast te houden in plaats van ze samen te vatten."}, {"kind": "steps", "items": [{"label": "Contextbestanden", "body": "Kimi CLI leest een AGENTS.md-bestand voor persistente projectcontext — de natuurlijke plek om je designconventies, tokens en reviewchecklists vast te leggen. Voer /init uit om er een op te zetten voor een project dat het niet heeft."}, {"label": "MCP, ACP + subagents", "body": "Het beheert MCP-servers conversationeel met /mcp-config, stelt een sessie beschikbaar via het Agent Client Protocol (kimi acp) aan Zed en JetBrains, en kan ingebouwde coder-, explore- en plan-subagents in geïsoleerde contexten inzetten."}, {"label": "Login of BYOK", "body": "Bij de eerste start laat /login je autoriseren via OAuth (Kimi Code) of je eigen Moonshot-API-sleutel invoeren; het platform van Kimi stelt ook OpenAI- en Anthropic-compatibele eindpunten beschikbaar."}]}, {"kind": "ul", "items": ["Leverancier: Moonshot AI", "Credential: Moonshot-API-sleutel (BYOK), of OAuth-login via Kimi Code", "Licentie: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Waarom agentic K2-modellen en een grote context bij design passen", "blocks": [{"kind": "p", "text": "Het designvoordeel van Kimi CLI komt voort uit twee modeleigenschappen — maar, zoals bij elke agent, moet smaak nog steeds worden aangeleverd."}, {"kind": "steps", "items": [{"label": "Agentic, langdurige coding", "body": "De Kimi K2-modellen zijn geoptimaliseerd voor tool-gebruik en meerstapswerk, zodat de agent een referentie en een briefing kan nemen en de UI daadwerkelijk kan bouwen, draaien en verfijnen in plaats van te stoppen bij een eerste concept."}, {"label": "Een groot contextvenster", "body": "Tot 256k tokens op recente K2-releases betekent dat het hele design-systeem, de tokens en veel referentietoestanden in één keer passen, zodat de agent je echte primitives hergebruikt in plaats van eenmalige stijlen te verzinnen."}, {"label": "Conventies in AGENTS.md", "body": "Een AGENTS.md (plus een MCP-server zoals Figma) wijst de agent naar je tokens, componenten en echte specs, zodat het tegen een merk werkt in plaats van een standaardlook."}]}, {"kind": "image", "src": "/agents/kimi-design/kimi-design-taste-triangle.webp", "alt": "Diagram dat laat zien hoe design-systeem, skill en referentieafbeelding samenkomen tot goede designoutput", "caption": "Smaak komt uit drie inputs die jij aanlevert: een design-systeem, een skill en echte referentieafbeeldingen."}, {"kind": "p", "text": "De les is dezelfde die elke agent leert: Kimi CLI heeft standaard geen smaak. Het levert goed design als je het beperkingen geeft — een design-systeem, een esthetische skill en concrete referenties. Open Design verpakt precies die inputs, en daarom passen de twee samen (meer hieronder)."}]}, {"id": "setup", "heading": "Kimi CLI voor designwerk instellen, vanaf nul", "blocks": [{"kind": "p", "text": "Hier is het volledige pad van een schone machine naar een Kimi CLI die UI kan bouwen en verifiëren."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Kimi CLI (uses uv; Python 3.12–3.14, 3.13 recommended)\ncurl -LsSf https://code.kimi.com/install.sh | bash\n# or, if you already have uv:\nuv tool install --python 3.13 kimi-cli\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\nkimi              # then run /login: OAuth via Kimi Code, or paste a Moonshot API key\n\n# 3. Generate project context\n/init             # scaffolds an AGENTS.md for this project\n\n# 4. Wire an MCP server (optional, e.g. Figma for design handoff)\n/mcp-config       # add, edit, and authenticate MCP servers conversationally"}, {"kind": "image", "src": "/agents/kimi-design/kimi-design-setup-flow.webp", "alt": "Setupstroom in vijf stappen: installeren, authenticeren, AGENTS.md configureren, een skill toevoegen, verifiëren", "caption": "De setupvolgorde: installeren → authenticeren → AGENTS.md configureren → een skill toevoegen → browserverificatie inschakelen."}, {"kind": "steps", "items": [{"label": "Leg je designregels vast", "body": "Zet je tokens, primitives en conventies in AGENTS.md en wijs Kimi ernaar, zodat de output bij een merk past in plaats van standaard naar een generieke look te vallen."}, {"label": "Voeg browserverificatie toe", "body": "Koppel een Playwright- of browser-MCP zodat Kimi in een echte browser rendert en zijn output over breekpunten controleert in plaats van alleen te bevestigen dat de build slaagt."}]}]}, {"id": "screenshot-workflow", "heading": "De referentie-naar-UI-workflow", "blocks": [{"kind": "p", "text": "De designlus met de meeste hefboomwerking bij Kimi CLI is referentiemateriaal omzetten in werkende, responsive UI en itereren tot het overeenkomt — door de agent je referenties te geven en zijn gerenderde output ermee te laten vergelijken in een echte browser."}, {"kind": "ol", "items": ["Begin met de duidelijkste referenties die je hebt — en neem meerdere toestanden mee (desktop en mobiel, hover, leeg, laden), niet alleen één hero-shot.", "Wees specifiek in de prompt; vage prompts leveren generieke UI op, zelfs met een sterke agent.", "Houd je design-systeem en conventies in AGENTS.md, en vertel Kimi waar de tokens en canonieke primitives zich bevinden.", "Draai een dev-server en laat Kimi in een echte browser renderen, met formaatwijziging naar breekpunten om het resultaat te controleren.", "Itereer door Kimi zijn implementatie terug te laten vergelijken met de referenties — niet alleen bevestigen dat het bouwt."]}, {"kind": "p", "text": "Wijs Kimi naar je referenties en de dev-server, en geef dan concrete beperkingen:"}, {"kind": "code", "lang": "bash", "code": "kimi\n# in the prompt:\n> Implement the design in ./references (reference-desktop.png,\n  reference-mobile.png) using React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, render it in the browser, and iterate until it\n  matches the references across breakpoints."}, {"kind": "p", "text": "Houd prompts klein en gericht, commit goede iteraties en draai slechte terug (en vertel Kimi wanneer je terugdraait), zodat elke ronde voortbouwt op een schone basis. Kimi CLI kan ook een korte schermopname of democlip nemen wanneer een flow moeilijk in woorden te beschrijven is."}]}, {"id": "extend", "heading": "AGENTS.md, MCP en subagents", "blocks": [{"kind": "p", "text": "Drie uitbreidingspunten maken Kimi CLI praktisch voor langdurig designwerk, en alle drie sluiten ze netjes aan op een open designworkflow."}, {"kind": "steps", "items": [{"label": "AGENTS.md-context", "body": "Projectregels staan in een AGENTS.md in de root van de repo. Het is het duurzame thuis voor je designconventies, gelezen bij elke run — en het is hetzelfde draagbare formaat dat andere agents gebruiken."}, {"label": "MCP-servers", "body": "Voeg MCP-servers conversationeel toe met /mcp-config — de draagbare manier om designcontext en externe tools in te brengen, het meest relevant de Figma MCP-server, die over agents heen werkt, niet alleen Kimi."}, {"label": "Subagents en de plugin-marketplace", "body": "Zet ingebouwde coder-, explore- en plan-subagents in geïsoleerde contexten in, en installeer skills, MCP-servers en gegevensbronnen uit de marketplace of een willekeurige GitHub-repo om referenties te verzamelen en de verificatielus te draaien."}]}, {"kind": "p", "text": "Dit zijn draagbare, multi-agent-mogelijkheden — precies het soort dingen dat Open Design is gebouwd om te orkestreren, in plaats van per project opnieuw te maken."}]}, {"id": "vs", "heading": "Kimi CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI voor design", "blocks": [{"kind": "p", "text": "Er is geen enkele winnaar voor designwerk — elke agent heeft een andere sterkte, en ervaren teams stapelen ze. Een eerlijke samenvatting:"}, {"kind": "table", "columns": ["Agent", "Designsterkte", "Het best voor"], "rows": [["Kimi CLI", "Agentic Kimi K2-modellen afgestemd op langdurige coding en tool-gebruik, met een grote context; open-source en BYOK", "Meerstapsbuilds en een heel design-systeem voordelig in context houden"], ["Codex", "Sterke visuele afwerking met een frontend-skill; sandboxed async builds", "Gedelegeerde async builds en draagbare AGENTS.md-regels"], ["Claude Code", "Specifieke designbeslissingen (hex, spacing, type) en codebase-bewuste UX", "Frontend-redenering en refactors met grote context"], ["Cursor", "Visuele bouw-en-zie-lus met live preview en inline-bewerkingen", "Strak itereren-en-meekijken UI-werk binnen een IDE"], ["Gemini CLI", "Sterk multimodaal beeldbegrip en een context van 1M tokens; gratis laag", "Screenshot-zwaar werk en zeer grote context"]]}, {"kind": "p", "text": "Het terugkerende oordeel van de community is dat smaak van mensen komt: ze vallen allemaal standaard terug op een generieke esthetiek zonder skills, referenties en beperkingen. Dat is het echte probleem dat moet worden opgelost — en het heeft de vorm van een designtool, niet van een model."}]}, {"id": "pitfalls", "heading": "Valkuilen, en hoe je de “AI slop”-look vermijdt", "blocks": [{"kind": "p", "text": "De meest voorkomende klacht over AI-gegenereerd design is dat het er generiek uitziet — zachte verlopen, zwevende panelen, overdreven afgeronde hoeken, dramatische schaduwen, een Inter-en-paars-vibe die “schreeuwt dat een AI dit heeft gemaakt.” Andere gemelde problemen zijn kapotte mobiele layouts en instructies die in de UI-tekst lekken. Geen daarvan is uniek voor Kimi CLI; ze zijn wat er gebeurt wanneer welke agent dan ook draait zonder een zorgvuldig samengestelde designcontext."}, {"kind": "steps", "items": [{"label": "Voeg een esthetische skill toe", "body": "Een zorgvuldig samengestelde designskill dwingt de agent zich vast te leggen op een echte richting in plaats van de standaardlook."}, {"label": "Verifieer in een echte browser", "body": "Laat Kimi renderen en zichzelf controleren over breekpunten zodat layouts niet stilletjes breken op mobiel."}, {"label": "Lever tokens en referenties aan", "body": "Echte design-tokens en referentiescreenshots zijn de grootste enkele hefboom op outputkwaliteit."}, {"label": "Leg regels vast in AGENTS.md", "body": "Zet stijlregels als “geen hero-kaarten, maximaal twee lettertypes, merk-eerst hiërarchie” waar de agent ze elke run leest."}]}, {"kind": "p", "text": "Merk op dat elke mitigatie draait om het geven van een zorgvuldig samengestelde designcontext aan de agent. Die context handmatig onderhouden, per project, is het monnikenwerk dat Open Design wegneemt."}]}, {"id": "open-design", "heading": "Ontwerpen met Kimi CLI in Open Design", "blocks": [{"kind": "p", "text": "Open Design is de open-source designlaag waar de bovenstaande workflow steeds om vraagt. Het behandelt Kimi CLI als een first-party adapter en omhult het met een zorgvuldig samengestelde skill- en design-systeembibliotheek, een gestructureerde render-pipeline en een lokale desktop-UI — zodat de designcontext die Kimi goed maakt er vanaf de eerste run is, niet elke keer met de hand samengesteld. Beide zijn open-source en local-first, wat de combinatie een natuurlijke match maakt."}, {"kind": "ol", "items": ["Installeer Open Design en selecteer Kimi CLI als je agent.", "Authenticeer met je Moonshot-API-sleutel (BYOK) — credentials blijven op je machine en worden nooit via ons doorgesluisd.", "Kies een design-systeem en een skill, en genereer dan decks, prototypes en landingspagina's met consistente smaak.", "Elk artefact en elk DESIGN.md-bestand leeft in je eigen repo, niet in een gehoste cloud."]}, {"kind": "p", "text": "Dezelfde Kimi CLI-agent, dezelfde sleutel — plus een echte, draagbare, open-source designworkflow eromheen. Het is local-first en Apache-2.0, dus niets over je werk of je credentials verlaat je machine."}]}], "faqTitle": "Veelgestelde vragen", "faq": [{"name": "Kan Kimi CLI echt designwerk doen?", "text": "Ja — met een esthetische skill, een design-systeem en echte referentieafbeeldingen in context produceert Kimi CLI productiekwaliteit, responsive UI, en de agentic Kimi K2-modellen kunnen de output renderen en verifiëren tegen referenties. Zonder die context neigt het standaard naar een generieke look, en dat is het gat dat Open Design opvult."}, {"name": "Moet ik betalen om met Kimi CLI te ontwerpen?", "text": "Je brengt je eigen credentials mee: autoriseer via de Kimi Code OAuth-login of plak een Moonshot-API-sleutel (BYOK), gefactureerd via het platform van Moonshot. Open Design sluist je credentials hoe dan ook nooit door."}, {"name": "Wat maakt Kimi CLI specifiek goed voor design?", "text": "Twee dingen: de Kimi K2-modellen zijn afgestemd op agentic, langdurige coding en tool-gebruik, zodat de agent kan bouwen en verfijnen tot een werkend resultaat, en het contextvenster reikt tot 256k tokens, genoeg om een heel design-systeem en referentieset in één keer vast te houden. Beide helpen — maar smaak komt nog steeds uit het design-systeem, de skill en de referenties die jij aanlevert."}, {"name": "Kimi CLI of Claude Code voor frontend-design?", "text": "Beide zijn sterk. Claude Code staat bekend om specifieke, codebase-bewuste designbeslissingen; het voordeel van Kimi CLI is zijn agentic Kimi K2-modellen en een grote context met BYOK-economie. Veel teams gebruiken beide — met Open Design kun je van agent wisselen zonder je designworkflow te veranderen."}, {"name": "Hoe verbind ik Kimi CLI met Figma?", "text": "Voer /mcp-config uit in Kimi CLI om de Figma MCP-server toe te voegen en te authenticeren. Kimi kan dan echte designcontext ophalen — componenten, variabelen, layoutdata — zodat de gegenereerde code overeenkomt met de bron in plaats van die te benaderen."}, {"name": "Is Open Design verbonden met Moonshot AI?", "text": "Nee. Kimi CLI is een product van Moonshot AI; Open Design is een onafhankelijk open-source project dat het ondersteunt als first-party adapter. Kimi is een handelsmerk van Moonshot AI."}, {"name": "Zijn mijn bestanden en credentials veilig?", "text": "Ja — Open Design is local-first en Apache-2.0. Je bestanden, artefacten en DESIGN.md blijven in je eigen repo, en je Moonshot-credentials worden rechtstreeks door je agent gebruikt, nooit via Open Design-servers gerouteerd."}], "ctaTitle": "Ontwerp met Kimi CLI, op de open manier.", "ctaBody": "Breng je eigen Moonshot-API-sleutel mee, houd elk bestand lokaal en krijg een zorgvuldig samengestelde designbibliotheek rond de agent die je al gebruikt.", "ctaActions": [{"label": "Gebruik Kimi CLI in Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Bekijk alle ondersteunde agents"},
      },
      'deepseek': {
        ...en['deepseek']!,
        title: "DeepSeek TUI voor design — Open Design",
        description: "Hoe mensen een DeepSeek-aangedreven terminal-coding-agent gebruiken voor UI- en webdesign — de sterke coding-modellen, context van 1M tokens, kostenefficiëntie, contextbestanden en MCP — en hoe Open Design van de DeepSeek TUI een local-first, open-source design agent maakt.",
        breadcrumb: "DeepSeek TUI",
        label: "Agent · DeepSeek TUI",
        heading: "DeepSeek TUI voor design.",
        lead: "DeepSeek TUI is een terminal-coding-agent aangedreven door de modellen van DeepSeek. De sterke, kostenefficiënte coding-modellen en de context van 1M tokens kunnen een heel design-systeem en een hele codebase in één keer vasthouden, waardoor het een echt designtool wordt — zodra je het referenties, conventies en een verificatielus geeft. Open Design verbindt het met een open-source designworkflow: je DeepSeek-API-sleutel, je bestanden, local-first.",
        rich: {"heroCtaLead": "Open Design maakt van de DeepSeek TUI een local-first, open-source design agent — je DeepSeek-API-sleutel, je bestanden, een zorgvuldig samengestelde skill- en design-systeembibliotheek eromheen.", "heroCtaActions": [{"label": "Gebruik DeepSeek TUI in Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["DeepSeek TUI is een terminal-gebaseerde AI-coding-agent aangedreven door de modellen van DeepSeek. Twee dingen maken het juist voor design interessant: de coding-modellen zijn sterk en ongewoon kostenefficiënt, zodat je agressief kunt itereren zonder een meter in de gaten te houden; en het contextvenster reikt tot 1M tokens, groot genoeg om een heel design-systeem en een hele codebase in één keer vast te houden in plaats van ze samen te vatten. Gekoppeld aan de juiste referenties, conventies en een verificatielus bouwt het echte, responsive UI. Dit is een praktische, end-to-end-gids voor het gebruik van een DeepSeek-aangedreven terminal-agent voor UI-, frontend- en design-systeemwerk, en voor het inbedden ervan in een gestructureerde designworkflow met Open Design.", "Het behandelt wat de DeepSeek TUI echt is, waarom sterke coding-modellen, een enorme context en lage kosten bij design passen, hoe je het vanaf nul instelt, de referentie-naar-UI-lus, hoe contextbestanden en MCP het uitbreiden, hoe het zich verhoudt tot Codex, Claude Code, Cursor en Gemini CLI, de valkuilen die AI-output generiek doen lijken, en hoe Open Design het gat dicht als een open, local-first designlaag — een natuurlijke combinatie, aangezien beide open zijn en op je eigen machine draaien."], "heroImage": {"src": "/agents/deepseek-design/deepseek-design-hero.webp", "alt": "Feedbacklus van DeepSeek TUI-design: een terminal-agent die referenties en conventies leest, een browser die de UI rendert en een werkruimte, met een feedbackpijl die terugkoppelt", "caption": "De kernlus: DeepSeek TUI leest je referenties en conventies in de terminal, bouwt en verifieert de UI in een echte browser en itereert eraan — met een heel design-systeem in context."}, "tocLabel": "Op deze pagina", "toc": [{"id": "what-is-deepseek", "label": "Wat DeepSeek TUI eigenlijk is"}, {"id": "why-design", "label": "Waarom sterke coding-modellen + enorme context bij design passen"}, {"id": "setup", "label": "DeepSeek TUI voor design instellen (vanaf nul)"}, {"id": "screenshot-workflow", "label": "De referentie-naar-UI-workflow"}, {"id": "extend", "label": "Contextbestanden, MCP en tools"}, {"id": "vs", "label": "DeepSeek TUI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Valkuilen en de “AI slop”-look"}, {"id": "open-design", "label": "Ontwerpen met DeepSeek TUI in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-deepseek", "heading": "Wat DeepSeek TUI eigenlijk is", "blocks": [{"kind": "p", "text": "Een DeepSeek TUI is een toetsenbordgedreven terminal-AI-agent die de modellen van DeepSeek draait. Het leest je repository, bewerkt bestanden, voert shell-commando's uit, beheert git en kan het web doorzoeken — werk plannend en verifiërend vanuit taken in natuurlijke taal in plaats van alleen regels af te maken. DeepSeek zelf is de modelaanbieder: een OpenAI-compatibele API (het stelt ook een Anthropic-formaateindpunt beschikbaar), zodat een breed scala aan community-terminal-agents naar DeepSeek kan worden gewezen door een base-URL en sleutel in te stellen. Verschillende open-source TUI's leveren DeepSeek als eersteklas aanbieder."}, {"kind": "p", "text": "Voor designwerk springen drie eigenschappen eruit. De coding-modellen van DeepSeek zijn sterk, zodat de agent redeneert over layout, structuur en componenthiërarchie vanuit een duidelijke beschrijving. Het contextvenster reikt tot 1M tokens, groot genoeg om je hele design-systeem en componentenbibliotheek in één keer vast te houden. En de prijs per token is zeer laag, met prefix context-caching erbovenop — zodat itereren op een design weinig kost."}, {"kind": "steps", "items": [{"label": "Contextbestanden", "body": "Terminal-agents lezen een projectcontextbestand (een AGENTS.md-achtig bestand, of de eigen conventie van de agent) voor persistente regels — de natuurlijke plek om je designconventies, tokens en reviewchecklists vast te leggen."}, {"label": "Tools + MCP", "body": "De meeste DeepSeek TUI's leveren bestands-, shell-, git- en webtools, en ondersteunen MCP-servers om externe context toe te voegen zoals een live Figma-bestand — de API van DeepSeek ondersteunt tool calling, waar deze agents op leunen."}, {"label": "Breng je eigen sleutel mee", "body": "Je authenticeert met een DeepSeek-API-sleutel van het DeepSeek-platform. Omdat de API OpenAI-compatibel is, is het wijzen van een agent naar DeepSeek meestal twee regels: base-URL en sleutel."}]}, {"kind": "ul", "items": ["Leverancier: DeepSeek (model- en API-aanbieder)", "Credential: DeepSeek-API-sleutel (BYOK) van het DeepSeek-platform", "Modellen: deepseek-v4-flash en deepseek-v4-pro (alleen tekst; geen native beeldinvoer)"]}]}, {"id": "why-design", "heading": "Waarom sterke coding-modellen en een enorme context bij design passen", "blocks": [{"kind": "p", "text": "Het designvoordeel van DeepSeek TUI komt voort uit het model en de economie ervan — maar, zoals bij elke agent, moet smaak nog steeds worden aangeleverd."}, {"kind": "steps", "items": [{"label": "Sterke, kostenefficiënte coding", "body": "De coding-modellen van DeepSeek zijn capabel en goedkoop, zodat de agent goed redeneert over layout en structuur en je vele keren kunt itereren zonder dat kosten de beperking vormen."}, {"label": "Een contextvenster van 1M tokens", "body": "Een grote context betekent dat het hele design-systeem, de tokens en veel referentietoestanden in één keer passen, zodat de agent je echte primitives hergebruikt in plaats van eenmalige stijlen te verzinnen — en context-caching houdt herhaalde prompts goedkoop."}, {"label": "Conventies in een contextbestand", "body": "Een projectcontextbestand (plus de Figma MCP-server) wijst de agent naar je tokens, componenten en echte specs, zodat het tegen een merk werkt in plaats van een standaardlook."}]}, {"kind": "image", "src": "/agents/deepseek-design/deepseek-design-taste-triangle.webp", "alt": "Diagram dat laat zien hoe design-systeem, skill en referentie samenkomen tot goede designoutput", "caption": "Smaak komt uit drie inputs die jij aanlevert: een design-systeem, een skill en echte referenties."}, {"kind": "p", "text": "De les is dezelfde die elke agent leert: DeepSeek TUI heeft standaard geen smaak. Het levert goed design als je het beperkingen geeft — een design-systeem, een esthetische skill en concrete referenties. Open Design verpakt precies die inputs, en daarom passen de twee samen (meer hieronder)."}]}, {"id": "setup", "heading": "DeepSeek TUI voor designwerk instellen, vanaf nul", "blocks": [{"kind": "p", "text": "Hier is het volledige pad van een schone machine naar een DeepSeek TUI die UI kan bouwen en verifiëren. De exacte installatie- en commandonamen variëren per welke terminal-agent je kiest, dus de onderstaande stappen blijven op het niveau dat over allemaal geldt."}, {"kind": "code", "lang": "bash", "code": "# 1. Get a DeepSeek API key from the DeepSeek platform\n#    https://platform.deepseek.com\nexport DEEPSEEK_API_KEY=sk-...\n\n# 2. Install a DeepSeek-capable terminal agent (follow its README),\n#    then point it at DeepSeek. The API is OpenAI-compatible:\n#      base URL: https://api.deepseek.com\n#      model:    deepseek-v4-flash (or deepseek-v4-pro)\n#    (an Anthropic-format endpoint also exists at /anthropic)\n\n# 3. Start it in your project and generate project context\ncd your-project\n#   create/scaffold a project context file with your design rules\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add it to the agent's MCP server configuration"}, {"kind": "image", "src": "/agents/deepseek-design/deepseek-design-setup-flow.webp", "alt": "Setupstroom in vijf stappen: sleutel ophalen, agent installeren, contextbestand configureren, een skill toevoegen, verifiëren", "caption": "De setupvolgorde: een sleutel ophalen → de agent naar DeepSeek wijzen → een contextbestand configureren → een skill toevoegen → browserverificatie inschakelen."}, {"kind": "steps", "items": [{"label": "Leg je designregels vast", "body": "Zet je tokens, primitives en conventies in het contextbestand van de agent en wijs het ernaar, zodat de output bij een merk past in plaats van standaard naar een generieke look te vallen."}, {"label": "Voeg browserverificatie toe", "body": "Koppel een Playwright- of browser-MCP zodat de agent in een echte browser rendert en zijn output over breekpunten controleert in plaats van alleen te bevestigen dat de build slaagt."}]}]}, {"id": "screenshot-workflow", "heading": "De referentie-naar-UI-workflow", "blocks": [{"kind": "p", "text": "De modellen van DeepSeek zijn alleen-tekst — ze lezen geen afbeeldingen native — dus de designlus met de meeste hefboomwerking is duidelijke referenties en beschreven layouts omzetten in werkende, responsive UI, en het resultaat vervolgens verifiëren in een echte browser in plaats van het model te vragen naar een screenshot te kijken."}, {"kind": "ol", "items": ["Begin met de duidelijkste referenties die je hebt — en beschrijf meerdere toestanden (desktop en mobiel, hover, leeg, laden), niet alleen één hero-shot.", "Wees specifiek in de prompt; vage prompts leveren generieke UI op, zelfs met een sterk model. Specificeer spacing, hiërarchie en de componenten om te hergebruiken.", "Houd je design-systeem en conventies in het contextbestand, en vertel de agent waar de tokens en canonieke primitives zich bevinden.", "Draai een dev-server en laat de agent in een echte browser renderen, met formaatwijziging naar breekpunten om het resultaat te controleren — hier vindt de verificatie plaats, aangezien het model de afbeelding zelf niet kan zien.", "Itereer door de agent de gerenderde DOM en berekende stijlen terug te laten vergelijken met je beschreven spec — niet alleen bevestigen dat het bouwt."]}, {"kind": "p", "text": "Beschrijf het doel nauwkeurig en geef concrete beperkingen:"}, {"kind": "code", "lang": "bash", "code": "# in the agent's prompt:\n> Implement this design in React + Vite + Tailwind + TypeScript.\n  Layout: two-column dashboard, 240px sidebar, 24px gutters,\n  card grid at 3/2/1 columns for desktop/tablet/mobile.\n  Reuse my existing design-system components and tokens from the\n  context file. Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, render it in the browser, and iterate against the\n  spec across breakpoints until it matches."}, {"kind": "p", "text": "Houd prompts klein en gericht, commit goede iteraties en draai slechte terug (en vertel de agent wanneer je terugdraait), zodat elke ronde voortbouwt op een schone basis."}]}, {"id": "extend", "heading": "Contextbestanden, MCP en tools", "blocks": [{"kind": "p", "text": "Drie uitbreidingspunten maken een DeepSeek TUI praktisch voor langdurig designwerk, en alle drie sluiten ze netjes aan op een open designworkflow."}, {"kind": "steps", "items": [{"label": "Projectcontextbestand", "body": "Projectregels staan in een contextbestand in de root van de repo (met globale en teamlagen). Het is het duurzame thuis voor je designconventies, gelezen bij elke run."}, {"label": "MCP-servers", "body": "Configureer MCP-servers in de agent — de draagbare manier om designcontext en externe tools in te brengen, het meest relevant de Figma MCP-server, die over agents heen werkt, niet alleen één. De API van DeepSeek ondersteunt de tool calling waar deze servers op leunen."}, {"label": "Ingebouwde tools", "body": "DeepSeek TUI's leveren bestands-, shell-, git- en webtools zodat de agent referenties kan verzamelen en de verificatielus kan draaien zonder de terminal te verlaten."}]}, {"kind": "p", "text": "Dit zijn draagbare, multi-agent-mogelijkheden — precies het soort dingen dat Open Design is gebouwd om te orkestreren, in plaats van per project opnieuw te maken."}]}, {"id": "vs", "heading": "DeepSeek TUI vs Codex vs Claude Code vs Cursor vs Gemini CLI voor design", "blocks": [{"kind": "p", "text": "Er is geen enkele winnaar voor designwerk — elke agent heeft een andere sterkte, en ervaren teams stapelen ze. Een eerlijke samenvatting:"}, {"kind": "table", "columns": ["Agent", "Designsterkte", "Het best voor"], "rows": [["DeepSeek TUI", "Sterke, zeer kostenefficiënte coding-modellen met open gewichten en een context van 1M tokens; alleen-tekst (geen native vision)", "Iteratie in hoog volume binnen budget en een heel design-systeem in context houden"], ["Codex", "Sterke visuele afwerking met een frontend-skill; sandboxed async builds", "Gedelegeerde async builds en draagbare AGENTS.md-regels"], ["Claude Code", "Specifieke designbeslissingen (hex, spacing, type) en codebase-bewuste UX", "Frontend-redenering en refactors met grote context"], ["Cursor", "Visuele bouw-en-zie-lus met live preview en inline-bewerkingen", "Strak itereren-en-meekijken UI-werk binnen een IDE"], ["Gemini CLI", "Native multimodaal beeldbegrip en een context van 1M tokens; open-source met een gratis laag", "Screenshot-zwaar werk waar de agent referenties rechtstreeks leest"]]}, {"kind": "p", "text": "Het terugkerende oordeel van de community is dat smaak van mensen komt: ze vallen allemaal standaard terug op een generieke esthetiek zonder skills, referenties en beperkingen. Dat is het echte probleem dat moet worden opgelost — en het heeft de vorm van een designtool, niet van een model."}]}, {"id": "pitfalls", "heading": "Valkuilen, en hoe je de “AI slop”-look vermijdt", "blocks": [{"kind": "p", "text": "De meest voorkomende klacht over AI-gegenereerd design is dat het er generiek uitziet — zachte verlopen, zwevende panelen, overdreven afgeronde hoeken, dramatische schaduwen, een Inter-en-paars-vibe die “schreeuwt dat een AI dit heeft gemaakt.” Andere gemelde problemen zijn kapotte mobiele layouts en instructies die in de UI-tekst lekken. Geen daarvan is uniek voor DeepSeek TUI; ze zijn wat er gebeurt wanneer welke agent dan ook draait zonder een zorgvuldig samengestelde designcontext. Omdat DeepSeek alleen-tekst is, is het bijzonder belangrijk om in een echte browser te verifiëren in plaats van erop te vertrouwen dat het model naar het resultaat “kijkt.”"}, {"kind": "steps", "items": [{"label": "Voeg een esthetische skill toe", "body": "Een zorgvuldig samengestelde designskill dwingt de agent zich vast te leggen op een echte richting in plaats van de standaardlook."}, {"label": "Verifieer in een echte browser", "body": "Render en controleer jezelf over breekpunten met een browser-tool — hier essentieel, aangezien het model zelf geen screenshot kan lezen — zodat layouts niet stilletjes breken op mobiel."}, {"label": "Lever tokens en referenties aan", "body": "Echte design-tokens en concrete, beschreven referenties zijn de grootste enkele hefboom op outputkwaliteit."}, {"label": "Leg regels vast in het contextbestand", "body": "Zet stijlregels als “geen hero-kaarten, maximaal twee lettertypes, merk-eerst hiërarchie” waar de agent ze elke run leest."}]}, {"kind": "p", "text": "Merk op dat elke mitigatie draait om het geven van een zorgvuldig samengestelde designcontext aan de agent. Die context handmatig onderhouden, per project, is het monnikenwerk dat Open Design wegneemt."}]}, {"id": "open-design", "heading": "Ontwerpen met DeepSeek TUI in Open Design", "blocks": [{"kind": "p", "text": "Open Design is de open-source designlaag waar de bovenstaande workflow steeds om vraagt. Het behandelt de DeepSeek-agent als een first-party adapter en omhult het met een zorgvuldig samengestelde skill- en design-systeembibliotheek, een gestructureerde render-pipeline en een lokale desktop-UI — zodat de designcontext die DeepSeek goed maakt er vanaf de eerste run is, niet elke keer met de hand samengesteld. Beide zijn open en local-first, wat de combinatie een natuurlijke match maakt."}, {"kind": "ol", "items": ["Installeer Open Design en selecteer de DeepSeek TUI als je agent.", "Authenticeer met je eigen DeepSeek-API-sleutel (BYOK) — credentials blijven op je machine en worden nooit via ons doorgesluisd.", "Kies een design-systeem en een skill, en genereer dan decks, prototypes en landingspagina's met consistente smaak.", "Elk artefact en elk DESIGN.md-bestand leeft in je eigen repo, niet in een gehoste cloud."]}, {"kind": "p", "text": "Dezelfde DeepSeek-agent, dezelfde sleutel — plus een echte, draagbare, open-source designworkflow eromheen. Het is local-first en Apache-2.0, dus niets over je werk of je credentials verlaat je machine."}]}], "faqTitle": "Veelgestelde vragen", "faq": [{"name": "Kan DeepSeek TUI echt designwerk doen?", "text": "Ja — met een esthetische skill, een design-systeem en concrete referenties in context produceert een DeepSeek-aangedreven terminal-agent productiekwaliteit, responsive UI, en je verifieert de output in een echte browser. De modellen van DeepSeek zijn alleen-tekst, dus de verificatielus vervangt native beeldlezen. Zonder die context neigt het standaard naar een generieke look, en dat is het gat dat Open Design opvult."}, {"name": "Hoeveel kost het om met DeepSeek TUI te ontwerpen?", "text": "Weinig — de API van DeepSeek behoort tot de goedkoopste per token, en prefix context-caching verlaagt de kosten van herhaalde prompts verder, zodat je agressief kunt itereren. Je brengt je eigen DeepSeek-API-sleutel mee (BYOK); Open Design sluist je credentials nooit door."}, {"name": "Wat maakt DeepSeek specifiek goed voor design?", "text": "Sterke, kostenefficiënte coding-modellen, open gewichten en een context van 1M tokens die een heel design-systeem en referentieset in één keer vasthoudt. DeepSeek is alleen-tekst — het leest geen afbeeldingen native — dus smaak komt nog steeds uit het design-systeem, de skill en de beschreven referenties die jij aanlevert, geverifieerd in een browser."}, {"name": "DeepSeek TUI of Claude Code voor frontend-design?", "text": "Beide zijn sterk. Claude Code staat bekend om specifieke, codebase-bewuste designbeslissingen; het voordeel van DeepSeek TUI is open gewichten, zeer lage kosten en een enorme context voor iteratie in hoog volume. Veel teams gebruiken beide — met Open Design kun je van agent wisselen zonder je designworkflow te veranderen."}, {"name": "Hoe verbind ik DeepSeek TUI met Figma?", "text": "Voeg de Figma MCP-server toe in de MCP-configuratie van je terminal-agent. De agent kan dan echte designcontext ophalen — componenten, variabelen, layoutdata — zodat de gegenereerde code overeenkomt met de bron in plaats van die te benaderen. De API van DeepSeek ondersteunt de tool calling waar MCP op leunt."}, {"name": "Is Open Design verbonden met DeepSeek?", "text": "Nee. DeepSeek is de model- en API-aanbieder; Open Design is een onafhankelijk open-source project dat DeepSeek-aangedreven terminal-agents ondersteunt als first-party adapter. DeepSeek is een handelsmerk van DeepSeek."}, {"name": "Zijn mijn bestanden en credentials veilig?", "text": "Ja — Open Design is local-first en Apache-2.0. Je bestanden, artefacten en DESIGN.md blijven in je eigen repo, en je DeepSeek-API-sleutel wordt rechtstreeks door je agent gebruikt, nooit via Open Design-servers gerouteerd."}], "ctaTitle": "Ontwerp met DeepSeek TUI, op de open manier.", "ctaBody": "Breng je eigen DeepSeek-API-sleutel mee, houd elk bestand lokaal en krijg een zorgvuldig samengestelde designbibliotheek rond de agent die je al gebruikt.", "ctaActions": [{"label": "Gebruik DeepSeek TUI in Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Bekijk alle ondersteunde agents"},
      },
      'trae-cli': {
        ...en['trae-cli']!,
        title: "Trae CLI voor design — Open Design",
        description: "Hoe mensen ByteDance's Trae CLI (trae-agent) gebruiken voor UI- en webdesign — de open-source, modelonafhankelijke CLI-agent, breng-je-eigen-LLM-provider en config-gestuurde workflow — en hoe Open Design Trae CLI verandert in een local-first, open-source design-agent via ACP.",
        breadcrumb: "Trae CLI",
        label: "Agent · Trae CLI",
        heading: "Trae CLI voor design.",
        lead: "Trae CLI is de open-source terminal-agent van ByteDance (trae-agent). Hij is modelonafhankelijk — je wijst hem op de LLM-provider die je vertrouwt — en hij leest je repo, bewerkt bestanden en voert opdrachten uit op basis van taken in natuurlijke taal, waardoor hij een echt designtool wordt zodra je hem referenties, conventies en een verificatielus geeft. Open Design verbindt hem met een open-source design-workflow via ACP: je eigen providersleutel, je bestanden, local-first.",
        rich: {"heroCtaLead": "Open Design verandert Trae CLI in een local-first, open-source design-agent — je eigen LLM-providersleutel, je bestanden, een samengestelde bibliotheek van skills en designsystemen eromheen, aangestuurd via ACP.", "heroCtaActions": [{"label": "Gebruik Trae CLI in Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Trae CLI is ByteDance's open-source AI-agent voor de terminal, uitgebracht als het trae-agent-project. Twee dingen maken hem specifiek interessant voor design: hij is modelonafhankelijk, zodat je elke LLM-provider die je vertrouwt kunt meebrengen in plaats van vast te zitten aan één leverancier; en hij is een transparante, MIT-gelicentieerde agent die je codebase leest, bestanden bewerkt en shell-opdrachten uitvoert op basis van taken in natuurlijke taal. Gecombineerd met de juiste referenties, conventies en een verificatielus bouwt hij echte, responsieve UI — en hij is gratis en open om mee te starten, je hoeft alleen een providersleutel aan te leveren. Dit is een praktische, end-to-end gids voor het gebruik van Trae CLI voor UI-, frontend- en designsysteemwerk, en voor het inbedden ervan in een gestructureerde design-workflow met Open Design.", "Het behandelt wat Trae CLI eigenlijk is, waarom een open, modelonafhankelijke agent bij design past, hoe je hem vanaf nul opzet, de screenshot-naar-UI-lus, hoe zijn configuratiebestand en tools hem uitbreiden, hoe hij zich verhoudt tot Codex, Claude Code, Cursor en Gemini CLI, de valkuilen die AI-output generiek doen lijken, en hoe Open Design de kloof dicht als een open, local-first designlaag — een natuurlijke combinatie, want beide zijn open-source en draaien op je eigen machine, waarbij Open Design Trae CLI aanstuurt via het Agent Client Protocol (ACP)."], "heroImage": {"src": "/agents/trae-cli-design/trae-cli-design-hero.webp", "alt": "Trae CLI design-feedbacklus: een terminal-agent die een referentieafbeelding leest, een browser die de UI rendert, en een werkruimte, met een feedbackpijl die terugloopt", "caption": "De kernlus: Trae CLI leest je referenties en conventies in de terminal, bouwt en verifieert de UI in een echte browser, en itereert daartegen."}, "tocLabel": "Op deze pagina", "toc": [{"id": "what-is-trae-cli", "label": "Wat Trae CLI eigenlijk is"}, {"id": "why-design", "label": "Waarom een open, modelonafhankelijke agent bij design past"}, {"id": "setup", "label": "Trae CLI opzetten voor design (vanaf nul)"}, {"id": "screenshot-workflow", "label": "De screenshot-naar-UI-workflow"}, {"id": "extend", "label": "Config, tools en providers"}, {"id": "vs", "label": "Trae CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Valkuilen en de “AI-slop”-look"}, {"id": "open-design", "label": "Ontwerpen met Trae CLI in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-trae-cli", "heading": "Wat Trae CLI eigenlijk is", "blocks": [{"kind": "p", "text": "Trae CLI is de command-line-agent uit ByteDance's open-source trae-agent-project. Hij leest je repository, bekijkt, maakt en bewerkt bestanden, en voert shell-opdrachten uit in een persistente omgeving — hij plant en verifieert werk op basis van taken in natuurlijke taal in plaats van alleen regels aan te vullen. Hij is MIT-gelicentieerd en gebouwd rond een transparante, modulaire architectuur, zodat hij eenvoudig te inspecteren en uit te breiden is. Hij staat los van de afzonderlijke Trae IDE, ByteDance's op VS Code gebaseerde AI-editor, hoewel beide van dezelfde leverancier komen."}, {"kind": "p", "text": "Voor designwerk springen twee eigenschappen eruit. Hij is modelonafhankelijk — jij kiest de LLM-provider, dus je zit nooit vast aan de sterke punten of beperkingen van één model. En hij is volledig open en config-gestuurd, zodat zijn gedrag, tools en provider naast je project in versiebeheer kunnen worden vastgelegd in plaats van verborgen achter een gehoste dienst."}, {"kind": "steps", "items": [{"label": "Run- en interactieve modi", "body": "Trae CLI voert één taak uit met `trae-cli run \"...\"` of houdt een doorlopende sessie aan met `trae-cli interactive` — de natuurlijke plek om een UI te itereren tegen je designconventies."}, {"label": "Ingebouwde tools", "body": "Hij wordt geleverd met tools voor bestandsbewerking, bash/shell-uitvoering en gestructureerd redeneren, zodat hij kan bouwen, een dev-server draaien en runtime-fouten inspecteren zonder de terminal te verlaten."}, {"label": "Breng je eigen provider mee", "body": "Je levert een API-sleutel aan voor de provider die je vertrouwt — OpenAI, Anthropic, Google, OpenRouter, Doubao, Azure of een lokaal Ollama-model — via omgevingsvariabelen of een configuratiebestand."}]}, {"kind": "ul", "items": ["Leverancier: ByteDance (open-source trae-agent-project)", "Credential: een LLM-provider-API-sleutel (BYOK) — bijv. OpenAI, Anthropic, Google, OpenRouter, Doubao, Azure of een lokaal Ollama-model", "Licentie: MIT, open source"]}]}, {"id": "why-design", "heading": "Waarom een open, modelonafhankelijke agent bij design past", "blocks": [{"kind": "p", "text": "Trae CLI's designvoordeel komt voort uit het feit dat hij open en provider-flexibel is — maar, zoals bij elke agent, smaak moet nog steeds worden aangeleverd."}, {"kind": "steps", "items": [{"label": "Modelonafhankelijk van opzet", "body": "Omdat jij de provider kiest, kun je designwerk routeren naar welk model vandaag het beste redeneert over lay-out en frontend-code, en het later wisselen zonder je workflow te veranderen."}, {"label": "Open en config-gestuurd", "body": "De agent, zijn tools en zijn provider worden vastgelegd in een configuratiebestand dat je kunt committen, zodat een team op elke machine hetzelfde agentgedrag krijgt in plaats van per ontwikkelaar af te drijven."}, {"label": "Conventies in je repo", "body": "Wijs de agent op je tokens, componenten en echte specificaties — bewaard in je project — zodat hij werkt tegen een merk in plaats van terug te vallen op een generieke look."}]}, {"kind": "image", "src": "/agents/trae-cli-design/trae-cli-design-taste-triangle.webp", "alt": "Diagram dat toont hoe designsysteem, skill en referentieafbeelding samenkomen tot goede design-output", "caption": "Smaak komt voort uit drie inputs die jij aanlevert: een designsysteem, een skill en echte referentieafbeeldingen."}, {"kind": "p", "text": "De les is dezelfde die elke agent leert: Trae CLI heeft standaard geen smaak. Hij produceert goed design wanneer je hem beperkingen geeft — een designsysteem, een esthetische skill en concrete referenties. Open Design verpakt precies die inputs en voedt ze aan Trae CLI via ACP, en daarom passen de twee bij elkaar (meer hieronder)."}]}, {"id": "setup", "heading": "Trae CLI opzetten voor designwerk, vanaf nul", "blocks": [{"kind": "p", "text": "Hier is het volledige pad van een schone machine naar een Trae CLI die UI kan bouwen en verifiëren. Trae CLI wordt vanuit de broncode geïnstalleerd met uv, en vervolgens geconfigureerd met de LLM-provider die je wilt gebruiken."}, {"kind": "code", "lang": "bash", "code": "# 1. Get Trae CLI (trae-agent) from source — needs uv\ngit clone https://github.com/bytedance/trae-agent.git\ncd trae-agent\nuv sync --all-extras\nsource .venv/bin/activate\n\n# 2. Authenticate by pointing it at your LLM provider key\n#    set it in the environment (or a trae_config.yaml file)\nexport OPENAI_API_KEY=...        # or ANTHROPIC_API_KEY, GOOGLE_API_KEY, etc.\n\n# 3. Run a task in your project\ntrae-cli run \"Create a hello world page\"\n#    or hold a session:\ntrae-cli interactive\n\n# 4. Check the resolved configuration (keys are masked)\ntrae-cli show-config"}, {"kind": "image", "src": "/agents/trae-cli-design/trae-cli-design-setup-flow.webp", "alt": "Stappenplan in vijf stappen: installeren, authenticeren, conventies configureren, een skill toevoegen, verifiëren", "caption": "De opzetvolgorde: installeren → authenticeren met een providersleutel → je designconventies configureren → een skill toevoegen → browserverificatie inschakelen."}, {"kind": "steps", "items": [{"label": "Codeer je designregels", "body": "Bewaar je tokens, primitieven en conventies in de repo en wijs Trae CLI erop, zodat output overeenkomt met een merk in plaats van terug te vallen op een generieke look."}, {"label": "Voeg browserverificatie toe", "body": "Laat Trae CLI een dev-server draaien en renderen in een echte browser zodat hij zijn output controleert over breakpoints heen in plaats van alleen te bevestigen dat de build slaagt."}]}]}, {"id": "screenshot-workflow", "heading": "De screenshot-naar-UI-workflow", "blocks": [{"kind": "p", "text": "De designlus met de meeste hefboomwerking met Trae CLI is het omzetten van een referentieafbeelding in werkende, responsieve UI en daarop itereren tot het overeenkomt. Omdat Trae CLI modelonafhankelijk is, wijs hem op een provider waarvan het model je referenties goed verwerkt, en leun op een echte browser om het resultaat te controleren."}, {"kind": "ol", "items": ["Begin met de duidelijkste visuele referenties die je hebt — en beschrijf meerdere staten (desktop en mobiel, hover, leeg, laden), niet slechts één hero-shot.", "Wees specifiek in de prompt; vage prompts leveren generieke UI op, zelfs met een sterk model.", "Bewaar je designsysteem en conventies in de repo, en vertel Trae CLI waar de tokens en canonieke primitieven leven.", "Draai een dev-server en laat Trae CLI renderen in een echte browser, met formaataanpassing naar breakpoints om het resultaat te controleren.", "Itereer door Trae CLI zijn implementatie te laten vergelijken met de referenties — niet alleen bevestigen dat het bouwt."]}, {"kind": "p", "text": "Voer een interactieve sessie en geef concrete beperkingen in plaats van een verzoek van één regel:"}, {"kind": "code", "lang": "bash", "code": "trae-cli interactive\n# in the session:\n> Implement the attached reference design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, render it in the browser, and iterate until it\n  matches the references across breakpoints."}, {"kind": "p", "text": "Houd prompts klein en gericht, commit goede iteraties en draai slechte terug (en vertel Trae CLI wanneer je terugdraait), zodat elke ronde voortbouwt op een schone basis."}]}, {"id": "extend", "heading": "Config, tools en providers", "blocks": [{"kind": "p", "text": "Drie uitbreidingspunten maken Trae CLI praktisch voor langdurig designwerk, en alle drie passen netjes op een open design-workflow."}, {"kind": "steps", "items": [{"label": "Configuratiebestand", "body": "Trae CLI leest een trae_config.yaml die je provider, model en instellingen vastlegt — de duurzame, versiebeheerbare thuisbasis voor hoe de agent op een project draait."}, {"label": "Providerkeuze", "body": "Omdat hij veel providers ondersteunt (OpenAI, Anthropic, Google, OpenRouter, Doubao, Azure, Ollama), routeer je designwerk naar het model dat je vertrouwt en wissel je het zonder je workflow opnieuw te bedraden."}, {"label": "Ingebouwde tools", "body": "Zijn tools voor bestandsbewerking, shell en gestructureerd redeneren laten hem context verzamelen, bouwen, een dev-server draaien en de verificatielus uitvoeren zonder de terminal te verlaten."}]}, {"kind": "p", "text": "Dit zijn overdraagbare mogelijkheden op agentniveau — precies het soort dingen die Open Design is gebouwd om te orkestreren via ACP, in plaats van per project opnieuw te creëren."}]}, {"id": "vs", "heading": "Trae CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI voor design", "blocks": [{"kind": "p", "text": "Er is geen enkele winnaar voor designwerk — elke agent heeft een ander sterk punt, en ervaren teams stapelen ze. Een eerlijke samenvatting:"}, {"kind": "table", "columns": ["Agent", "Designsterkte", "Best voor"], "rows": [["Trae CLI", "Open-source (MIT) en modelonafhankelijk; breng je eigen providersleutel mee, config-gestuurd en transparant", "Teams die een gratis, inspecteerbare agent willen en de vrijheid om LLM-providers te kiezen of te wisselen"], ["Codex", "Sterke visuele afwerking met een frontend-skill; gesandboxte async builds", "Gedelegeerde async builds en overdraagbare AGENTS.md-regels"], ["Claude Code", "Specifieke designbeslissingen (hex, spacing, type) en codebase-bewuste UX", "Frontend-redenering en refactors met grote context"], ["Cursor", "Visuele bouw-en-zie-lus met live preview en inline bewerkingen", "Strak itereren-en-meekijken UI-werk binnen een IDE"], ["Gemini CLI", "Sterk multimodaal beeldbegrip en een context van 1M tokens; open-source met een gratis laag", "Screenshot-intensief werk en een heel designsysteem in context houden"]]}, {"kind": "p", "text": "Het terugkerende oordeel van de community is dat smaak van mensen komt: ze vallen allemaal terug op een generieke esthetiek zonder skills, referenties en beperkingen. Dat is het echte probleem om op te lossen — en het heeft de vorm van een designtool, niet van een model."}]}, {"id": "pitfalls", "heading": "Valkuilen, en hoe je de “AI-slop”-look vermijdt", "blocks": [{"kind": "p", "text": "De meest voorkomende klacht over door AI gegenereerd design is dat het er generiek uitziet — zachte gradiënten, zwevende panelen, overdreven afgeronde hoeken, dramatische schaduwen, een Inter-en-paars-sfeer die “schreeuwt dat een AI dit heeft gemaakt.” Andere gemelde problemen zijn kapotte mobiele lay-outs en instructies die in de UI-tekst lekken. Geen van deze is uniek voor Trae CLI; ze zijn wat er gebeurt wanneer welke agent dan ook draait zonder een samengestelde designcontext."}, {"kind": "steps", "items": [{"label": "Voeg een esthetische skill toe", "body": "Een samengestelde design-skill dwingt de agent om zich vast te leggen op een echte richting in plaats van de standaard look."}, {"label": "Verifieer in een echte browser", "body": "Laat Trae CLI renderen en zichzelf controleren over breakpoints heen zodat lay-outs niet stilletjes breken op mobiel."}, {"label": "Lever tokens en referenties aan", "body": "Echte design-tokens en referentie-screenshots zijn de grootste enkele hefboom op outputkwaliteit."}, {"label": "Codeer regels in je repo", "body": "Plaats stijlregels als “geen hero-cards, maximaal twee lettertypes, merk-eerst-hiërarchie” waar de agent ze elke ronde leest."}]}, {"kind": "p", "text": "Merk op dat elke mitigatie gaat over het geven van een samengestelde designcontext aan de agent. Die context handmatig onderhouden, per project, is het zware werk dat Open Design wegneemt."}]}, {"id": "open-design", "heading": "Ontwerpen met Trae CLI in Open Design", "blocks": [{"kind": "p", "text": "Open Design is de open-source designlaag waar de bovenstaande workflow steeds om vraagt. Het behandelt Trae CLI als een first-party adapter — en stuurt hem aan via het Agent Client Protocol (ACP) met zijn trae-cli-binary — en wikkelt hem in een samengestelde bibliotheek van skills en designsystemen, een gestructureerde render-pijplijn en een lokale desktop-UI, zodat de designcontext die Trae CLI goed maakt er vanaf de eerste ronde is, niet telkens handmatig samengesteld. Beide zijn open-source en local-first, wat de combinatie een natuurlijke match maakt."}, {"kind": "ol", "items": ["Installeer Open Design en selecteer Trae CLI als je agent.", "Authenticeer met je eigen LLM-providersleutel (BYOK) — credentials blijven op je machine en worden nooit via ons doorgesluisd.", "Kies een designsysteem en een skill, en genereer dan decks, prototypes en landingspagina's met consistente smaak.", "Elk artefact en DESIGN.md-bestand leeft in je eigen repo, niet in een gehoste cloud."]}, {"kind": "p", "text": "Dezelfde Trae CLI-agent, dezelfde providersleutel — plus een echte, overdraagbare, open-source design-workflow eromheen. Het is local-first en open-source, dus niets van je werk of je credentials verlaat je machine."}]}], "faqTitle": "Veelgestelde vragen", "faq": [{"name": "Kan Trae CLI echt designwerk doen?", "text": "Ja — met een esthetische skill, een designsysteem en echte referentiecontext produceert Trae CLI responsieve UI van productiekwaliteit, en omdat hij modelonafhankelijk is kun je het werk routeren naar de provider die het beste redeneert over je frontend. Zonder die context valt hij doorgaans terug op een generieke look, en dat is de kloof die Open Design dicht."}, {"name": "Moet ik betalen om met Trae CLI te ontwerpen?", "text": "Trae CLI zelf is gratis en open-source (MIT). Je brengt je eigen LLM-providersleutel mee, dus je enige kosten zijn wat die provider in rekening brengt — of niets als je een lokaal model draait via Ollama. Open Design sluist je credentials sowieso nooit door."}, {"name": "Wat maakt Trae CLI specifiek goed voor design?", "text": "Twee dingen: hij is modelonafhankelijk, dus je kiest de LLM-provider die het beste geschikt is voor frontend-werk, en hij is volledig open en config-gestuurd, zodat zijn gedrag transparant en reproduceerbaar is binnen een team. Maar smaak komt nog steeds van het designsysteem, de skill en de referenties die jij aanlevert."}, {"name": "Trae CLI of Claude Code voor frontend-design?", "text": "Beide zijn capabel. Claude Code staat bekend om specifieke, codebase-bewuste designbeslissingen; het voordeel van Trae CLI is dat hij open-source en provider-flexibel is, zodat je nooit vastzit aan één model. Veel teams gebruiken beide — met Open Design kun je van agent wisselen zonder je design-workflow te veranderen."}, {"name": "Wat heeft Open Design nodig om Trae CLI te draaien?", "text": "Open Design stuurt de trae-cli-binary van Trae CLI aan via het Agent Client Protocol (ACP) en gebruikt je geconfigureerde LLM-providersleutel. Je selecteert Trae CLI als je agent, wijst hem op een provider, en Open Design levert de samengestelde designcontext eromheen."}, {"name": "Is Open Design verbonden met ByteDance of Trae?", "text": "Nee. Trae CLI (trae-agent) is een product van ByteDance; Open Design is een onafhankelijk open-source project dat het ondersteunt als first-party adapter. Trae is een handelsmerk van ByteDance."}, {"name": "Zijn mijn bestanden en credentials veilig?", "text": "Ja — Open Design is local-first en open-source. Je bestanden, artefacten en DESIGN.md blijven in je eigen repo, en je LLM-provider-credentials worden rechtstreeks door je agent gebruikt, nooit gerouteerd via Open Design-servers."}], "ctaTitle": "Ontwerp met Trae CLI, op de open manier.", "ctaBody": "Breng je eigen LLM-providersleutel mee, houd elk bestand lokaal, en krijg een samengestelde designbibliotheek rond de agent die je al gebruikt.", "ctaActions": [{"label": "Gebruik Trae CLI in Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Bekijk alle ondersteunde agents"},
      },
      'aider': {
        ...en['aider']!,
        title: "Aider voor design — Open Design",
        description: "Hoe mensen Aider — de open-source, modelonafhankelijke AI-pairprogrammeur in je terminal — gebruiken voor UI- en webdesign, met git-native bewerkingen, een CONVENTIONS.md-bestand, beeldondersteuning en BYOK, en hoe Open Design Aider verandert in een local-first, open-source design-agent.",
        breadcrumb: "Aider",
        label: "Agent · Aider",
        heading: "Aider voor design.",
        lead: "Aider is de open-source AI-pairprogrammeur die in je terminal leeft en rechtstreeks op je git-repo werkt. Hij is modelonafhankelijk — wijs hem op Claude, GPT-4o, DeepSeek of Gemini met je eigen sleutel — en hij bewerkt bestanden, commit automatisch en leest afbeeldingen op modellen met beeldverwerking. Dat maakt hem een echt designtool zodra je hem referenties, conventies en een verificatielus geeft. Open Design verbindt hem met een open-source design-workflow: je providersleutels, je bestanden, local-first.",
        rich: {"heroCtaLead": "Open Design verandert Aider in een local-first, open-source design-agent — je eigen provider-API-sleutels, je bestanden, een samengestelde bibliotheek van skills en designsystemen eromheen.", "heroCtaActions": [{"label": "Gebruik Aider in Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Aider is een open-source AI-pairprogrammeertool die in je terminal draait en werkt op de code in je git-repository. Twee dingen maken hem specifiek interessant voor design: hij is modelonafhankelijk, zodat je je eigen sleutel meebrengt voor vrijwel elke LLM — Claude, GPT-4o, DeepSeek, Gemini of een lokaal model — en hij is git-native, bewerkt bestanden ter plekke en commit elke wijziging met een zinnige boodschap, zodat elke iteratie te reviewen en omkeerbaar is. Op modellen met beeldverwerking kan hij ook afbeeldingen lezen, zodat een screenshot deel wordt van de prompt. Gecombineerd met de juiste referenties, conventies en een verificatielus bouwt hij echte, responsieve UI. Dit is een praktische, end-to-end gids voor het gebruik van Aider voor UI-, frontend- en designsysteemwerk, en voor het inbedden ervan in een gestructureerde design-workflow met Open Design.", "Het behandelt wat Aider eigenlijk is, waarom een modelonafhankelijke, git-native tool bij design past, hoe je hem vanaf nul opzet, de screenshot-naar-UI-lus, hoe CONVENTIONS.md en Aiders commando's hem uitbreiden, hoe hij zich verhoudt tot Codex, Claude Code, Cursor en Gemini CLI, de valkuilen die AI-output generiek doen lijken, en hoe Open Design de kloof dicht als een open, local-first designlaag — een natuurlijke combinatie, want beide zijn open-source en draaien op je eigen machine."], "heroImage": {"src": "/agents/aider-design/aider-design-hero.webp", "alt": "Aider design-feedbacklus: een terminal-agent die een referentieafbeelding leest, een git-repo met commits, een browser die de UI rendert, met een feedbackpijl die terugloopt", "caption": "De kernlus: Aider leest je referenties in de terminal, bewerkt en commit de UI in je git-repo, en itereert daartegen — met welk model je ook meebrengt."}, "tocLabel": "Op deze pagina", "toc": [{"id": "what-is-aider", "label": "Wat Aider eigenlijk is"}, {"id": "why-design", "label": "Waarom modelonafhankelijk + git-native bij design past"}, {"id": "setup", "label": "Aider opzetten voor design (vanaf nul)"}, {"id": "screenshot-workflow", "label": "De screenshot-naar-UI-workflow"}, {"id": "extend", "label": "CONVENTIONS.md, afbeeldingen en commando's"}, {"id": "vs", "label": "Aider vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Valkuilen en de “AI-slop”-look"}, {"id": "open-design", "label": "Ontwerpen met Aider in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-aider", "heading": "Wat Aider eigenlijk is", "blocks": [{"kind": "p", "text": "Aider is een open-source (Apache-2.0) AI-pairprogrammeertool die in je terminal draait. Hij leest je bestaande codebase, brengt de hele repository in kaart voor context, bewerkt bestanden ter plekke en commit automatisch elke wijziging met een zinnige boodschap — zodat je het werk van de AI kunt diffen, beheren en ongedaan maken met de git-tools die je al gebruikt. Hij werkt met 100+ programmeertalen en start nieuwe projecten of bouwt voort op bestaande."}, {"kind": "p", "text": "Voor designwerk springen twee eigenschappen eruit. Aider is modelonafhankelijk: je brengt je eigen sleutel mee en verbindt hem met vrijwel elke LLM — Claude, GPT-4o, DeepSeek, Gemini of een lokaal model — zodat je nooit vastzit aan één provider. En op modellen met beeldverwerking zoals GPT-4o en Claude kan hij beeldbestanden lezen, waardoor een referentie-screenshot deel wordt van de prompt."}, {"kind": "steps", "items": [{"label": "Conventiebestand", "body": "Aider leest een CONVENTIONS.md-bestand dat je laadt met /read CONVENTIONS.md (of aider --read CONVENTIONS.md) — de natuurlijke plek om je designconventies, tokens en reviewchecklists te coderen als alleen-lezen context."}, {"label": "Git-native bewerkingen", "body": "Elke wijziging wordt toegepast op bestanden in je repo en automatisch gecommit, zodat elke design-iteratie te reviewen en omkeerbaar is met vertrouwde git-tools."}, {"label": "Breng je eigen model mee", "body": "Verbind OpenAI, Anthropic, DeepSeek, Gemini of een lokaal model met je eigen API-sleutel; Aider zit niet vast aan één leverancier of een gehoste backend."}]}, {"kind": "ul", "items": ["Leverancier: Aider (Aider-AI, open source) — modelonafhankelijk", "Credential: je eigen provider-API-sleutel — BYOK (OpenAI, Anthropic, DeepSeek, Gemini of een lokaal model)", "Licentie: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Waarom een modelonafhankelijke, git-native tool bij design past", "blocks": [{"kind": "p", "text": "Aiders designvoordeel komt voort uit hoe hij werkt met je repo en je modelkeuze — maar, zoals bij elke agent, smaak moet nog steeds worden aangeleverd."}, {"kind": "steps", "items": [{"label": "Modelonafhankelijk, BYOK", "body": "Kies het model dat het beste ontwerpt voor je taak en budget — Claude, GPT-4o, DeepSeek, Gemini — en wissel vrij zonder je workflow te veranderen, allemaal op je eigen sleutel."}, {"label": "Git-native iteratie", "body": "Auto-commits maken van elke designronde een te reviewen diff die je kunt terugdraaien, zodat je itereert tegen een schone basis in plaats van een ongetrackte stapel bewerkingen."}, {"label": "Conventies in CONVENTIONS.md", "body": "Een CONVENTIONS.md (alleen-lezen geladen) wijst de agent op je tokens, componenten en regels, zodat hij werkt tegen een merk in plaats van een standaard look."}]}, {"kind": "image", "src": "/agents/aider-design/aider-design-taste-triangle.webp", "alt": "Diagram dat toont hoe designsysteem, skill en referentieafbeelding samenkomen tot goede design-output", "caption": "Smaak komt voort uit drie inputs die jij aanlevert: een designsysteem, een skill en echte referentieafbeeldingen."}, {"kind": "p", "text": "De les is dezelfde die elke agent leert: Aider heeft standaard geen smaak. Hij produceert goed design wanneer je hem beperkingen geeft — een designsysteem, een esthetische skill en concrete referenties. Open Design verpakt precies die inputs, en daarom passen de twee bij elkaar (meer hieronder)."}]}, {"id": "setup", "heading": "Aider opzetten voor designwerk, vanaf nul", "blocks": [{"kind": "p", "text": "Hier is het volledige pad van een schone machine naar een Aider die UI kan bouwen en verifiëren."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Aider (recommended installer; Python 3.8–3.13)\npython -m pip install aider-install\naider-install\n# or with pipx: pipx install aider-chat\n\n# 2. Start it in your git project and bring your own key\ncd your-project\naider --model sonnet --api-key anthropic=<your-key>\n# or: aider --api-key openai=<your-key>   (also deepseek=, gemini=)\n\n# 3. Load your design conventions as read-only context\naider --read CONVENTIONS.md\n\n# 4. Add a reference image (on a vision-capable model)\n#    inside the chat: /add reference-desktop.png"}, {"kind": "image", "src": "/agents/aider-design/aider-design-setup-flow.webp", "alt": "Stappenplan in vijf stappen: installeren, je eigen sleutel meebrengen, CONVENTIONS.md laden, een referentie toevoegen, verifiëren", "caption": "De opzetvolgorde: installeren → je eigen sleutel meebrengen → CONVENTIONS.md laden → een referentie toevoegen → browserverificatie inschakelen."}, {"kind": "steps", "items": [{"label": "Codeer je designregels", "body": "Plaats je tokens, primitieven en conventies in CONVENTIONS.md en laad het alleen-lezen, zodat output overeenkomt met een merk in plaats van terug te vallen op een generieke look."}, {"label": "Voeg browserverificatie toe", "body": "Draai een dev-server en laat Aider renderen in een echte browser, en controleer zijn output over breakpoints heen in plaats van alleen te bevestigen dat de build slaagt."}]}]}, {"id": "screenshot-workflow", "heading": "De screenshot-naar-UI-workflow", "blocks": [{"kind": "p", "text": "De designlus met de meeste hefboomwerking met Aider is het omzetten van een referentieafbeelding in werkende, responsieve UI en daarop itereren tot het overeenkomt — met een model met beeldverwerking om output te vergelijken met de referentie, waarbij elke ronde naar git wordt gecommit."}, {"kind": "ol", "items": ["Begin met de duidelijkste visuele referenties die je hebt — en neem meerdere staten mee (desktop en mobiel, hover, leeg, laden), niet slechts één hero-shot.", "Wees specifiek in de prompt; vage prompts leveren generieke UI op, zelfs met een sterk model.", "Bewaar je designsysteem en conventies in CONVENTIONS.md, en vertel Aider waar de tokens en canonieke primitieven leven.", "Draai een dev-server en controleer het gerenderde resultaat in een echte browser, met formaataanpassing naar breakpoints.", "Itereer door Aider zijn implementatie te laten vergelijken met de screenshots — niet alleen bevestigen dat het bouwt."]}, {"kind": "p", "text": "Voeg een afbeelding toe met /add (of /paste vanaf het klembord) op een model met beeldverwerking, en geef dan concrete beperkingen:"}, {"kind": "code", "lang": "bash", "code": "aider --model gpt-4o --read CONVENTIONS.md\n# in the chat:\n> /add reference-desktop.png\n> /add reference-mobile.png\n> Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from CONVENTIONS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  I'll render it in the browser and tell you what to fix until it matches\n  the references across breakpoints."}, {"kind": "p", "text": "Houd prompts klein en gericht. Omdat Aider elke wijziging commit, behoud je goede iteraties en gebruik je git (of /undo) om slechte terug te draaien — zodat elke ronde voortbouwt op een schone basis."}]}, {"id": "extend", "heading": "CONVENTIONS.md, afbeeldingen en commando's", "blocks": [{"kind": "p", "text": "Drie mogelijkheden maken Aider praktisch voor langdurig designwerk, en alle drie passen netjes op een open design-workflow."}, {"kind": "steps", "items": [{"label": "CONVENTIONS.md-context", "body": "Laad code- en designconventies met /read CONVENTIONS.md of aider --read CONVENTIONS.md, of stel read: CONVENTIONS.md in in .aider.conf.yml om het elke ronde te laden. Het is de duurzame thuisbasis voor je tokens, primitieven en regels."}, {"label": "Afbeeldingen en webpagina's", "body": "Op modellen met beeldverwerking kun je een beeldbestand /add of /paste vanaf het klembord om Aider een echte referentie te geven; /web <url> schraapt de tekst van een pagina in de chat voor aanvullende context."}, {"label": "Commando's in de chat", "body": "Commando's als /add om bestanden in context te brengen, /read voor alleen-lezen referenties en /undo om de laatste commit terug te draaien laten hem referenties verzamelen en de verificatielus uitvoeren zonder de terminal te verlaten."}]}, {"kind": "p", "text": "Dit zijn overdraagbare, repo-native mogelijkheden — precies het soort dingen die Open Design is gebouwd om te orkestreren, in plaats van per project opnieuw te creëren."}]}, {"id": "vs", "heading": "Aider vs Codex vs Claude Code vs Cursor vs Gemini CLI voor design", "blocks": [{"kind": "p", "text": "Er is geen enkele winnaar voor designwerk — elke agent heeft een ander sterk punt, en ervaren teams stapelen ze. Een eerlijke samenvatting:"}, {"kind": "table", "columns": ["Agent", "Designsterkte", "Best voor"], "rows": [["Aider", "Open-source, modelonafhankelijk (BYOK) en git-native; auto-commits maken elke iteratie te reviewen en omkeerbaar", "Repo-native iteratie op je bestaande codebase met welk model dan ook het beste ontwerpt"], ["Codex", "Sterke visuele afwerking met een frontend-skill; gesandboxte async builds", "Gedelegeerde async builds en overdraagbare AGENTS.md-regels"], ["Claude Code", "Specifieke designbeslissingen (hex, spacing, type) en codebase-bewuste UX", "Frontend-redenering en refactors met grote context"], ["Cursor", "Visuele bouw-en-zie-lus met live preview en inline bewerkingen", "Strak itereren-en-meekijken UI-werk binnen een IDE"], ["Gemini CLI", "Sterk multimodaal beeldbegrip en een context van 1M tokens; open-source met een gratis laag", "Screenshot-intensief werk en een heel designsysteem in context houden"]]}, {"kind": "p", "text": "Het terugkerende oordeel van de community is dat smaak van mensen komt: ze vallen allemaal terug op een generieke esthetiek zonder skills, referenties en beperkingen. Dat is het echte probleem om op te lossen — en het heeft de vorm van een designtool, niet van een model."}]}, {"id": "pitfalls", "heading": "Valkuilen, en hoe je de “AI-slop”-look vermijdt", "blocks": [{"kind": "p", "text": "De meest voorkomende klacht over door AI gegenereerd design is dat het er generiek uitziet — zachte gradiënten, zwevende panelen, overdreven afgeronde hoeken, dramatische schaduwen, een Inter-en-paars-sfeer die “schreeuwt dat een AI dit heeft gemaakt.” Andere gemelde problemen zijn kapotte mobiele lay-outs en instructies die in de UI-tekst lekken. Geen van deze is uniek voor Aider; ze zijn wat er gebeurt wanneer welke agent dan ook draait zonder een samengestelde designcontext."}, {"kind": "steps", "items": [{"label": "Voeg een esthetische skill toe", "body": "Een samengestelde design-skill dwingt de agent om zich vast te leggen op een echte richting in plaats van de standaard look."}, {"label": "Verifieer in een echte browser", "body": "Render en controleer zichzelf over breakpoints heen zodat lay-outs niet stilletjes breken op mobiel — voer op een model met beeldverwerking de screenshots terug."}, {"label": "Lever tokens en referenties aan", "body": "Echte design-tokens en referentie-screenshots zijn de grootste enkele hefboom op outputkwaliteit."}, {"label": "Codeer regels in CONVENTIONS.md", "body": "Plaats stijlregels als “geen hero-cards, maximaal twee lettertypes, merk-eerst-hiërarchie” waar de agent ze elke ronde leest."}]}, {"kind": "p", "text": "Merk op dat elke mitigatie gaat over het geven van een samengestelde designcontext aan de agent. Die context handmatig onderhouden, per project, is het zware werk dat Open Design wegneemt."}]}, {"id": "open-design", "heading": "Ontwerpen met Aider in Open Design", "blocks": [{"kind": "p", "text": "Open Design is de open-source designlaag waar de bovenstaande workflow steeds om vraagt. Het behandelt Aider als een first-party adapter en wikkelt hem in een samengestelde bibliotheek van skills en designsystemen, een gestructureerde render-pijplijn en een lokale desktop-UI — zodat de designcontext die Aider goed maakt er vanaf de eerste ronde is, niet telkens handmatig samengesteld. Beide zijn open-source en local-first, wat de combinatie een natuurlijke match maakt."}, {"kind": "ol", "items": ["Installeer Open Design en selecteer Aider als je agent.", "Authenticeer met je eigen provider-API-sleutel (BYOK) — OpenAI, Anthropic, DeepSeek of Gemini; credentials blijven op je machine en worden nooit via ons doorgesluisd.", "Kies een designsysteem en een skill, en genereer dan decks, prototypes en landingspagina's met consistente smaak.", "Elk artefact en DESIGN.md-bestand leeft in je eigen git-repo, niet in een gehoste cloud."]}, {"kind": "p", "text": "Dezelfde Aider-agent, dezelfde sleutel — plus een echte, overdraagbare, open-source design-workflow eromheen. Het is local-first en open-source, dus niets van je werk of je credentials verlaat je machine."}]}], "faqTitle": "Veelgestelde vragen", "faq": [{"name": "Kan Aider echt designwerk doen?", "text": "Ja — met een esthetische skill, een designsysteem en echte referentieafbeeldingen in context produceert Aider responsieve UI van productiekwaliteit, en op modellen met beeldverwerking leest hij screenshots om output te verifiëren tegen referenties. Zonder die context valt hij doorgaans terug op een generieke look, en dat is de kloof die Open Design dicht."}, {"name": "Welke modellen kan ik met Aider gebruiken voor design?", "text": "Aider is modelonafhankelijk. Je brengt je eigen API-sleutel mee en verbindt vrijwel elke LLM — Claude, GPT-4o, DeepSeek, Gemini of een lokaal model. Gebruik voor beeldgebaseerd designwerk een model met beeldverwerking zoals GPT-4o of Claude. Open Design sluist je credentials nooit door."}, {"name": "Wat maakt Aider specifiek goed voor design?", "text": "Twee dingen: hij is modelonafhankelijk, dus je kiest het model dat het beste ontwerpt voor je taak, en hij is git-native, commit elke wijziging zodat elke design-iteratie te reviewen en omkeerbaar is. Beide helpen — maar smaak komt nog steeds van het designsysteem, de skill en de referenties die jij aanlevert."}, {"name": "Bewerkt Aider mijn bestanden en commit hij naar git?", "text": "Ja. Aider bewerkt bestanden rechtstreeks in je repository en commit automatisch elke wijziging met een zinnige boodschap, zodat je het werk van de AI kunt diffen, beheren en ongedaan maken met de git-tools die je al gebruikt."}, {"name": "Hoe geef ik Aider mijn designconventies?", "text": "Maak een CONVENTIONS.md met je tokens, primitieven en regels, en laad het dan alleen-lezen met /read CONVENTIONS.md of aider --read CONVENTIONS.md (of stel read: CONVENTIONS.md in in .aider.conf.yml om het elke ronde te laden). Aider werkt dan tegen je merk in plaats van een standaard look."}, {"name": "Is Open Design verbonden met Aider?", "text": "Nee. Aider is een onafhankelijk open-source project (Aider-AI); Open Design is een apart onafhankelijk open-source project dat Aider ondersteunt als first-party adapter. De twee zijn niet verbonden."}, {"name": "Zijn mijn bestanden en credentials veilig?", "text": "Ja — Open Design is local-first en open-source. Je bestanden, artefacten en DESIGN.md blijven in je eigen git-repo, en je provider-API-sleutels worden rechtstreeks door je agent gebruikt, nooit gerouteerd via Open Design-servers."}], "ctaTitle": "Ontwerp met Aider, op de open manier.", "ctaBody": "Breng je eigen provider-API-sleutel mee, houd elk bestand lokaal in je git-repo, en krijg een samengestelde designbibliotheek rond de agent die je al gebruikt.", "ctaActions": [{"label": "Gebruik Aider in Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Bekijk alle ondersteunde agents"},
      },
      'antigravity': {
        ...en['antigravity']!,
        title: "Antigravity voor design — Open Design",
        description: "Hoe mensen Google Antigravity — Google's agent-first ontwikkelplatform aangedreven door multimodale Gemini 3.x-modellen, met de Editor View, Manager Surface, geïntegreerde browserbesturing en Artifacts — gebruiken voor UI- en webdesign, en hoe Open Design Antigravity verandert in een local-first, open-source design-agent.",
        breadcrumb: "Antigravity",
        label: "Agent · Antigravity",
        heading: "Antigravity voor design.",
        lead: "Antigravity is Google's agent-first ontwikkelplatform. Zijn Gemini 3.x-modellen lezen screenshots en redeneren over lay-out, zijn geïntegreerde browser laat agents verifiëren wat ze bouwen, en zijn Artifacts maken van agentwerk te reviewen deliverables — wat het een echt designtool maakt zodra je het referenties, conventies en een verificatielus geeft. Open Design verbindt het met een open-source design-workflow: je Google-account, je bestanden, local-first.",
        rich: {"heroCtaLead": "Open Design verandert Antigravity in een local-first, open-source design-agent — je Google-account, je bestanden, een samengestelde bibliotheek van skills en designsystemen eromheen.", "heroCtaActions": [{"label": "Gebruik Antigravity in Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Antigravity is Google's agent-first ontwikkelplatform, gelanceerd naast Gemini 3. Drie dingen maken het specifiek interessant voor design: zijn agents draaien op natief multimodale Gemini 3.x-modellen, dus ze lezen een screenshot en redeneren over lay-out, spacing en hiërarchie; het wordt geleverd met een geïntegreerde browser die de agent kan aansturen, zodat hij zijn eigen UI rendert en controleert in plaats van te gokken; en het produceert Artifacts — takenlijsten, implementatieplannen, screenshots en browseropnamen — die van agentwerk iets maken dat je daadwerkelijk kunt reviewen. Gecombineerd met de juiste referenties, conventies en een verificatielus bouwt het echte, responsieve UI — en het is gratis om mee te starten met een Google-account. Dit is een praktische, end-to-end gids voor het gebruik van Antigravity voor UI-, frontend- en designsysteemwerk, en voor het inbedden ervan in een gestructureerde design-workflow met Open Design.", "Het behandelt wat Antigravity eigenlijk is, waarom multimodale Gemini en een geïntegreerde browser bij design passen, hoe je het vanaf nul opzet, de screenshot-naar-UI-lus, hoe zijn agentcontext en tooling het uitbreiden, hoe het zich verhoudt tot Codex, Claude Code, Cursor en Gemini CLI, de valkuilen die AI-output generiek doen lijken, en hoe Open Design de kloof dicht als een open, local-first designlaag — een natuurlijke combinatie, want Open Design is open-source en draait op je eigen machine."], "heroImage": {"src": "/agents/antigravity-design/antigravity-design-hero.webp", "alt": "Antigravity design-feedbacklus: een agent-first IDE die een referentieafbeelding leest, een geïntegreerde browser die de UI rendert, en een Manager-surface, met een feedbackpijl die terugloopt", "caption": "De kernlus: een Antigravity-agent leest je referenties, bouwt en verifieert de UI in zijn geïntegreerde browser, en itereert daartegen — en presenteert het werk als te reviewen Artifacts."}, "tocLabel": "Op deze pagina", "toc": [{"id": "what-is-antigravity", "label": "Wat Antigravity eigenlijk is"}, {"id": "why-design", "label": "Waarom multimodale Gemini + een ingebouwde browser bij design passen"}, {"id": "setup", "label": "Antigravity opzetten voor design (vanaf nul)"}, {"id": "screenshot-workflow", "label": "De screenshot-naar-UI-workflow"}, {"id": "extend", "label": "Agentcontext, tools en Artifacts"}, {"id": "vs", "label": "Antigravity vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Valkuilen en de “AI-slop”-look"}, {"id": "open-design", "label": "Ontwerpen met Antigravity in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-antigravity", "heading": "Wat Antigravity eigenlijk is", "blocks": [{"kind": "p", "text": "Antigravity is Google's agent-first ontwikkelplatform — een door AI aangedreven IDE die zo is gebouwd dat autonome agents, niet zijbalk-chatbots, het werk doen. Aangekondigd op 18 november 2025 naast Gemini 3 en beschikbaar in publieke preview tegen geen kosten voor particulieren, laat het je complexe softwaretaken met meerdere tools delegeren aan een agent die werkt over de editor, terminal en een geïntegreerde browser. Zijn agents draaien voornamelijk op Google's multimodale Gemini 3.x-modellen."}, {"kind": "p", "text": "Voor designwerk springen drie eigenschappen eruit. Zijn agents lezen screenshots en redeneren over de daadwerkelijke lay-out, omdat Gemini 3.x natief multimodaal is. Het kan een echte browser aansturen, zodat het rendert en verifieert wat het bouwt. En het presenteert Artifacts — takenlijsten, plannen, screenshots en browseropnamen — zodat je tastbare output reviewt in plaats van ruwe toollogboeken."}, {"kind": "steps", "items": [{"label": "Editor View + Manager Surface", "body": "De Editor View is een vertrouwde AI-IDE met tab-aanvullingen en inline-commando's; de Manager Surface laat je meerdere agents spawnen, orkestreren en observeren die asynchroon over werkruimtes werken — de natuurlijke plek om een lange designtaak te draaien."}, {"label": "Geïntegreerde browser + Artifacts", "body": "Agents kunnen handelen in een ingebouwde browser en Artifacts uitstoten (screenshots, browseropnamen, takenlijsten, plannen) waarop je feedback kunt achterlaten — een verificatielus die in het platform is ingebouwd in plaats van eraan vastgeschroefd."}, {"label": "Gratis om te starten", "body": "Inloggen met een persoonlijk Google-account geeft genereuze rate limits op Gemini 3.x; het platform draait op macOS, Windows en Linux."}]}, {"kind": "ul", "items": ["Leverancier: Google", "Credential: Google-account (persoonlijke Gmail), gratis tijdens de publieke preview", "Binary: start met agy; draait op macOS, Windows en Linux"]}]}, {"id": "why-design", "heading": "Waarom multimodale Gemini en een ingebouwde browser bij design passen", "blocks": [{"kind": "p", "text": "Antigravity's designvoordeel komt voort uit het model en het platform samen — maar, zoals bij elke agent, smaak moet nog steeds worden aangeleverd."}, {"kind": "steps", "items": [{"label": "Sterk multimodaal begrip", "body": "Omdat Gemini 3.x natief multimodaal is, leest de agent referentie-screenshots goed — en vergelijkt zijn gerenderde output met een afbeelding in plaats van te gokken op basis van een prozabeschrijving."}, {"label": "Een geïntegreerde browser om te verifiëren", "body": "De agent stuurt een echte browser aan, dus hij rendert de UI, controleert hem over staten heen en vangt kapotte lay-outs — en legt het resultaat vast als een browseropname-Artifact dat je kunt reviewen."}, {"label": "Conventies die de agent leest", "body": "Codeer je tokens, componenten en reviewregels in de projectcontext van de agent zodat hij werkt tegen je merk in plaats van een standaard look."}]}, {"kind": "image", "src": "/agents/antigravity-design/antigravity-design-taste-triangle.webp", "alt": "Diagram dat toont hoe designsysteem, skill en referentieafbeelding samenkomen tot goede design-output", "caption": "Smaak komt voort uit drie inputs die jij aanlevert: een designsysteem, een skill en echte referentieafbeeldingen."}, {"kind": "p", "text": "De les is dezelfde die elke agent leert: Antigravity heeft standaard geen smaak. Het produceert goed design wanneer je het beperkingen geeft — een designsysteem, een esthetische skill en concrete referenties. Open Design verpakt precies die inputs, en daarom passen de twee bij elkaar (meer hieronder)."}]}, {"id": "setup", "heading": "Antigravity opzetten voor designwerk, vanaf nul", "blocks": [{"kind": "p", "text": "Hier is het volledige pad van een schone machine naar een Antigravity-agent die UI kan bouwen en verifiëren. De exacte in-app-menu's kunnen tijdens de preview verschuiven, dus dit blijft op het niveau waar je op kunt vertrouwen."}, {"kind": "code", "lang": "bash", "code": "# 1. Download Antigravity for your OS (macOS, Windows, Linux)\n#    from the official download page: antigravity.google/download\n\n# 2. Launch it and sign in\nagy               # opens Antigravity; sign in with your Google account\n\n# 3. Accept the data-use policy, pick a theme, and open your project folder\n\n# 4. Start an agent task in the Editor View or the Manager Surface,\n#    selecting a Gemini 3.x model (e.g. Gemini 3.1 Pro)"}, {"kind": "image", "src": "/agents/antigravity-design/antigravity-design-setup-flow.webp", "alt": "Stappenplan in vijf stappen: downloaden, inloggen met Google, project openen, designregels en een skill toevoegen, browserverificatie inschakelen", "caption": "De opzetvolgorde: downloaden → inloggen met Google → je project openen → designregels en een skill toevoegen → de geïntegreerde browser gebruiken om te verifiëren."}, {"kind": "steps", "items": [{"label": "Codeer je designregels", "body": "Plaats je tokens, primitieven en conventies in de projectcontext van de agent zodat output overeenkomt met een merk in plaats van terug te vallen op een generieke look."}, {"label": "Gebruik de geïntegreerde browser", "body": "Laat de agent renderen in Antigravity's ingebouwde browser en controleer zijn output over breakpoints heen — verifieer dat de UI er goed uitziet, niet alleen dat de build slaagt."}]}]}, {"id": "screenshot-workflow", "heading": "De screenshot-naar-UI-workflow", "blocks": [{"kind": "p", "text": "De designlus met de meeste hefboomwerking met Antigravity is het omzetten van een referentieafbeelding in werkende, responsieve UI en daarop itereren tot het overeenkomt — leunend op het multimodale model om output te vergelijken met de referentie, en op de geïntegreerde browser om het te verifiëren."}, {"kind": "ol", "items": ["Begin met de duidelijkste visuele referenties die je hebt — en neem meerdere staten mee (desktop en mobiel, hover, leeg, laden), niet slechts één hero-shot.", "Wees specifiek in de prompt; vage prompts leveren generieke UI op, zelfs met een sterk model.", "Bewaar je designsysteem en conventies in de projectcontext van de agent, en vertel hem waar de tokens en canonieke primitieven leven.", "Laat de agent renderen in Antigravity's geïntegreerde browser, met formaataanpassing naar breakpoints om het resultaat te controleren.", "Itereer door de agent zijn implementatie te laten vergelijken met de screenshots — niet alleen bevestigen dat het bouwt — en review de browseropname- en screenshot-Artifacts die hij produceert."]}, {"kind": "p", "text": "Voeg je referentieafbeeldingen toe en geef concrete beperkingen, en laat de agent dan verifiëren in de browser:"}, {"kind": "code", "lang": "text", "code": "# In an Antigravity agent task, attach reference-desktop.png and\n# reference-mobile.png, then prompt:\n\nImplement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nRender it in the integrated browser and iterate until it matches\nthe references across breakpoints, and show me the screenshots."}, {"kind": "p", "text": "Houd prompts klein en gericht, commit goede iteraties en draai slechte terug (en vertel de agent wanneer je terugdraait), zodat elke ronde voortbouwt op een schone basis."}]}, {"id": "extend", "heading": "Agentcontext, tools en Artifacts", "blocks": [{"kind": "p", "text": "Drie uitbreidingspunten maken Antigravity praktisch voor langdurig designwerk, en alle drie passen netjes op een open design-workflow."}, {"kind": "steps", "items": [{"label": "Projectcontext", "body": "Persistente projectregels zijn de duurzame thuisbasis voor je designconventies — tokens, primitieven en reviewchecklists die de agent bij elke taak leest, zodat output on-brand blijft."}, {"label": "Geïntegreerde browser + terminal", "body": "Agents handelen over de editor, terminal en een ingebouwde browser, zodat ze referenties kunnen verzamelen, een dev-server draaien en gerenderde UI verifiëren zonder het platform te verlaten."}, {"label": "Artifacts die je reviewt", "body": "Takenlijsten, implementatieplannen, screenshots en browseropnamen maken agentwerk leesbaar; je laat feedback achter op het Artifact en de agent verwerkt correcties."}]}, {"kind": "p", "text": "Dit zijn de mogelijkheden die een serieuze designlus nodig heeft — precies het soort dingen die Open Design is gebouwd om te orkestreren, in plaats van per project opnieuw te creëren."}]}, {"id": "vs", "heading": "Antigravity vs Codex vs Claude Code vs Cursor vs Gemini CLI voor design", "blocks": [{"kind": "p", "text": "Er is geen enkele winnaar voor designwerk — elke agent heeft een ander sterk punt, en ervaren teams stapelen ze. Een eerlijke samenvatting:"}, {"kind": "table", "columns": ["Agent", "Designsterkte", "Best voor"], "rows": [["Antigravity", "Agent-first IDE met multimodale Gemini 3.x, een geïntegreerde browser voor zelfverificatie en te reviewen Artifacts; gratis in preview", "Async multi-agent builds met ingebouwde browserverificatie van UI"], ["Codex", "Sterke visuele afwerking met een frontend-skill; gesandboxte async builds", "Gedelegeerde async builds en overdraagbare AGENTS.md-regels"], ["Claude Code", "Specifieke designbeslissingen (hex, spacing, type) en codebase-bewuste UX", "Frontend-redenering en refactors met grote context"], ["Cursor", "Visuele bouw-en-zie-lus met live preview en inline bewerkingen", "Strak itereren-en-meekijken UI-werk binnen een IDE"], ["Gemini CLI", "Open-source terminal-agent op multimodale Gemini met een context van 1M tokens en gratis laag", "Screenshot-intensief terminalwerk en een heel designsysteem in context houden"]]}, {"kind": "p", "text": "Het terugkerende oordeel van de community is dat smaak van mensen komt: ze vallen allemaal terug op een generieke esthetiek zonder skills, referenties en beperkingen. Dat is het echte probleem om op te lossen — en het heeft de vorm van een designtool, niet van een model."}]}, {"id": "pitfalls", "heading": "Valkuilen, en hoe je de “AI-slop”-look vermijdt", "blocks": [{"kind": "p", "text": "De meest voorkomende klacht over door AI gegenereerd design is dat het er generiek uitziet — zachte gradiënten, zwevende panelen, overdreven afgeronde hoeken, dramatische schaduwen, een Inter-en-paars-sfeer die “schreeuwt dat een AI dit heeft gemaakt.” Andere gemelde problemen zijn kapotte mobiele lay-outs en instructies die in de UI-tekst lekken. Geen van deze is uniek voor Antigravity; ze zijn wat er gebeurt wanneer welke agent dan ook draait zonder een samengestelde designcontext."}, {"kind": "steps", "items": [{"label": "Voeg een esthetische skill toe", "body": "Een samengestelde design-skill dwingt de agent om zich vast te leggen op een echte richting in plaats van de standaard look."}, {"label": "Verifieer in de geïntegreerde browser", "body": "Gebruik het multimodale model en Antigravity's ingebouwde browser om te renderen en zichzelf te controleren over breakpoints heen zodat lay-outs niet stilletjes breken op mobiel."}, {"label": "Lever tokens en referenties aan", "body": "Echte design-tokens en referentie-screenshots zijn de grootste enkele hefboom op outputkwaliteit."}, {"label": "Codeer regels in projectcontext", "body": "Plaats stijlregels als “geen hero-cards, maximaal twee lettertypes, merk-eerst-hiërarchie” waar de agent ze bij elke taak leest."}]}, {"kind": "p", "text": "Merk op dat elke mitigatie gaat over het geven van een samengestelde designcontext aan de agent. Die context handmatig onderhouden, per project, is het zware werk dat Open Design wegneemt."}]}, {"id": "open-design", "heading": "Ontwerpen met Antigravity in Open Design", "blocks": [{"kind": "p", "text": "Open Design is de open-source designlaag waar de bovenstaande workflow steeds om vraagt. Het behandelt Antigravity als een first-party adapter en wikkelt het in een samengestelde bibliotheek van skills en designsystemen, een gestructureerde render-pijplijn en een lokale desktop-UI — zodat de designcontext die Antigravity goed maakt er vanaf de eerste ronde is, niet telkens handmatig samengesteld. Open Design is open-source en local-first, wat de combinatie een natuurlijke match maakt."}, {"kind": "ol", "items": ["Installeer Open Design en selecteer Antigravity als je agent.", "Authenticeer met je Google-account — credentials blijven op je machine en worden nooit via ons doorgesluisd.", "Kies een designsysteem en een skill, en genereer dan decks, prototypes en landingspagina's met consistente smaak.", "Elk artefact en DESIGN.md-bestand leeft in je eigen repo, niet in een gehoste cloud."]}, {"kind": "p", "text": "Dezelfde Antigravity-agent, hetzelfde Google-account — plus een echte, overdraagbare, open-source design-workflow eromheen. Open Design is local-first en Apache-2.0, dus niets van je werk of je credentials verlaat je machine."}]}], "faqTitle": "Veelgestelde vragen", "faq": [{"name": "Kan Antigravity echt designwerk doen?", "text": "Ja — met een esthetische skill, een designsysteem en echte referentieafbeeldingen in context produceert Antigravity responsieve UI van productiekwaliteit, en zijn multimodale Gemini 3.x-agents verifiëren output in de geïntegreerde browser. Zonder die context valt het doorgaans terug op een generieke look, en dat is de kloof die Open Design dicht."}, {"name": "Moet ik betalen om met Antigravity te ontwerpen?", "text": "Antigravity is beschikbaar in publieke preview tegen geen kosten voor particulieren, met genereuze rate limits op Gemini 3.x wanneer je inlogt met een persoonlijk Google-account. Open Design sluist je credentials sowieso nooit door."}, {"name": "Wat maakt Antigravity specifiek goed voor design?", "text": "Drie dingen: zijn agents draaien op natief multimodale Gemini 3.x-modellen die referentie-screenshots goed lezen, het wordt geleverd met een geïntegreerde browser die de agent kan aansturen om UI te verifiëren, en het presenteert Artifacts — screenshots en browseropnamen — die je kunt reviewen. Smaak komt nog steeds van het designsysteem, de skill en de referenties die jij aanlevert."}, {"name": "Antigravity of Claude Code voor frontend-design?", "text": "Beide zijn sterk. Claude Code staat bekend om specifieke, codebase-bewuste designbeslissingen; het voordeel van Antigravity is zijn agent-first platform — multimodale Gemini 3.x, een geïntegreerde browser voor verificatie en te reviewen Artifacts. Veel teams gebruiken beide — met Open Design kun je van agent wisselen zonder je design-workflow te veranderen."}, {"name": "Hoe verifieer ik wat Antigravity bouwt?", "text": "Antigravity wordt geleverd met een geïntegreerde browser die zijn agents kunnen aansturen, zodat ze de UI renderen, hem over breakpoints heen controleren en screenshots en browseropnamen vastleggen als Artifacts. Die Artifacts reviewen — en de agent zijn output laten vergelijken met je referenties — is hoe je het resultaat op-spec houdt."}, {"name": "Is Open Design verbonden met Google?", "text": "Nee. Antigravity is een product van Google; Open Design is een onafhankelijk open-source project dat het ondersteunt als first-party adapter. Antigravity en Gemini zijn handelsmerken van Google."}, {"name": "Zijn mijn bestanden en credentials veilig?", "text": "Ja — Open Design is local-first en Apache-2.0. Je bestanden, artefacten en DESIGN.md blijven in je eigen repo, en je Google-credentials worden rechtstreeks door je agent gebruikt, nooit gerouteerd via Open Design-servers."}], "ctaTitle": "Ontwerp met Antigravity, op de open manier.", "ctaBody": "Breng je eigen Google-account mee, houd elk bestand lokaal, en krijg een samengestelde designbibliotheek rond de agent die je al gebruikt.", "ctaActions": [{"label": "Gebruik Antigravity in Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Bekijk alle ondersteunde agents"},
      },
      'reasonix': {
        ...en['reasonix']!,
        title: "DeepSeek Reasonix voor design — Open Design",
        description: "Hoe mensen DeepSeek Reasonix — de door de community gebouwde, DeepSeek-native terminal-codingagent — gebruiken voor UI- en webdesign, en hoe Open Design het verandert in een local-first, open-source design-agent. BYOK met je eigen DeepSeek-API-sleutel.",
        breadcrumb: "DeepSeek Reasonix",
        label: "Agent · DeepSeek Reasonix",
        heading: "DeepSeek Reasonix voor design.",
        lead: "DeepSeek Reasonix is een open-source, door de community gebouwde terminal-codingagent aangedreven door DeepSeek-modellen. Hij leest je repo, bewerkt bestanden en voert je verificatielus goedkoop uit — zijn hele ontwerp is gebouwd rond DeepSeeks prefix-cache om lange sessies betaalbaar te houden. Met referenties, conventies en een browsercontrole wordt hij een echt designtool. Open Design verbindt hem met een open-source design-workflow: je eigen DeepSeek-API-sleutel, je bestanden, local-first.",
        rich: {"heroCtaLead": "Open Design verandert DeepSeek Reasonix in een local-first, open-source design-agent — je eigen DeepSeek-API-sleutel, je bestanden, een samengestelde bibliotheek van skills en designsystemen eromheen.", "heroCtaActions": [{"label": "Gebruik DeepSeek Reasonix in Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["DeepSeek Reasonix is een open-source, door de community gebouwde AI-codingagent voor de terminal, aangedreven door DeepSeeks modellen. Het is geen officieel DeepSeek-product — het wordt onderhouden door de esengine GitHub-auteur en de community, en het is specifiek gebouwd rond DeepSeeks prefix-cache-mechanismen zodat lange, iteratieve sessies goedkoop blijven. Hij leest je repository, bewerkt bestanden, voert opdrachten uit en werkt vanuit taken in natuurlijke taal in plaats van alleen regels aan te vullen. Je brengt je eigen DeepSeek-API-sleutel mee (BYOK), en de agent draait op DeepSeek-modellen zoals deepseek-v4-pro en deepseek-v4-flash. Dit is een praktische, end-to-end gids voor het gebruik van DeepSeek Reasonix voor UI-, frontend- en designsysteemwerk, en voor het inbedden ervan in een gestructureerde design-workflow met Open Design.", "Het behandelt wat DeepSeek Reasonix eigenlijk is, waarom een kostenefficiënte, door DeepSeek aangedreven agent bij iteratief design past, hoe je hem vanaf nul opzet met je eigen sleutel, de referentie-naar-UI-lus, hoe skills en MCP hem uitbreiden, hoe hij zich verhoudt tot Codex, Claude Code, Cursor en Gemini CLI, de valkuilen die AI-output generiek doen lijken, en hoe Open Design de kloof dicht als een open, local-first designlaag — een natuurlijke combinatie, want beide zijn open-source en draaien op je eigen machine."], "heroImage": {"src": "/agents/reasonix-design/reasonix-design-hero.webp", "alt": "DeepSeek Reasonix design-feedbacklus: een terminal-agent die designreferenties leest, een browser die de UI rendert, en een werkruimte, met een feedbackpijl die terugloopt", "caption": "De kernlus: DeepSeek Reasonix werkt in de terminal tegen je referenties en conventies, je verifieert de UI in een echte browser, en hij itereert — goedkoop, dankzij DeepSeek prefix-caching."}, "tocLabel": "Op deze pagina", "toc": [{"id": "what-is-reasonix", "label": "Wat DeepSeek Reasonix eigenlijk is"}, {"id": "why-design", "label": "Waarom een kostenefficiënte DeepSeek-agent bij design past"}, {"id": "setup", "label": "DeepSeek Reasonix opzetten voor design (vanaf nul)"}, {"id": "screenshot-workflow", "label": "De referentie-naar-UI-workflow"}, {"id": "extend", "label": "Skills, MCP en config"}, {"id": "vs", "label": "DeepSeek Reasonix vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Valkuilen en de “AI-slop”-look"}, {"id": "open-design", "label": "Ontwerpen met DeepSeek Reasonix in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-reasonix", "heading": "Wat DeepSeek Reasonix eigenlijk is", "blocks": [{"kind": "p", "text": "DeepSeek Reasonix is een open-source (MIT) AI-codingagent voor de terminal, gebouwd door de esengine GitHub-auteur en de community. Hij is DeepSeek-native: ontworpen rond DeepSeeks prefix-cache-mechanismen zodat lange, iteratieve sessies goedkoop blijven. Hij leest je repository, bewerkt bestanden met een review-gestuurde SEARCH/REPLACE-editor, voert shell-opdrachten uit en werkt vanuit taken in natuurlijke taal — hij plant en verifieert in plaats van alleen regels aan te vullen. Het is belangrijk duidelijk te zijn dat dit een communityproject is, geen officieel product van DeepSeek het bedrijf."}, {"kind": "p", "text": "Voor designwerk telt vooral dat het een capabele, repo-bewuste codingagent is die op sterke DeepSeek-modellen draait tegen lage kosten. De DeepSeek-modellen die hij gebruikt zijn alleen-tekst — ze lezen niet natief afbeeldingen — dus de praktische designlus is referentiegestuurd en geverifieerd in een echte browser, in plaats van dat de agent een screenshot direct “ziet.” De kostenefficiëntie is het designrelevante voordeel: je kunt vele keren op UI itereren zonder de rekening die strakke lussen meestal ontmoedigt."}, {"kind": "steps", "items": [{"label": "DeepSeek-native, BYOK", "body": "Reasonix draait op DeepSeek-modellen zoals deepseek-v4-pro en deepseek-v4-flash. Je brengt je eigen DeepSeek-API-sleutel mee — de credential leeft in je omgeving, niet in de config van de agent."}, {"label": "Repo-bewuste bewerking", "body": "Hij leest en bewerkt bestanden in je project met een review-gestuurde editor en voert shell-opdrachten uit, zodat hij echte UI-code in je eigen repository kan bouwen en itereren."}, {"label": "Skills + MCP", "body": "Hij ondersteunt in Markdown geschreven skills en MCP-servers, zodat je hem duurzame conventies kunt geven en externe context zoals een designbron kunt verbinden."}]}, {"kind": "ul", "items": ["Leverancier: community / de esengine GitHub-auteur (niet DeepSeek het bedrijf)", "Credential: je eigen DeepSeek-API-sleutel (BYOK), aangeleverd via de omgeving", "Licentie: MIT, open source"]}]}, {"id": "why-design", "heading": "Waarom een kostenefficiënte DeepSeek-agent bij design past", "blocks": [{"kind": "p", "text": "Het designvoordeel van DeepSeek Reasonix gaat minder over één opzichtige mogelijkheid en meer over het goedkoop en herhaalbaar maken van iteratief UI-werk — maar, zoals bij elke agent, smaak moet nog steeds worden aangeleverd."}, {"kind": "steps", "items": [{"label": "Goedkope, strakke iteratie", "body": "Omdat hij ontworpen is rond DeepSeeks prefix-cache, blijven lange designsessies betaalbaar — zodat je de bouw-verifieer-verfijn-lus vele keren kunt draaien in plaats van ermee te rantsoeneren."}, {"label": "Repo-bewust hergebruik", "body": "Hij bewerkt bestanden rechtstreeks in je repo, zodat hij je bestaande componenten en tokens kan hergebruiken in plaats van eenmalige stijlen te verzinnen, wanneer je hem erop wijst."}, {"label": "Conventies in skills", "body": "Markdown-skills en projectconfig laten je tokens, componenten en reviewregels coderen, zodat de agent werkt tegen je merk in plaats van een standaard look."}]}, {"kind": "image", "src": "/agents/reasonix-design/reasonix-design-taste-triangle.webp", "alt": "Diagram dat toont hoe designsysteem, skill en referentieafbeelding samenkomen tot goede design-output", "caption": "Smaak komt voort uit drie inputs die jij aanlevert: een designsysteem, een skill en echte referentieafbeeldingen."}, {"kind": "p", "text": "De les is dezelfde die elke agent leert: DeepSeek Reasonix heeft standaard geen smaak. Hij produceert goed design wanneer je hem beperkingen geeft — een designsysteem, een esthetische skill en concrete referenties die aan hem beschreven worden — en een browser om tegen te verifiëren. Open Design verpakt precies die inputs, en daarom passen de twee bij elkaar (meer hieronder)."}]}, {"id": "setup", "heading": "DeepSeek Reasonix opzetten voor designwerk, vanaf nul", "blocks": [{"kind": "p", "text": "Hier is het pad van een schone machine naar een DeepSeek Reasonix die UI kan bouwen en verifiëren. Omdat het een communityproject is, volg altijd de installatie-instructies in de README van de repo; de schets hieronder is de algemene vorm."}, {"kind": "code", "lang": "bash", "code": "# 1. Install DeepSeek Reasonix (Node 22+) — see the repo README\nnpm install -g reasonix\n\n# 2. Bring your own DeepSeek API key (BYOK)\n#    Reasonix reads it from your environment, not from config files.\nexport DEEPSEEK_API_KEY=sk-...    # your DeepSeek key\n\n# 3. Start it in your project\ncd your-project\nreasonix                         # see README for the exact subcommands\n\n# 4. Add a design source via MCP (optional)\n#    e.g. a Figma MCP server, configured per the repo docs"}, {"kind": "image", "src": "/agents/reasonix-design/reasonix-design-setup-flow.webp", "alt": "Stappenplan in vijf stappen: installeren, je DeepSeek-sleutel toevoegen, conventies configureren, een skill toevoegen, verifiëren in een browser", "caption": "De opzetvolgorde: installeren → je DeepSeek-API-sleutel toevoegen → conventies coderen → een skill toevoegen → browserverificatie inschakelen."}, {"kind": "steps", "items": [{"label": "Codeer je designregels", "body": "Plaats je tokens, primitieven en conventies in een skill of projectconfig en wijs Reasonix erop, zodat output overeenkomt met een merk in plaats van terug te vallen op een generieke look."}, {"label": "Voeg browserverificatie toe", "body": "Omdat DeepSeek-modellen alleen-tekst zijn, bedraad een Playwright- of browser-MCP zodat de agent rendert in een echte browser en zijn output controleert over breakpoints heen in plaats van alleen te bevestigen dat de build slaagt."}]}]}, {"id": "screenshot-workflow", "heading": "De referentie-naar-UI-workflow", "blocks": [{"kind": "p", "text": "De designlus met de meeste hefboomwerking met DeepSeek Reasonix is het omzetten van duidelijke referenties in werkende, responsieve UI en daarop itereren tot het overeenkomt. Omdat de DeepSeek-modellen alleen-tekst zijn, worden de referenties aangeleverd als gedetailleerde beschrijvingen en specificaties — niet natief als afbeeldingen gelezen — en wordt de overeenkomst bevestigd door te renderen in een echte browser."}, {"kind": "ol", "items": ["Vertaal je referenties naar concrete specificaties — beschrijf lay-out, spacing, hiërarchie en staten (desktop en mobiel, hover, leeg, laden) in woorden, want het model leest tekst, geen pixels.", "Wees specifiek in de prompt; vage prompts leveren generieke UI op, zelfs met een sterk model.", "Bewaar je designsysteem en conventies in een skill of projectconfig, en vertel Reasonix waar de tokens en canonieke primitieven leven.", "Draai een dev-server en verifieer het resultaat in een echte browser, met formaataanpassing naar breakpoints — bedraad een browser-MCP zodat de agent zichzelf kan controleren.", "Itereer door de gerenderde UI te vergelijken met je referenties in de browser — niet alleen bevestigen dat het bouwt."]}, {"kind": "p", "text": "Geef de agent concrete beperkingen in de prompt in plaats van een vage briefing:"}, {"kind": "code", "lang": "bash", "code": "reasonix\n# in the prompt:\n> Implement this design in React + Vite + Tailwind + TypeScript.\n  Reference: a two-column hero, 48px vertical rhythm, brand teal\n  accent, system-ui type — desktop and mobile described in DESIGN.md.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in a browser and iterate until it matches the spec\n  across breakpoints."}, {"kind": "p", "text": "Houd prompts klein en gericht, commit goede iteraties en draai slechte terug (en vertel Reasonix wanneer je terugdraait), zodat elke ronde voortbouwt op een schone basis — en zodat de goedkope, cache-vriendelijke lus productief blijft."}]}, {"id": "extend", "heading": "Skills, MCP en config", "blocks": [{"kind": "p", "text": "Een paar uitbreidingspunten maken DeepSeek Reasonix praktisch voor langdurig designwerk, en ze passen netjes op een open design-workflow."}, {"kind": "steps", "items": [{"label": "Markdown-skills", "body": "Reasonix ondersteunt skills geschreven in Markdown — de duurzame thuisbasis voor je designconventies, tokens en reviewchecklists, toegepast bij elke ronde."}, {"label": "MCP-servers", "body": "Hij integreert MCP-servers, de overdraagbare manier om designcontext en externe tools in te brengen — het meest relevant een designbron zoals een Figma MCP-server — die over agents heen werken, niet alleen Reasonix."}, {"label": "Projectconfig en ingebouwde tools", "body": "Config per project plus ingebouwde bestands-, shell- en webtools laten hem context verzamelen en de verificatielus uitvoeren zonder de terminal te verlaten. Raadpleeg de README van de repo voor exacte configpaden."}]}, {"kind": "p", "text": "Dit zijn overdraagbare, multi-agent-mogelijkheden — precies het soort dingen die Open Design is gebouwd om te orkestreren, in plaats van per project opnieuw te creëren."}]}, {"id": "vs", "heading": "DeepSeek Reasonix vs Codex vs Claude Code vs Cursor vs Gemini CLI voor design", "blocks": [{"kind": "p", "text": "Er is geen enkele winnaar voor designwerk — elke agent heeft een ander sterk punt, en ervaren teams stapelen ze. Een eerlijke samenvatting:"}, {"kind": "table", "columns": ["Agent", "Designsterkte", "Best voor"], "rows": [["DeepSeek Reasonix", "Open-source en door DeepSeek aangedreven; kostenefficiënt via prefix-caching, BYOK met je eigen DeepSeek-sleutel (door de community gebouwd, alleen-tekstmodellen)", "Goedkope, hoog-volume iteratie op UI in je eigen repo"], ["Codex", "Sterke visuele afwerking met een frontend-skill; gesandboxte async builds", "Gedelegeerde async builds en overdraagbare AGENTS.md-regels"], ["Claude Code", "Specifieke designbeslissingen (hex, spacing, type) en codebase-bewuste UX", "Frontend-redenering en refactors met grote context"], ["Cursor", "Visuele bouw-en-zie-lus met live preview en inline bewerkingen", "Strak itereren-en-meekijken UI-werk binnen een IDE"], ["Gemini CLI", "Sterk multimodaal beeldbegrip en een context van 1M tokens; open-source met een gratis laag", "Screenshot-intensief werk en een heel designsysteem in context houden"]]}, {"kind": "p", "text": "Het terugkerende oordeel van de community is dat smaak van mensen komt: ze vallen allemaal terug op een generieke esthetiek zonder skills, referenties en beperkingen. Dat is het echte probleem om op te lossen — en het heeft de vorm van een designtool, niet van een model."}]}, {"id": "pitfalls", "heading": "Valkuilen, en hoe je de “AI-slop”-look vermijdt", "blocks": [{"kind": "p", "text": "De meest voorkomende klacht over door AI gegenereerd design is dat het er generiek uitziet — zachte gradiënten, zwevende panelen, overdreven afgeronde hoeken, dramatische schaduwen, een Inter-en-paars-sfeer die “schreeuwt dat een AI dit heeft gemaakt.” Andere gemelde problemen zijn kapotte mobiele lay-outs en instructies die in de UI-tekst lekken. Geen van deze is uniek voor DeepSeek Reasonix; ze zijn wat er gebeurt wanneer welke agent dan ook draait zonder een samengestelde designcontext — en omdat zijn modellen alleen-tekst zijn, telt het nauwkeurig beschrijven van referenties nog meer."}, {"kind": "steps", "items": [{"label": "Voeg een esthetische skill toe", "body": "Een samengestelde design-skill dwingt de agent om zich vast te leggen op een echte richting in plaats van de standaard look."}, {"label": "Verifieer in een echte browser", "body": "Omdat het model niet kan zien, render en controleer zichzelf over breakpoints heen in een echte browser zodat lay-outs niet stilletjes breken op mobiel."}, {"label": "Lever tokens en beschreven referenties aan", "body": "Echte design-tokens en nauwkeurig beschreven referentiestaten zijn de grootste enkele hefboom op outputkwaliteit voor een alleen-tekstagent."}, {"label": "Codeer regels in een skill of config", "body": "Plaats stijlregels als “geen hero-cards, maximaal twee lettertypes, merk-eerst-hiërarchie” waar de agent ze elke ronde leest."}]}, {"kind": "p", "text": "Merk op dat elke mitigatie gaat over het geven van een samengestelde designcontext aan de agent. Die context handmatig onderhouden, per project, is het zware werk dat Open Design wegneemt."}]}, {"id": "open-design", "heading": "Ontwerpen met DeepSeek Reasonix in Open Design", "blocks": [{"kind": "p", "text": "Open Design is de open-source designlaag waar de bovenstaande workflow steeds om vraagt. Het behandelt DeepSeek Reasonix als een first-party adapter en wikkelt hem in een samengestelde bibliotheek van skills en designsystemen, een gestructureerde render-pijplijn en een lokale desktop-UI — zodat de designcontext die Reasonix goed maakt er vanaf de eerste ronde is, niet telkens handmatig samengesteld. Beide zijn open-source en local-first, wat de combinatie een natuurlijke match maakt."}, {"kind": "ol", "items": ["Installeer Open Design en selecteer DeepSeek Reasonix als je agent.", "Authenticeer met je eigen DeepSeek-API-sleutel (BYOK) — credentials blijven op je machine en worden nooit via ons doorgesluisd.", "Kies een designsysteem en een skill, en genereer dan decks, prototypes en landingspagina's met consistente smaak.", "Elk artefact en DESIGN.md-bestand leeft in je eigen repo, niet in een gehoste cloud."]}, {"kind": "p", "text": "Dezelfde DeepSeek Reasonix-agent, dezelfde sleutel — plus een echte, overdraagbare, open-source design-workflow eromheen. Het is local-first en open-source, dus niets van je werk of je credentials verlaat je machine."}]}], "faqTitle": "Veelgestelde vragen", "faq": [{"name": "Kan DeepSeek Reasonix echt designwerk doen?", "text": "Ja — met een esthetische skill, een designsysteem en nauwkeurig beschreven referenties in context produceert DeepSeek Reasonix responsieve UI van productiekwaliteit in je eigen repo, en je verifieert output in een echte browser. Zijn DeepSeek-modellen zijn alleen-tekst, dus de lus is referentie-beschreven-en-geverifieerd in plaats van beeldlezend. Zonder die context valt hij doorgaans terug op een generieke look, en dat is de kloof die Open Design dicht."}, {"name": "Moet ik betalen om met DeepSeek Reasonix te ontwerpen?", "text": "Je brengt je eigen DeepSeek-API-sleutel mee, dus je betaalt DeepSeek voor gebruik (BYOK) — maar de agent is gebouwd rond DeepSeeks prefix-cache om die kosten laag te houden over lange sessies. Reasonix zelf is gratis en MIT-gelicentieerd. Open Design sluist je credentials nooit door."}, {"name": "Is DeepSeek Reasonix een officieel DeepSeek-product?", "text": "Nee. DeepSeek Reasonix is een door de community gebouwd, open-source project van de esengine GitHub-auteur — het draait op DeepSeeks modellen en gebruikt een DeepSeek-API-sleutel, maar het is niet gemaakt of onderschreven door DeepSeek het bedrijf. DeepSeek is een handelsmerk van zijn respectieve eigenaar."}, {"name": "DeepSeek Reasonix of Claude Code voor frontend-design?", "text": "Beide kunnen echt designwerk doen. Claude Code staat bekend om specifieke, codebase-bewuste designbeslissingen; het voordeel van DeepSeek Reasonix is dat hij open-source en kostenefficiënt is, met goedkope, hoog-volume iteratie op DeepSeek-modellen met je eigen sleutel. Veel teams gebruiken er meer dan één — met Open Design kun je van agent wisselen zonder je design-workflow te veranderen."}, {"name": "Hoe verbind ik DeepSeek Reasonix met een designbron zoals Figma?", "text": "Reasonix ondersteunt MCP-servers, zodat je een designbron-MCP (zoals een Figma MCP-server) kunt toevoegen volgens de docs van de repo. De agent kan dan echte designcontext binnenhalen — componenten, variabelen, lay-outdata — als tekst waarop hij kan handelen, zodat de gegenereerde code overeenkomt met de bron in plaats van die te benaderen."}, {"name": "Is Open Design verbonden met DeepSeek?", "text": "Nee. DeepSeek Reasonix is een communityproject dat op DeepSeeks modellen draait; Open Design is een onafhankelijk open-source project dat het ondersteunt als first-party adapter. Het is met geen van beide verbonden — noch DeepSeek het bedrijf, noch de Reasonix-onderhouders. DeepSeek is een handelsmerk van zijn respectieve eigenaar."}, {"name": "Zijn mijn bestanden en credentials veilig?", "text": "Ja — Open Design is local-first en open-source. Je bestanden, artefacten en DESIGN.md blijven in je eigen repo, en je DeepSeek-API-sleutel wordt rechtstreeks door je agent gebruikt, nooit gerouteerd via Open Design-servers."}], "ctaTitle": "Ontwerp met DeepSeek Reasonix, op de open manier.", "ctaBody": "Breng je eigen DeepSeek-API-sleutel mee, houd elk bestand lokaal, en krijg een samengestelde designbibliotheek rond de open-source agent die je al gebruikt.", "ctaActions": [{"label": "Gebruik DeepSeek Reasonix in Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Bekijk alle ondersteunde agents"},
      },
      'hermes': {
        ...en['hermes']!,
        title: "Hermes voor design — Open Design",
        description: "Hoe mensen Nous Research's Hermes — de autonome, multi-provider terminal-codingagent — gebruiken voor UI- en webdesign, en hoe Open Design het verandert in een local-first, open-source design-agent met je eigen xAI-, OpenAI- of Anthropic-sleutel.",
        breadcrumb: "Hermes",
        label: "Agent · Hermes",
        heading: "Hermes voor design.",
        lead: "Hermes is Nous Research's open-source, autonome terminal-agent. Hij plant, voert uit en delegeert werk op zijn eigen machine — en hij is provider-onafhankelijk, dus je brengt je eigen xAI-, OpenAI- of Anthropic-sleutel mee. Die autonomie maakt hem een echt designtool zodra je hem referenties, conventies en een verificatielus geeft. Open Design verbindt hem met een open-source design-workflow: je sleutel, je bestanden, local-first.",
        rich: {"heroCtaLead": "Open Design verandert Hermes in een local-first, open-source design-agent — je eigen xAI-, OpenAI- of Anthropic-sleutel, je bestanden, een samengestelde bibliotheek van skills en designsystemen eromheen.", "heroCtaActions": [{"label": "Gebruik Hermes in Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Hermes is Nous Research's open-source autonome AI-agent. Twee dingen maken hem specifiek interessant voor design: hij is echt agentisch, dus hij plant een taak, voert die uit en delegeert delen aan geïsoleerde subagents in plaats van alleen regels aan te vullen; en hij is provider-onafhankelijk, dus je wijst hem op welk model je ook vertrouwt — standaard xAI Grok, of OpenAI en Anthropic via breng-je-eigen-sleutel. Gecombineerd met de juiste referenties, conventies en een verificatielus bouwt hij echte, responsieve UI op je eigen machine. Dit is een praktische, end-to-end gids voor het gebruik van Hermes voor UI-, frontend- en designsysteemwerk, en voor het inbedden ervan in een gestructureerde design-workflow met Open Design.", "Het behandelt wat Hermes eigenlijk is, waarom een autonome, multi-provider agent bij design past, hoe je hem vanaf nul opzet, de screenshot-naar-UI-lus, hoe skills en subagents hem uitbreiden, hoe hij zich verhoudt tot Codex, Claude Code, Cursor en Gemini CLI, de valkuilen die AI-output generiek doen lijken, en hoe Open Design de kloof dicht als een open, local-first designlaag — een natuurlijke combinatie, want beide zijn open-source en draaien op je eigen machine."], "heroImage": {"src": "/agents/hermes-design/hermes-design-hero.webp", "alt": "Hermes design-feedbacklus: een autonome terminal-agent die een referentieafbeelding leest, delegeert aan subagents, een browser die de UI rendert, en een werkruimte, met een feedbackpijl die terugloopt", "caption": "De kernlus: Hermes leest je referenties in de terminal, plant en delegeert de bouw, verifieert de UI in een echte browser, en itereert daartegen — op welk model je ook meebrengt."}, "tocLabel": "Op deze pagina", "toc": [{"id": "what-is-hermes", "label": "Wat Hermes eigenlijk is"}, {"id": "why-design", "label": "Waarom een autonome, multi-provider agent bij design past"}, {"id": "setup", "label": "Hermes opzetten voor design (vanaf nul)"}, {"id": "screenshot-workflow", "label": "De screenshot-naar-UI-workflow"}, {"id": "extend", "label": "Skills, subagents en providers"}, {"id": "vs", "label": "Hermes vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Valkuilen en de “AI-slop”-look"}, {"id": "open-design", "label": "Ontwerpen met Hermes in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-hermes", "heading": "Wat Hermes eigenlijk is", "blocks": [{"kind": "p", "text": "Hermes is een open-source (MIT) autonome AI-agent van Nous Research. Hij draait persistent op je eigen machine of server, leest je repository, bewerkt bestanden, voert shell-opdrachten uit, doorzoekt het web en — cruciaal — plant en voert meerstaps werk zelfstandig uit, en delegeert delen aan geïsoleerde subagents. Hij is een autonome agent, geen copiloot vastgeklonken aan een IDE."}, {"kind": "p", "text": "Voor designwerk springen twee eigenschappen eruit. Hij is echt agentisch, dus je kunt hem een doel geven en hij plant, bouwt en verifieert in plaats van te wachten op regel-voor-regel-aansturing. En hij is provider-onafhankelijk: je brengt je eigen sleutel mee, standaard xAI Grok maar vrij om hem op OpenAI, Anthropic of een ander ondersteund endpoint te wijzen — zodat jij bepaalt welk model over je design redeneert."}, {"kind": "steps", "items": [{"label": "Skills", "body": "Hermes bouwt en hergebruikt skills — procedureel geheugen dat hij uit ervaring creëert — de natuurlijke plek om je designconventies, tokens en reviewchecklists vast te leggen zodat ze over runs heen blijven bestaan."}, {"label": "Subagents + tools", "body": "Hij spawnt geïsoleerde subagents voor parallelle werkstromen en wordt geleverd met bestands-, shell-, web- en browsertooling, zodat hij referenties kan verzamelen en een bouw-en-verifieer-lus kan uitvoeren zonder de terminal te verlaten."}, {"label": "Breng je eigen sleutel mee", "body": "Hermes valt standaard terug op xAI Grok en ondersteunt OpenAI, Anthropic, OpenRouter en vele andere providers via BYOK — stel een sleutel in of doorloop een OAuth-flow en kies je model."}]}, {"kind": "ul", "items": ["Leverancier: Nous Research", "Credential: providersleutel via BYOK — xAI (Grok, standaard), OpenAI of Anthropic — toegevoegd met hermes auth add", "Licentie: MIT, open source"]}]}, {"id": "why-design", "heading": "Waarom een autonome, multi-provider agent bij design past", "blocks": [{"kind": "p", "text": "Hermes' designvoordeel komt voort uit twee eigenschappen — maar, zoals bij elke agent, smaak moet nog steeds worden aangeleverd."}, {"kind": "steps", "items": [{"label": "Autonoom plannen-en-uitvoeren", "body": "Omdat Hermes zelfstandig plant, uitvoert en delegeert, kan hij een designdoel — match deze referentie, maak het responsief — oppakken en daarnaartoe itereren in plaats van elke stap uitgespeld te krijgen."}, {"label": "Breng het model dat je vertrouwt mee", "body": "Provider-onafhankelijke BYOK betekent dat je het redeneermodel voor de klus kiest: standaard xAI Grok, of OpenAI- en Anthropic-modellen wanneer je hun sterke punten wilt — geen lock-in aan de esthetiek van één leverancier."}, {"label": "Conventies in skills", "body": "Skills (plus een MCP-server zoals Figma) wijzen de agent op je tokens, componenten en echte specificaties, zodat hij werkt tegen een merk in plaats van een standaard look."}]}, {"kind": "image", "src": "/agents/hermes-design/hermes-design-taste-triangle.webp", "alt": "Diagram dat toont hoe designsysteem, skill en referentieafbeelding samenkomen tot goede design-output", "caption": "Smaak komt voort uit drie inputs die jij aanlevert: een designsysteem, een skill en echte referentieafbeeldingen."}, {"kind": "p", "text": "De les is dezelfde die elke agent leert: Hermes heeft standaard geen smaak. Hij produceert goed design wanneer je hem beperkingen geeft — een designsysteem, een esthetische skill en concrete referenties. Open Design verpakt precies die inputs, en daarom passen de twee bij elkaar (meer hieronder)."}]}, {"id": "setup", "heading": "Hermes opzetten voor designwerk, vanaf nul", "blocks": [{"kind": "p", "text": "Hier is het volledige pad van een schone machine naar een Hermes die UI kan bouwen en verifiëren."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Hermes (one-line installer from Nous Research)\ncurl -fsSL https://hermes-agent.nousresearch.com/install.sh | bash\n\n# 2. Run the setup wizard\nhermes setup\n\n# 3. Add a provider and authenticate (BYOK)\n#    default is xAI Grok; OpenAI / Anthropic also supported\nhermes auth add        # add a provider key or run its OAuth flow\nhermes model           # pick the provider and model (grok-4.3 by default)\n\n# 4. Wire a Figma MCP server (optional, for design handoff)\n#    configure it among Hermes' MCP / tool settings"}, {"kind": "image", "src": "/agents/hermes-design/hermes-design-setup-flow.webp", "alt": "Stappenplan in vijf stappen: installeren, authenticeren, een skill configureren, een designsysteem toevoegen, verifiëren", "caption": "De opzetvolgorde: installeren → een providersleutel toevoegen → designregels vastleggen in een skill → een designsysteem toevoegen → browserverificatie inschakelen."}, {"kind": "steps", "items": [{"label": "Codeer je designregels", "body": "Leg je tokens, primitieven en conventies vast in een Hermes-skill en wijs de agent erop, zodat output overeenkomt met een merk in plaats van terug te vallen op een generieke look."}, {"label": "Voeg browserverificatie toe", "body": "Bedraad een Playwright- of browser-MCP zodat Hermes rendert in een echte browser en zijn output controleert over breakpoints heen in plaats van alleen te bevestigen dat de build slaagt."}]}]}, {"id": "screenshot-workflow", "heading": "De screenshot-naar-UI-workflow", "blocks": [{"kind": "p", "text": "De designlus met de meeste hefboomwerking met Hermes is het omzetten van een referentieafbeelding in werkende, responsieve UI en daarop itereren tot het overeenkomt — door de autonome agent de bouw te laten plannen en zijn output te laten vergelijken met de referentie."}, {"kind": "ol", "items": ["Begin met de duidelijkste visuele referenties die je hebt — en neem meerdere staten mee (desktop en mobiel, hover, leeg, laden), niet slechts één hero-shot.", "Wees specifiek in de prompt; vage prompts leveren generieke UI op, zelfs met een sterk model.", "Bewaar je designsysteem en conventies in een skill, en vertel Hermes waar de tokens en canonieke primitieven leven.", "Draai een dev-server en laat Hermes renderen in een echte browser, met formaataanpassing naar breakpoints om het resultaat te controleren.", "Itereer door Hermes zijn implementatie te laten vergelijken met de screenshots — niet alleen bevestigen dat het bouwt."]}, {"kind": "p", "text": "Wijs Hermes op je referenties en geef concrete beperkingen:"}, {"kind": "code", "lang": "bash", "code": "hermes\n# in the prompt:\n> Use reference-desktop.png and reference-mobile.png in this folder.\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from my skill.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Houd prompts klein en gericht, commit goede iteraties en draai slechte terug (en vertel Hermes wanneer je terugdraait), zodat elke ronde voortbouwt op een schone basis."}]}, {"id": "extend", "heading": "Skills, subagents en providers", "blocks": [{"kind": "p", "text": "Drie uitbreidingspunten maken Hermes praktisch voor langdurig designwerk, en alle drie passen netjes op een open design-workflow."}, {"kind": "steps", "items": [{"label": "Skills", "body": "Hermes bouwt en hergebruikt skills — procedureel geheugen dat uit ervaring is gecreëerd. Ze zijn de duurzame thuisbasis voor je designconventies, toegepast bij latere runs in plaats van telkens opnieuw uitgelegd."}, {"label": "Subagents en MCP", "body": "Hij delegeert werk aan geïsoleerde subagents en ondersteunt MCP-servers — de overdraagbare manier om designcontext en externe tools binnen te halen, het meest relevant een Figma MCP-server, die over agents heen werken, niet alleen Hermes."}, {"label": "Providerkeuze", "body": "Omdat Hermes provider-onafhankelijk is (standaard xAI Grok, OpenAI en Anthropic via BYOK), kun je het model afstemmen op de taak zonder je workflow opnieuw te bouwen."}]}, {"kind": "p", "text": "Dit zijn overdraagbare, multi-agent-mogelijkheden — precies het soort dingen die Open Design is gebouwd om te orkestreren, in plaats van per project opnieuw te creëren."}]}, {"id": "vs", "heading": "Hermes vs Codex vs Claude Code vs Cursor vs Gemini CLI voor design", "blocks": [{"kind": "p", "text": "Er is geen enkele winnaar voor designwerk — elke agent heeft een ander sterk punt, en ervaren teams stapelen ze. Een eerlijke samenvatting:"}, {"kind": "table", "columns": ["Agent", "Designsterkte", "Best voor"], "rows": [["Hermes", "Autonome plan-uitvoer-delegeer-agent; provider-onafhankelijke BYOK (standaard xAI Grok, ook OpenAI/Anthropic); open-source en zelf-gehost", "Hands-off autonome builds op welk model je ook vertrouwt, lokaal gehouden"], ["Codex", "Sterke visuele afwerking met een frontend-skill; gesandboxte async builds", "Gedelegeerde async builds en overdraagbare AGENTS.md-regels"], ["Claude Code", "Specifieke designbeslissingen (hex, spacing, type) en codebase-bewuste UX", "Frontend-redenering en refactors met grote context"], ["Cursor", "Visuele bouw-en-zie-lus met live preview en inline bewerkingen", "Strak itereren-en-meekijken UI-werk binnen een IDE"], ["Gemini CLI", "Sterk multimodaal beeldbegrip en een context van 1M tokens; gratis laag", "Screenshot-intensief werk en een heel designsysteem in context houden"]]}, {"kind": "p", "text": "Het terugkerende oordeel van de community is dat smaak van mensen komt: ze vallen allemaal terug op een generieke esthetiek zonder skills, referenties en beperkingen. Dat is het echte probleem om op te lossen — en het heeft de vorm van een designtool, niet van een model."}]}, {"id": "pitfalls", "heading": "Valkuilen, en hoe je de “AI-slop”-look vermijdt", "blocks": [{"kind": "p", "text": "De meest voorkomende klacht over door AI gegenereerd design is dat het er generiek uitziet — zachte gradiënten, zwevende panelen, overdreven afgeronde hoeken, dramatische schaduwen, een Inter-en-paars-sfeer die “schreeuwt dat een AI dit heeft gemaakt.” Andere gemelde problemen zijn kapotte mobiele lay-outs en instructies die in de UI-tekst lekken. Geen van deze is uniek voor Hermes; ze zijn wat er gebeurt wanneer welke agent dan ook draait zonder een samengestelde designcontext."}, {"kind": "steps", "items": [{"label": "Voeg een esthetische skill toe", "body": "Een samengestelde design-skill dwingt de agent om zich vast te leggen op een echte richting in plaats van de standaard look."}, {"label": "Verifieer in een echte browser", "body": "Laat Hermes renderen en zichzelf controleren over breakpoints heen zodat lay-outs niet stilletjes breken op mobiel."}, {"label": "Lever tokens en referenties aan", "body": "Echte design-tokens en referentie-screenshots zijn de grootste enkele hefboom op outputkwaliteit."}, {"label": "Codeer regels in een skill", "body": "Plaats stijlregels als “geen hero-cards, maximaal twee lettertypes, merk-eerst-hiërarchie” in een skill die de agent elke ronde toepast."}]}, {"kind": "p", "text": "Merk op dat elke mitigatie gaat over het geven van een samengestelde designcontext aan de agent. Die context handmatig onderhouden, per project, is het zware werk dat Open Design wegneemt."}]}, {"id": "open-design", "heading": "Ontwerpen met Hermes in Open Design", "blocks": [{"kind": "p", "text": "Open Design is de open-source designlaag waar de bovenstaande workflow steeds om vraagt. Het behandelt Hermes als een first-party adapter en wikkelt hem in een samengestelde bibliotheek van skills en designsystemen, een gestructureerde render-pijplijn en een lokale desktop-UI — zodat de designcontext die Hermes goed maakt er vanaf de eerste ronde is, niet telkens handmatig samengesteld. Beide zijn open-source en local-first, wat de combinatie een natuurlijke match maakt."}, {"kind": "ol", "items": ["Installeer Open Design en selecteer Hermes als je agent.", "Authenticeer met je eigen providersleutel (BYOK) — standaard xAI Grok, of OpenAI of Anthropic — credentials blijven op je machine en worden nooit via ons doorgesluisd.", "Kies een designsysteem en een skill, en genereer dan decks, prototypes en landingspagina's met consistente smaak.", "Elk artefact en DESIGN.md-bestand leeft in je eigen repo, niet in een gehoste cloud."]}, {"kind": "p", "text": "Dezelfde Hermes-agent, dezelfde sleutel — plus een echte, overdraagbare, open-source design-workflow eromheen. Het is local-first en Apache-2.0, dus niets van je werk of je credentials verlaat je machine."}]}], "faqTitle": "Veelgestelde vragen", "faq": [{"name": "Kan Hermes echt designwerk doen?", "text": "Ja — met een esthetische skill, een designsysteem en echte referentieafbeeldingen in context produceert Hermes responsieve UI van productiekwaliteit, en als autonome agent kan hij output zelfstandig renderen en verifiëren tegen referenties. Zonder die context valt hij doorgaans terug op een generieke look, en dat is de kloof die Open Design dicht."}, {"name": "Welke modellen en sleutels gebruikt Hermes?", "text": "Hermes is provider-onafhankelijk en breng-je-eigen-sleutel. Hij valt standaard terug op xAI Grok (bijvoorbeeld grok-4.3) en ondersteunt ook OpenAI, Anthropic, OpenRouter en vele andere providers — je voegt een providersleutel toe (of doorloopt zijn OAuth-flow) met hermes auth add en kiest een model met hermes model. Open Design sluist je credentials nooit door."}, {"name": "Wat maakt Hermes specifiek goed voor design?", "text": "Twee dingen: hij is echt autonoom, dus hij plant, bouwt en verifieert UI in plaats van te wachten op regel-voor-regel-aansturing; en hij is provider-onafhankelijk, dus je kunt het redeneermodel draaien dat je vertrouwt. Beide helpen — maar smaak komt nog steeds van het designsysteem, de skill en de referenties die jij aanlevert."}, {"name": "Hermes of Claude Code voor frontend-design?", "text": "Beide zijn sterk. Claude Code staat bekend om specifieke, codebase-bewuste designbeslissingen; het voordeel van Hermes is autonoom plannen-en-uitvoeren plus providerkeuze — en je kunt Hermes zelfs op een Anthropic-sleutel wijzen. Veel teams gebruiken beide — met Open Design kun je van agent wisselen zonder je design-workflow te veranderen."}, {"name": "Hoe verbind ik Hermes met Figma?", "text": "Voeg een Figma MCP-server toe in Hermes' toolconfiguratie. Hermes kan dan echte designcontext binnenhalen — componenten, variabelen, lay-outdata — zodat de gegenereerde code overeenkomt met de bron in plaats van die te benaderen."}, {"name": "Is Open Design verbonden met Nous Research?", "text": "Nee. Hermes is een product van Nous Research; Open Design is een onafhankelijk open-source project dat het ondersteunt als first-party adapter. Hermes en Nous Research zijn handelsmerken van hun respectieve eigenaar."}, {"name": "Zijn mijn bestanden en credentials veilig?", "text": "Ja — Open Design is local-first en Apache-2.0. Je bestanden, artefacten en DESIGN.md blijven in je eigen repo, en je provider-credentials worden rechtstreeks door je agent gebruikt, nooit gerouteerd via Open Design-servers."}], "ctaTitle": "Ontwerp met Hermes, op de open manier.", "ctaBody": "Breng je eigen xAI-, OpenAI- of Anthropic-sleutel mee, houd elk bestand lokaal, en krijg een samengestelde designbibliotheek rond de agent die je al gebruikt.", "ctaActions": [{"label": "Gebruik Hermes in Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Bekijk alle ondersteunde agents"},
      },
      'devin': {
        ...en['devin']!,
        title: "Devin for Terminal voor design — Open Design",
        description: "Hoe mensen Devin for Terminal — Cognition's autonome AI-software-engineer in de command line — gebruiken voor UI- en webdesign, en hoe Open Design het verandert in een local-first, open-source design-agent met een samengestelde bibliotheek van skills en designsystemen.",
        breadcrumb: "Devin for Terminal",
        label: "Agent · Devin",
        heading: "Devin for Terminal voor design.",
        lead: "Devin for Terminal is Cognition's autonome AI-software-engineer, draaiend in je terminal. Hij plant en voert zelfstandig meerstaps taken uit en kan een sessie overdragen aan een gesandboxte cloud-agent — wat hem een echte manier maakt om frontend-werk te leveren, zodra je hem referenties, conventies en een verificatielus geeft. Open Design verbindt hem met een open-source design-workflow: je Devin-account, je bestanden, local-first.",
        rich: {"heroCtaLead": "Open Design verandert Devin for Terminal in een local-first, open-source design-agent — je Devin-account, je bestanden, een samengestelde bibliotheek van skills en designsystemen eromheen.", "heroCtaActions": [{"label": "Gebruik Devin in Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Devin for Terminal is Cognition's autonome AI-software-engineer, gebracht naar de lokale command line. Twee dingen maken hem specifiek interessant voor design: hij is echt agentisch, dus hij plant en voert een meerstaps taak van begin tot eind uit in plaats van alleen regels aan te vullen; en hij kan een sessie overdragen aan een gesandboxte cloud-agent met zijn eigen computer, zodat langere builds blijven draaien nadat je je laptop dichtklapt. Gecombineerd met de juiste referenties, conventies en een verificatielus bouwt hij echte, responsieve UI. Dit is een praktische, end-to-end gids voor het gebruik van Devin for Terminal voor UI-, frontend- en designsysteemwerk, en voor het inbedden ervan in een gestructureerde design-workflow met Open Design.", "Het behandelt wat Devin for Terminal eigenlijk is, waarom een autonome software-engineer bij designwerk past, hoe je hem vanaf nul opzet, de screenshot-naar-UI-lus, hoe projectregels en externe tools hem uitbreiden, hoe hij zich verhoudt tot Codex, Claude Code, Cursor en Gemini CLI, de valkuilen die AI-output generiek doen lijken, en hoe Open Design de kloof dicht als een open, local-first designlaag — een natuurlijke combinatie voor elke agent die frontend-werk kan plannen en leveren."], "heroImage": {"src": "/agents/devin-design/devin-design-hero.webp", "alt": "Devin for Terminal design-feedbacklus: een autonome terminal-agent die een referentieafbeelding leest, een browser die de UI rendert, en een werkruimte, met een feedbackpijl die terugloopt", "caption": "De kernlus: Devin leest je referenties in de terminal, plant en bouwt de UI, verifieert die in een echte browser, en itereert daartegen — en draagt langere runs over aan de cloud wanneer nodig."}, "tocLabel": "Op deze pagina", "toc": [{"id": "what-is-devin", "label": "Wat Devin for Terminal eigenlijk is"}, {"id": "why-design", "label": "Waarom een autonome software-engineer bij design past"}, {"id": "setup", "label": "Devin opzetten voor design (vanaf nul)"}, {"id": "screenshot-workflow", "label": "De screenshot-naar-UI-workflow"}, {"id": "extend", "label": "Projectregels, tools en cloud-overdracht"}, {"id": "vs", "label": "Devin vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Valkuilen en de “AI-slop”-look"}, {"id": "open-design", "label": "Ontwerpen met Devin in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-devin", "heading": "Wat Devin for Terminal eigenlijk is", "blocks": [{"kind": "p", "text": "Devin for Terminal is de command-line-versie van Devin, Cognition's autonome AI-software-engineer. Hij draait als een lokale codingagent met toegang tot je codebase, tools en omgeving — hij leest je repository, bewerkt bestanden, voert shell-opdrachten uit, en plant en verifieert werk vanuit een taak in natuurlijke taal in plaats van alleen regels aan te vullen. Cognition bouwde een aangepaste terminal-renderbibliotheek in Rust om de interface snel en responsief te houden."}, {"kind": "p", "text": "Voor designwerk springen twee eigenschappen eruit. Hij is echt autonoom, dus je kunt een uitkomst beschrijven en hij voert het meerstaps pad uit om daar te komen. En wanneer een build je laptop ontgroeit, kun je de sessie overdragen aan een cloud-agent die in zijn eigen gesandboxte omgeving draait en asynchroon blijft werken — zodat je kunt terugkomen bij een afgeronde pull request."}, {"kind": "steps", "items": [{"label": "Autonome, agentische uitvoering", "body": "Devin plant en voert zelfstandig een meerstaps taak uit — een feature implementeren, UI bouwen, die draaien en testen — geleid door duidelijke prompts met expliciete voltooiingscriteria."}, {"label": "Lokale agent, cloud-overdracht", "body": "Hij draait lokaal in je terminal, en kan een sessie escaleren naar een gesandboxte cloud-agent die zijn eigen computer heeft en het werk voortzet nadat je weg bent."}, {"label": "Account-gebaseerd, modelkeuze", "body": "Je logt in met een Devin (Cognition)-account; Devin draait op frontier-modellen — je kunt kiezen tussen opties zoals Cognitions eigen SWE-1.6 en andere frontier-modellen."}]}, {"kind": "ul", "items": ["Leverancier: Cognition", "Credential: Devin (Cognition)-account — abonnements-/account-gebaseerde aanmelding, geen breng-je-eigen-sleutel", "Vormfactor: lokale terminal-agent met optionele gesandboxte cloud-overdracht"]}]}, {"id": "why-design", "heading": "Waarom een autonome software-engineer bij design past", "blocks": [{"kind": "p", "text": "Devins designvoordeel komt voort uit hoe hij werkt — autonome, end-to-end uitvoering — maar, zoals bij elke agent, smaak moet nog steeds worden aangeleverd."}, {"kind": "steps", "items": [{"label": "End-to-end, meerstaps builds", "body": "Omdat Devin hele taken plant en uitvoert, kan hij een pagina opzetten, componenten bedraden, een dev-server draaien en het resultaat testen in één keer in plaats van te stoppen bij een snippet."}, {"label": "Gesandboxte cloud-runs", "body": "Langer frontend-werk — een volledige landingspagina, een multi-screen flow — kan overdragen aan een gesandboxte cloud-agent en blijven bouwen, zodat iteratie niet wordt geblokkeerd door je laptop."}, {"label": "Conventies in projectregels", "body": "Wijs de agent op je tokens, componenten en echte specificaties via de regels en docs van je project, zodat hij werkt tegen een merk in plaats van een standaard look."}]}, {"kind": "image", "src": "/agents/devin-design/devin-design-taste-triangle.webp", "alt": "Diagram dat toont hoe designsysteem, skill en referentieafbeelding samenkomen tot goede design-output", "caption": "Smaak komt voort uit drie inputs die jij aanlevert: een designsysteem, een skill en echte referentieafbeeldingen."}, {"kind": "p", "text": "De les is dezelfde die elke agent leert: Devin heeft standaard geen smaak. Hij produceert goed design wanneer je hem beperkingen geeft — een designsysteem, een esthetische skill en concrete referenties. Open Design verpakt precies die inputs, en daarom passen de twee bij elkaar (meer hieronder)."}]}, {"id": "setup", "heading": "Devin opzetten voor designwerk, vanaf nul", "blocks": [{"kind": "p", "text": "Hier is het volledige pad van een schone machine naar een Devin for Terminal die UI kan bouwen en verifiëren."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Devin for Terminal\ncurl -fsSL https://cli.devin.ai/install.sh | bash\n\n# 2. Start it in your project and sign in on first run\ncd your-project\ndevin             # sign in with your Devin (Cognition) account\n\n# 3. Describe the task in natural language, with clear\n#    completion criteria, and let Devin plan and execute.\n\n# 4. When a build outgrows your laptop, hand the session\n#    off to a sandboxed cloud agent that keeps working."}, {"kind": "image", "src": "/agents/devin-design/devin-design-setup-flow.webp", "alt": "Stappenplan in vijf stappen: installeren, inloggen, designregels coderen, referenties toevoegen, verifiëren in een browser", "caption": "De opzetvolgorde: installeren → inloggen → je designregels coderen → referenties aanleveren → verifiëren in een echte browser."}, {"kind": "steps", "items": [{"label": "Codeer je designregels", "body": "Plaats je tokens, primitieven en conventies waar de agent ze leest — in de regels en docs van je project — zodat output overeenkomt met een merk in plaats van terug te vallen op een generieke look."}, {"label": "Voeg browserverificatie toe", "body": "Laat Devin renderen in een echte browser en zijn output controleren over breakpoints heen, zodat hij verifieert tegen het design in plaats van alleen te bevestigen dat de build slaagt."}]}]}, {"id": "screenshot-workflow", "heading": "De screenshot-naar-UI-workflow", "blocks": [{"kind": "p", "text": "De designlus met de meeste hefboomwerking met Devin is het omzetten van een referentieafbeelding in werkende, responsieve UI en daarop itereren tot het overeenkomt — door de autonome agent te laten bouwen, draaien en zijn output te laten vergelijken met de referentie."}, {"kind": "ol", "items": ["Begin met de duidelijkste visuele referenties die je hebt — en neem meerdere staten mee (desktop en mobiel, hover, leeg, laden), niet slechts één hero-shot.", "Wees specifiek in de prompt en geef expliciete voltooiingscriteria; vage prompts leveren generieke UI op, zelfs met een sterke agent.", "Bewaar je designsysteem en conventies in je projectregels, en vertel Devin waar de tokens en canonieke primitieven leven.", "Draai een dev-server en laat Devin renderen in een echte browser, met formaataanpassing naar breakpoints om het resultaat te controleren.", "Itereer door Devin zijn implementatie te laten vergelijken met de referenties — niet alleen bevestigen dat het bouwt — en draag over aan de cloud voor langere rondes."]}, {"kind": "p", "text": "Geef Devin de referenties en concrete beperkingen, met een duidelijke definitie van klaar:"}, {"kind": "code", "lang": "bash", "code": "devin\n# in the prompt:\n> Implement the attached reference (desktop + mobile) in\n  React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the\n  references across breakpoints. Done = pixel-close on both\n  desktop and mobile with no console errors."}, {"kind": "p", "text": "Houd prompts gericht, commit goede iteraties en draai slechte terug (en vertel Devin wanneer je terugdraait), zodat elke ronde voortbouwt op een schone basis."}]}, {"id": "extend", "heading": "Projectregels, tools en cloud-overdracht", "blocks": [{"kind": "p", "text": "Drie uitbreidingspunten maken Devin for Terminal praktisch voor langdurig designwerk, en alle drie passen netjes op een open design-workflow."}, {"kind": "steps", "items": [{"label": "Projectregels en context", "body": "Bewaar je designconventies, tokens en reviewchecklists in de regels en docs van je project, zodat de agent ze elke ronde leest en werkt tegen je merk."}, {"label": "Codebase, tools en omgeving", "body": "Devin draait als een lokale agent met toegang tot je codebase, tools en omgeving — hij kan een dev-server draaien, de build uitvoeren en output verifiëren zonder de terminal te verlaten."}, {"label": "Gesandboxte cloud-overdracht", "body": "Draag een sessie over aan een cloud-agent in zijn eigen sandbox om langere builds, tests en PR-creatie asynchroon uit te voeren, en kom dan terug bij een afgeronde pull request."}]}, {"kind": "p", "text": "Dit zijn precies het soort overdraagbare, agent-vormige mogelijkheden die Open Design is gebouwd om te orkestreren, in plaats van per project opnieuw te creëren."}]}, {"id": "vs", "heading": "Devin vs Codex vs Claude Code vs Cursor vs Gemini CLI voor design", "blocks": [{"kind": "p", "text": "Er is geen enkele winnaar voor designwerk — elke agent heeft een ander sterk punt, en ervaren teams stapelen ze. Een eerlijke samenvatting:"}, {"kind": "table", "columns": ["Agent", "Designsterkte", "Best voor"], "rows": [["Devin", "Volledig autonome software-engineer; plant en voert meerstaps builds uit en draagt over aan een gesandboxte cloud-agent", "Het delegeren van end-to-end frontend-builds die blijven draaien nadat je weg bent"], ["Codex", "Sterke visuele afwerking met een frontend-skill; gesandboxte async builds", "Gedelegeerde async builds en overdraagbare AGENTS.md-regels"], ["Claude Code", "Specifieke designbeslissingen (hex, spacing, type) en codebase-bewuste UX", "Frontend-redenering en refactors met grote context"], ["Cursor", "Visuele bouw-en-zie-lus met live preview en inline bewerkingen", "Strak itereren-en-meekijken UI-werk binnen een IDE"], ["Gemini CLI", "Sterk multimodaal beeldbegrip en een context van 1M tokens; open-source met een gratis laag", "Screenshot-intensief werk en een heel designsysteem in context houden"]]}, {"kind": "p", "text": "Het terugkerende oordeel van de community is dat smaak van mensen komt: ze vallen allemaal terug op een generieke esthetiek zonder skills, referenties en beperkingen. Dat is het echte probleem om op te lossen — en het heeft de vorm van een designtool, niet van een model."}]}, {"id": "pitfalls", "heading": "Valkuilen, en hoe je de “AI-slop”-look vermijdt", "blocks": [{"kind": "p", "text": "De meest voorkomende klacht over door AI gegenereerd design is dat het er generiek uitziet — zachte gradiënten, zwevende panelen, overdreven afgeronde hoeken, dramatische schaduwen, een Inter-en-paars-sfeer die “schreeuwt dat een AI dit heeft gemaakt.” Andere gemelde problemen zijn kapotte mobiele lay-outs en instructies die in de UI-tekst lekken. Geen van deze is uniek voor Devin; ze zijn wat er gebeurt wanneer welke agent dan ook draait zonder een samengestelde designcontext."}, {"kind": "steps", "items": [{"label": "Voeg een esthetische skill toe", "body": "Een samengestelde design-skill dwingt de agent om zich vast te leggen op een echte richting in plaats van de standaard look."}, {"label": "Verifieer in een echte browser", "body": "Laat Devin renderen en zichzelf controleren over breakpoints heen zodat lay-outs niet stilletjes breken op mobiel."}, {"label": "Lever tokens en referenties aan", "body": "Echte design-tokens en referentie-screenshots zijn de grootste enkele hefboom op outputkwaliteit."}, {"label": "Codeer regels in projectcontext", "body": "Plaats stijlregels als “geen hero-cards, maximaal twee lettertypes, merk-eerst-hiërarchie” waar de agent ze elke ronde leest, met expliciete voltooiingscriteria."}]}, {"kind": "p", "text": "Merk op dat elke mitigatie gaat over het geven van een samengestelde designcontext aan de agent. Die context handmatig onderhouden, per project, is het zware werk dat Open Design wegneemt."}]}, {"id": "open-design", "heading": "Ontwerpen met Devin in Open Design", "blocks": [{"kind": "p", "text": "Open Design is de open-source designlaag waar de bovenstaande workflow steeds om vraagt. Het behandelt Devin for Terminal als een first-party adapter en wikkelt hem in een samengestelde bibliotheek van skills en designsystemen, een gestructureerde render-pijplijn en een lokale desktop-UI — zodat de designcontext die Devin goed maakt er vanaf de eerste ronde is, niet telkens handmatig samengesteld. Open Design is open-source en local-first, wat de combinatie een natuurlijke match maakt voor een agent die je al in je terminal draait."}, {"kind": "ol", "items": ["Installeer Open Design en selecteer Devin for Terminal als je agent.", "Authenticeer met je Devin (Cognition)-account — credentials worden rechtstreeks door je agent gebruikt en worden nooit via ons doorgesluisd.", "Kies een designsysteem en een skill, en genereer dan decks, prototypes en landingspagina's met consistente smaak.", "Elk artefact en DESIGN.md-bestand leeft in je eigen repo, niet in een gehoste cloud."]}, {"kind": "p", "text": "Dezelfde Devin-agent, hetzelfde account — plus een echte, overdraagbare, open-source design-workflow eromheen. Open Design is local-first en Apache-2.0, dus niets van je werk of je credentials verlaat je machine via ons."}]}], "faqTitle": "Veelgestelde vragen", "faq": [{"name": "Kan Devin for Terminal echt designwerk doen?", "text": "Ja — met een esthetische skill, een designsysteem en echte referentieafbeeldingen in context produceert Devin responsieve UI van productiekwaliteit, en als autonome agent kan hij het resultaat bouwen, draaien en verifiëren tegen je referenties. Zonder die context valt hij doorgaans terug op een generieke look, en dat is de kloof die Open Design dicht."}, {"name": "Hoe log ik in bij Devin?", "text": "Devin is account-gebaseerd: je logt in met een Devin (Cognition)-account in plaats van je eigen modelsleutel mee te brengen. Installeer Devin for Terminal, draai het in je project en authenticeer bij de eerste run. Open Design sluist je credentials nooit door — je agent gebruikt ze rechtstreeks."}, {"name": "Wat maakt Devin specifiek goed voor design?", "text": "Het is een volledig autonome software-engineer: hij plant en voert meerstaps frontend-builds van begin tot eind uit, en kan een sessie overdragen aan een gesandboxte cloud-agent die blijft werken nadat je weg bent. Smaak komt nog steeds van het designsysteem, de skill en de referenties die jij aanlevert."}, {"name": "Devin of Claude Code voor frontend-design?", "text": "Beide zijn sterk. Claude Code staat bekend om specifieke, codebase-bewuste designbeslissingen; het voordeel van Devin is volledig autonome, end-to-end uitvoering met een gesandboxte cloud-overdracht. Veel teams gebruiken beide — met Open Design kun je van agent wisselen zonder je design-workflow te veranderen."}, {"name": "Draait Devin in een sandbox?", "text": "Devin for Terminal draait lokaal met toegang tot je codebase en omgeving, en hij kan een sessie overdragen aan een cloud-agent die in zijn eigen gesandboxte omgeving draait — handig voor langere builds, tests en PR-creatie die asynchroon doorgaan."}, {"name": "Is Open Design verbonden met Cognition?", "text": "Nee. Devin for Terminal is een product van Cognition; Open Design is een onafhankelijk open-source project dat het ondersteunt als first-party adapter. Devin is een handelsmerk van Cognition."}, {"name": "Zijn mijn bestanden en credentials veilig?", "text": "Ja — Open Design is local-first en Apache-2.0. Je bestanden, artefacten en DESIGN.md blijven in je eigen repo, en je Devin-credentials worden rechtstreeks door je agent gebruikt, nooit gerouteerd via Open Design-servers."}], "ctaTitle": "Ontwerp met Devin, op de open manier.", "ctaBody": "Log in met je Devin-account, houd elk bestand lokaal, en krijg een samengestelde designbibliotheek rond de autonome agent die je al gebruikt.", "ctaActions": [{"label": "Gebruik Devin in Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Bekijk alle ondersteunde agents"},
      },
      'pi': {
        ...en['pi']!,
        title: "Pi voor design — Open Design",
        description: "Hoe mensen Pi, de open-source multi-provider terminal-codingagent, gebruiken voor UI- en webdesign — zijn any-model-routing, BYOK-providersleutels, Skills en Extensions — en hoe Open Design Pi verandert in een local-first, open-source design-agent.",
        breadcrumb: "Pi",
        label: "Agent · Pi",
        heading: "Pi voor design.",
        lead: "Pi is een open-source terminal-codingagent die naar elk model routeert — Anthropic, OpenAI, Google en 20+ providers — op je eigen API-sleutels. Die provider-onafhankelijke kern maakt hem een flexibel designtool: kies het model dat vandaag het beste screenshots leest, wissel morgen, behoud je workflow. Open Design verbindt hem met een open-source design-workflow: je providersleutels, je bestanden, local-first.",
        rich: {"heroCtaLead": "Open Design verandert Pi in een local-first, open-source design-agent — je eigen provider-API-sleutels, je bestanden, een samengestelde bibliotheek van skills en designsystemen eromheen.", "heroCtaActions": [{"label": "Gebruik Pi in Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Pi is een open-source (MIT) AI-codingagent voor de terminal. Wat hem specifiek interessant maakt voor design is dat hij provider-onafhankelijk is: hij normaliseert over Anthropic, OpenAI, Google en 20-plus andere providers achter één interface, zodat je authenticeert met je eigen API-sleutels (BYOK) en het model kiest dat bij de taak past — en je kunt midden in een sessie van model wisselen zonder de tool opnieuw te leren. Gecombineerd met de juiste referenties, conventies en een verificatielus bouwt hij echte, responsieve UI. Dit is een praktische, end-to-end gids voor het gebruik van Pi voor UI-, frontend- en designsysteemwerk, en voor het inbedden ervan in een gestructureerde design-workflow met Open Design.", "Het behandelt wat Pi eigenlijk is, waarom een multi-provider BYOK-agent bij design past, hoe je hem vanaf nul opzet, de screenshot-naar-UI-lus, hoe Skills en Extensions hem uitbreiden, hoe hij zich verhoudt tot Codex, Claude Code, Cursor en Gemini CLI, de valkuilen die AI-output generiek doen lijken, en hoe Open Design de kloof dicht als een open, local-first designlaag — een natuurlijke combinatie, want beide zijn open-source en draaien op je eigen machine."], "heroImage": {"src": "/agents/pi-design/pi-design-hero.webp", "alt": "Pi design-feedbacklus: een terminal-agent die een referentieafbeelding leest, een browser die de UI rendert, en een werkruimte, met een feedbackpijl die terugloopt", "caption": "De kernlus: Pi leest je referenties in de terminal, bouwt en verifieert de UI in een echte browser, en itereert daartegen — op welke provider je hem ook wijst."}, "tocLabel": "Op deze pagina", "toc": [{"id": "what-is-pi", "label": "Wat Pi eigenlijk is"}, {"id": "why-design", "label": "Waarom een multi-provider BYOK-agent bij design past"}, {"id": "setup", "label": "Pi opzetten voor design (vanaf nul)"}, {"id": "screenshot-workflow", "label": "De screenshot-naar-UI-workflow"}, {"id": "extend", "label": "Skills, Extensions en thema's"}, {"id": "vs", "label": "Pi vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Valkuilen en de “AI-slop”-look"}, {"id": "open-design", "label": "Ontwerpen met Pi in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-pi", "heading": "Wat Pi eigenlijk is", "blocks": [{"kind": "p", "text": "Pi is een open-source (MIT) AI-codingagent voor de terminal, onderdeel van de earendil-works pi-toolkit. Hij leest je repository, bewerkt bestanden en voert shell-opdrachten uit — hij plant en verifieert werk vanuit taken in natuurlijke taal in plaats van alleen regels aan te vullen. Zijn kern is bewust klein: vier standaardtools — read, write, edit en bash — plus ingebouwde grep, find en ls."}, {"kind": "p", "text": "Voor designwerk is de opvallendste eigenschap dat Pi provider-onafhankelijk is. Hij normaliseert over Anthropic, OpenAI, Google en vele andere providers achter één uniforme API, zodat je je eigen sleutels meebrengt en het model per taak kiest — bijvoorbeeld een sterk multimodaal model om referentie-screenshots te lezen — en wisselt met /model of Ctrl+L midden in een sessie zonder je workflow te veranderen."}, {"kind": "steps", "items": [{"label": "Elk model, je sleutels", "body": "Pi routeert naar 20+ providers waaronder Anthropic en OpenAI. Je authenticeert met je eigen API-sleutels (BYOK), of logt in op een Claude Pro/Max-, ChatGPT Plus/Pro- of GitHub Copilot-abonnement met /login."}, {"label": "Skills + Extensions", "body": "Pi laadt Skills (Markdown-capability-pakketten die de Agent Skills-standaard volgen) en TypeScript-Extensions — de natuurlijke plek om je designconventies te coderen en aangepaste tools toe te voegen."}, {"label": "Vertakkende sessies", "body": "Sessies worden opgeslagen als JSONL-bomen, zodat je een verkenning kunt vertakken en door de geschiedenis kunt navigeren in één bestand zonder eerdere rondes te verliezen."}]}, {"kind": "ul", "items": ["Leverancier: earendil-works (open-source communityproject)", "Credential: je eigen provider-API-sleutel (BYOK — Anthropic, OpenAI, Google, enz.) of een abonnements-login via /login; lokaal opgeslagen in ~/.pi/agent/auth.json (0600)", "Licentie: MIT, open source"]}]}, {"id": "why-design", "heading": "Waarom een multi-provider, BYOK-agent bij design past", "blocks": [{"kind": "p", "text": "Pi's designvoordeel is flexibiliteit, niet één ingebouwd model — maar, zoals bij elke agent, smaak moet nog steeds worden aangeleverd."}, {"kind": "steps", "items": [{"label": "Kies het juiste model per taak", "body": "Omdat Pi naar elke provider routeert, kun je grijpen naar een sterk multimodaal model om referentie-screenshots te lezen, en dan wisselen naar een ander voor refactoring — zonder de agent te verlaten."}, {"label": "Je sleutels, geen lock-in", "body": "BYOK betekent dat je niet vastzit aan de prijzen of contextlimieten van één leverancier; kies het model waarvan de sterke punten passen bij de designklus voor je."}, {"label": "Conventies in Skills", "body": "Een Skill (plus een MCP-bron zoals een Figma-server) wijst de agent op je tokens, componenten en echte specificaties, zodat hij werkt tegen een merk in plaats van een standaard look."}]}, {"kind": "image", "src": "/agents/pi-design/pi-design-taste-triangle.webp", "alt": "Diagram dat toont hoe designsysteem, skill en referentieafbeelding samenkomen tot goede design-output", "caption": "Smaak komt voort uit drie inputs die jij aanlevert: een designsysteem, een skill en echte referentieafbeeldingen."}, {"kind": "p", "text": "De les is dezelfde die elke agent leert: Pi heeft standaard geen smaak, en geen modelkeuze levert die. Hij produceert goed design wanneer je hem beperkingen geeft — een designsysteem, een esthetische skill en concrete referenties. Open Design verpakt precies die inputs, en daarom passen de twee bij elkaar (meer hieronder)."}]}, {"id": "setup", "heading": "Pi opzetten voor designwerk, vanaf nul", "blocks": [{"kind": "p", "text": "Hier is het volledige pad van een schone machine naar een Pi die UI kan bouwen en verifiëren."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Pi coding agent CLI (Node)\nnpm install -g --ignore-scripts @earendil-works/pi-coding-agent\n\n# 2. Authenticate with your own provider key (BYOK)\nexport ANTHROPIC_API_KEY=sk-ant-...   # or OPENAI_API_KEY=sk-...\n#    (or run /login inside Pi for a Claude / ChatGPT / Copilot subscription)\n\n# 3. Start it in your project\ncd your-project\npi\n\n# 4. Switch models any time with /model or Ctrl+L"}, {"kind": "image", "src": "/agents/pi-design/pi-design-setup-flow.webp", "alt": "Stappenplan in vijf stappen: installeren, authenticeren, designregels coderen, een skill toevoegen, verifiëren", "caption": "De opzetvolgorde: installeren → authenticeren (BYOK) → designregels coderen in een Skill → een model kiezen → browserverificatie inschakelen."}, {"kind": "steps", "items": [{"label": "Codeer je designregels", "body": "Plaats je tokens, primitieven en conventies in een Skill en wijs Pi erop, zodat output overeenkomt met een merk in plaats van terug te vallen op een generieke look."}, {"label": "Voeg browserverificatie toe", "body": "Bedraad een Playwright- of browser-MCP zodat Pi rendert in een echte browser en zijn output controleert over breakpoints heen in plaats van alleen te bevestigen dat de build slaagt."}]}]}, {"id": "screenshot-workflow", "heading": "De screenshot-naar-UI-workflow", "blocks": [{"kind": "p", "text": "De designlus met de meeste hefboomwerking met Pi is het omzetten van een referentieafbeelding in werkende, responsieve UI en daarop itereren tot het overeenkomt — leunend op een multimodaal model om output te vergelijken met de referentie. Omdat Pi provider-onafhankelijk is, wijs hem op welk model voor deze ronde ook het beste afbeeldingen leest."}, {"kind": "ol", "items": ["Begin met de duidelijkste visuele referenties die je hebt — en neem meerdere staten mee (desktop en mobiel, hover, leeg, laden), niet slechts één hero-shot.", "Kies met /model een sterk multimodaal model voor de ronde, want beeldbegrip is wat de screenshot-naar-UI-kwaliteit aandrijft.", "Wees specifiek in de prompt; vage prompts leveren generieke UI op, zelfs met een sterk model.", "Bewaar je designsysteem en conventies in een Skill, en vertel Pi waar de tokens en canonieke primitieven leven.", "Draai een dev-server en laat Pi renderen in een echte browser, met formaataanpassing naar breakpoints, en itereer dan door zijn implementatie te vergelijken met de screenshots — niet alleen bevestigen dat het bouwt."]}, {"kind": "p", "text": "Geef de agent vooraf de referenties en concrete beperkingen:"}, {"kind": "code", "lang": "bash", "code": "pi\n# in the prompt:\n> Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens (see the Skill).\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Houd prompts klein en gericht, commit goede iteraties en draai slechte terug (en vertel Pi wanneer je terugdraait), zodat elke ronde voortbouwt op een schone basis. Pi's vertakkende JSONL-sessies laten je ook een alternatief verkennen zonder de oorspronkelijke draad te verliezen."}]}, {"id": "extend", "heading": "Skills, Extensions en thema's", "blocks": [{"kind": "p", "text": "Pi breidt zichzelf tijdens runtime uit via een paar lagen, en die passen netjes op een open design-workflow."}, {"kind": "steps", "items": [{"label": "Skills", "body": "Markdown-capability-pakketten die de Agent Skills-standaard volgen — de duurzame, overdraagbare thuisbasis voor je designconventies, tokens en reviewchecklists. Dezelfde Skill werkt over compatibele agents heen, niet alleen Pi."}, {"label": "Extensions en prompt-sjablonen", "body": "TypeScript-Extensions voegen aangepaste tools, commando's en UI toe; herbruikbare prompt-sjablonen draaien via /name. Beide laten je de verificatielus scripten zonder de terminal te verlaten."}, {"label": "MCP en thema's", "body": "Pi verbindt met MCP-servers om externe designcontext binnen te halen (het meest relevant een Figma MCP-server), en thema's herladen direct zodat de terminal-UI leesbaar blijft terwijl je werkt."}]}, {"kind": "p", "text": "Dit zijn overdraagbare mogelijkheden — vooral Skills en MCP — precies het soort dingen die Open Design is gebouwd om te orkestreren, in plaats van per project opnieuw te creëren."}]}, {"id": "vs", "heading": "Pi vs Codex vs Claude Code vs Cursor vs Gemini CLI voor design", "blocks": [{"kind": "p", "text": "Er is geen enkele winnaar voor designwerk — elke agent heeft een ander sterk punt, en ervaren teams stapelen ze. Een eerlijke samenvatting:"}, {"kind": "table", "columns": ["Agent", "Designsterkte", "Best voor"], "rows": [["Pi", "Provider-onafhankelijk en BYOK — routeer naar elk model (Anthropic, OpenAI, Google…) en wissel midden in een sessie; MIT, zelf-uitbreidbaar", "Het beste model per taak kiezen zonder vendor lock-in"], ["Codex", "Sterke visuele afwerking met een frontend-skill; gesandboxte async builds", "Gedelegeerde async builds en overdraagbare AGENTS.md-regels"], ["Claude Code", "Specifieke designbeslissingen (hex, spacing, type) en codebase-bewuste UX", "Frontend-redenering en refactors met grote context"], ["Cursor", "Visuele bouw-en-zie-lus met live preview en inline bewerkingen", "Strak itereren-en-meekijken UI-werk binnen een IDE"], ["Gemini CLI", "Sterk multimodaal beeldbegrip en een context van 1M tokens; gratis laag", "Screenshot-intensief werk en een heel designsysteem in context houden"]]}, {"kind": "p", "text": "Pi's invalshoek staat haaks op de andere: hij is de agent die je elk van die onderliggende modellen op je eigen sleutels laat gebruiken. Het terugkerende oordeel van de community geldt nog steeds — smaak komt van mensen: ze vallen allemaal terug op een generieke esthetiek zonder skills, referenties en beperkingen. Dat is het echte probleem om op te lossen, en het heeft de vorm van een designtool, niet van een model."}]}, {"id": "pitfalls", "heading": "Valkuilen, en hoe je de “AI-slop”-look vermijdt", "blocks": [{"kind": "p", "text": "De meest voorkomende klacht over door AI gegenereerd design is dat het er generiek uitziet — zachte gradiënten, zwevende panelen, overdreven afgeronde hoeken, dramatische schaduwen, een Inter-en-paars-sfeer die “schreeuwt dat een AI dit heeft gemaakt.” Andere gemelde problemen zijn kapotte mobiele lay-outs en instructies die in de UI-tekst lekken. Geen van deze is uniek voor Pi of voor enig model; ze zijn wat er gebeurt wanneer welke agent dan ook draait zonder een samengestelde designcontext."}, {"kind": "steps", "items": [{"label": "Voeg een esthetische skill toe", "body": "Een samengestelde design-skill dwingt de agent om zich vast te leggen op een echte richting in plaats van de standaard look — en omdat het een overdraagbare Skill is, reist hij met je mee over modellen heen."}, {"label": "Verifieer in een echte browser", "body": "Kies een multimodaal model en laat Pi renderen en zichzelf controleren over breakpoints heen zodat lay-outs niet stilletjes breken op mobiel."}, {"label": "Lever tokens en referenties aan", "body": "Echte design-tokens en referentie-screenshots zijn de grootste enkele hefboom op outputkwaliteit."}, {"label": "Codeer regels waar Pi ze leest", "body": "Plaats stijlregels als “geen hero-cards, maximaal twee lettertypes, merk-eerst-hiërarchie” in een Skill die de agent elke ronde laadt."}]}, {"kind": "p", "text": "Merk op dat elke mitigatie gaat over het geven van een samengestelde designcontext aan de agent — onafhankelijk van naar welke provider je routeert. Die context handmatig onderhouden, per project, is het zware werk dat Open Design wegneemt."}]}, {"id": "open-design", "heading": "Ontwerpen met Pi in Open Design", "blocks": [{"kind": "p", "text": "Open Design is de open-source designlaag waar de bovenstaande workflow steeds om vraagt. Het behandelt Pi als een first-party adapter en wikkelt hem in een samengestelde bibliotheek van skills en designsystemen, een gestructureerde render-pijplijn en een lokale desktop-UI — zodat de designcontext die Pi goed maakt er vanaf de eerste ronde is, niet telkens handmatig samengesteld. Beide zijn open-source en local-first, wat de combinatie een natuurlijke match maakt."}, {"kind": "ol", "items": ["Installeer Open Design en selecteer Pi als je agent.", "Authenticeer met je eigen provider-API-sleutel (BYOK) of een abonnements-login — credentials blijven op je machine in ~/.pi/agent/auth.json en worden nooit via ons doorgesluisd.", "Kies een designsysteem en een skill, en genereer dan decks, prototypes en landingspagina's met consistente smaak.", "Elk artefact en DESIGN.md-bestand leeft in je eigen repo, niet in een gehoste cloud."]}, {"kind": "p", "text": "Dezelfde Pi-agent, dezelfde sleutels, dezelfde vrijheid om van model te wisselen — plus een echte, overdraagbare, open-source design-workflow eromheen. Het is local-first en MIT, dus niets van je werk of je credentials verlaat je machine."}]}], "faqTitle": "Veelgestelde vragen", "faq": [{"name": "Kan Pi echt designwerk doen?", "text": "Ja — met een esthetische skill, een designsysteem en echte referentieafbeeldingen in context produceert Pi responsieve UI van productiekwaliteit, en je kunt hem routeren naar een sterk multimodaal model om output te verifiëren tegen referenties. Zonder die context valt hij doorgaans terug op een generieke look, en dat is de kloof die Open Design dicht."}, {"name": "Moet ik betalen om met Pi te ontwerpen?", "text": "Pi zelf is gratis en open source (MIT). Je betaalt alleen voor het onderliggende model — breng je eigen provider-API-sleutel mee (BYOK), of gebruik een Claude Pro/Max-, ChatGPT Plus/Pro- of GitHub Copilot-abonnement via /login. Open Design sluist je credentials sowieso nooit door."}, {"name": "Wat maakt Pi specifiek goed voor design?", "text": "Hij is provider-onafhankelijk: je brengt je eigen sleutels mee en routeert naar elk van 20+ providers, en kiest het model waarvan de sterke punten bij de taak passen en wisselt midden in een sessie. Maar smaak komt nog steeds van het designsysteem, de skill en de referenties die jij aanlevert, niet van het model."}, {"name": "Welk model moet ik met Pi gebruiken voor frontend-design?", "text": "Pi routeert naar veel providers, dus kies per taak — een sterk multimodaal model leest referentie-screenshots goed, terwijl andere geschikt kunnen zijn voor refactoring. Het voordeel van Pi is dat je kunt wisselen zonder je workflow te veranderen. Met Open Design behoud je dezelfde designcontext over welk model je ook kiest."}, {"name": "Hoe verbind ik Pi met Figma?", "text": "Pi ondersteunt MCP-servers, zodat je een Figma MCP-server kunt toevoegen en echte designcontext kunt binnenhalen — componenten, variabelen, lay-outdata — zodat de gegenereerde code overeenkomt met de bron in plaats van die te benaderen."}, {"name": "Is Open Design verbonden met Pi?", "text": "Nee. Pi is een onafhankelijk open-source project van earendil-works; Open Design is een apart onafhankelijk open-source project dat Pi ondersteunt als first-party adapter."}, {"name": "Zijn mijn bestanden en credentials veilig?", "text": "Ja — Open Design is local-first en open source. Je bestanden, artefacten en DESIGN.md blijven in je eigen repo, en je providersleutels worden rechtstreeks door Pi gebruikt (lokaal opgeslagen in ~/.pi/agent/auth.json), nooit gerouteerd via Open Design-servers."}], "ctaTitle": "Ontwerp met Pi, op de open manier.", "ctaBody": "Breng je eigen providersleutels mee, routeer naar elk model, houd elk bestand lokaal, en krijg een samengestelde designbibliotheek rond de agent die je al gebruikt.", "ctaActions": [{"label": "Gebruik Pi in Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Bekijk alle ondersteunde agents"},
      },
      'kiro': {
        ...en['kiro']!,
        title: "Kiro CLI voor design — Open Design",
        description: "Hoe mensen Amazon's Kiro CLI gebruiken voor UI- en webdesign — zijn spec-gestuurde ontwikkeling, agent hooks, steering files en MCP — en hoe Open Design Kiro CLI verandert in een local-first, open-source design-agent.",
        breadcrumb: "Kiro CLI",
        label: "Agent · Kiro CLI",
        heading: "Kiro CLI voor design.",
        lead: "Kiro CLI is Amazon's terminal-agent voor spec-gestuurde ontwikkeling — hij verandert een prompt in een requirements-spec, een designdocument en een takenlijst voordat hij code schrijft. Die structuur is precies wat designwerk nodig heeft: intentie eerst, dan bouwen. Open Design verbindt hem met een open-source design-workflow: je Builder ID of aanmelding, je bestanden, local-first.",
        rich: {"heroCtaLead": "Open Design verandert Kiro CLI in een local-first, open-source design-agent — je AWS Builder ID of aanmelding, je bestanden, een samengestelde bibliotheek van skills en designsystemen eromheen.", "heroCtaActions": [{"label": "Gebruik Kiro CLI in Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Kiro CLI is Amazon's terminal-agent voor spec-gestuurde ontwikkeling. Wat hem onderscheidt is de workflow: in plaats van rechtstreeks van een prompt naar code te springen, formaliseert Kiro requirements in een spec, produceert een designdocument en een gesequenceerde takenlijst, en implementeert pas daarna — waarbij de bouw verantwoordelijk blijft tegenover de uitgesproken intentie. Hij wordt ook geleverd met agent hooks die afgaan op gebeurtenissen zoals het opslaan van een bestand, steering files die je standaarden en conventies in elke run dragen, en ondersteuning voor het Model Context Protocol voor externe tools. Kiro is in preview, beschikbaar als een IDE, een CLI en een webinterface, en je kunt gratis starten. Dit is een praktische, end-to-end gids voor het gebruik van Kiro CLI voor UI-, frontend- en designsysteemwerk, en voor het inbedden ervan in een gestructureerde design-workflow met Open Design.", "Het behandelt wat Kiro CLI eigenlijk is, waarom een spec-gestuurde workflow bij design past, hoe je hem vanaf nul opzet, de screenshot-naar-UI-lus, hoe steering, hooks en MCP hem uitbreiden, hoe hij zich verhoudt tot Codex, Claude Code, Cursor en Gemini CLI, de valkuilen die AI-output generiek doen lijken, en hoe Open Design de kloof dicht als een open, local-first designlaag eromheen."], "heroImage": {"src": "/agents/kiro-design/kiro-design-hero.webp", "alt": "Kiro CLI design-feedbacklus: een terminal-agent die een spec in een design verandert, een browser die de UI rendert, en een werkruimte, met een feedbackpijl die terugloopt", "caption": "De kernlus: Kiro CLI verandert je intentie in een spec en een takenlijst in de terminal, bouwt en verifieert de UI in een echte browser, en itereert tegen je referenties."}, "tocLabel": "Op deze pagina", "toc": [{"id": "what-is-kiro", "label": "Wat Kiro CLI eigenlijk is"}, {"id": "why-design", "label": "Waarom spec-gestuurde ontwikkeling bij design past"}, {"id": "setup", "label": "Kiro CLI opzetten voor design (vanaf nul)"}, {"id": "screenshot-workflow", "label": "De screenshot-naar-UI-workflow"}, {"id": "extend", "label": "Specs, steering, hooks en MCP"}, {"id": "vs", "label": "Kiro vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Valkuilen en de “AI-slop”-look"}, {"id": "open-design", "label": "Ontwerpen met Kiro CLI in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-kiro", "heading": "Wat Kiro CLI eigenlijk is", "blocks": [{"kind": "p", "text": "Kiro is een agentische AI van Amazon die wordt geleverd als een IDE, een command-line-interface en een webinterface, gebouwd om je van prototype naar productie te brengen met spec-gestuurde ontwikkeling. De Kiro CLI brengt die agent naar je terminal: je kunt een interactieve chatsessie starten, agents maken en beheren, en Model Context Protocol-servers draaien — allemaal vanaf de command line. Kiro is in preview."}, {"kind": "p", "text": "Voor designwerk is de bepalende eigenschap de workflow. In plaats van een prompt rechtstreeks in code te veranderen, schrijft Kiro eerst een spec — requirements, een designdocument en een gesequenceerde takenlijst — en implementeert daartegen. Dat maakt het plan van de agent zichtbaar en te reviewen voordat er UI wordt gebouwd, wat netjes overeenkomt met hoe designbeslissingen genomen zouden moeten worden: intentie eerst, dan uitvoering."}, {"kind": "steps", "items": [{"label": "Specs", "body": "Kiro verandert een prompt in een gestructureerde spec — requirements, een designdocument en discrete taken — voordat hij code schrijft, zodat het plan vooraf te reviewen is."}, {"label": "Steering + hooks", "body": "Steering files dragen je standaarden, conventies en voorkeurstools in elke run; agent hooks gaan af op gebeurtenissen zoals het opslaan van een bestand om achtergrondtaken automatisch uit te voeren."}, {"label": "Gratis om te starten, MCP-klaar", "body": "Log in met een Builder ID, Google, GitHub of je organisatie en start gratis; Kiro CLI beheert ook MCP-servers om externe context binnen te halen."}]}, {"kind": "ul", "items": ["Leverancier: Amazon (AWS)", "Credential: AWS Builder ID, Google, GitHub of AWS IAM Identity Center via kiro-cli login (geen AWS-account vereist)", "Status: In preview; beschikbaar als IDE, CLI en webinterface"]}]}, {"id": "why-design", "heading": "Waarom spec-gestuurde ontwikkeling bij design past", "blocks": [{"kind": "p", "text": "Kiro CLI's designvoordeel komt voort uit zijn workflow — maar, zoals bij elke agent, smaak moet nog steeds worden aangeleverd."}, {"kind": "steps", "items": [{"label": "Intentie vóór pixels", "body": "Omdat Kiro eerst een spec en een designdocument schrijft, kun je lay-out, hiërarchie en scope corrigeren in de planningsfase — voordat de agent zich heeft vastgelegd op een generieke implementatie."}, {"label": "Steering draagt je merk", "body": "Steering files houden je tokens, componenten en conventies bij elke run voor de agent, zodat output werkt tegen een merk in plaats van een standaard look."}, {"label": "Hooks dwingen de lus af", "body": "Agent hooks kunnen automatisch controles uitvoeren bij opslaan — een plek om een verificatie- of reviewstap in te bedraden in plaats van te vertrouwen op het geheugen van de agent."}]}, {"kind": "image", "src": "/agents/kiro-design/kiro-design-taste-triangle.webp", "alt": "Diagram dat toont hoe designsysteem, skill en referentieafbeelding samenkomen tot goede design-output", "caption": "Smaak komt voort uit drie inputs die jij aanlevert: een designsysteem, een skill en echte referentieafbeeldingen."}, {"kind": "p", "text": "De les is dezelfde die elke agent leert: Kiro CLI heeft standaard geen smaak. Een spec houdt een bouw eerlijk, maar hij produceert alleen goed design wanneer je hem beperkingen geeft — een designsysteem, een esthetische skill en concrete referenties. Open Design verpakt precies die inputs, en daarom passen de twee bij elkaar (meer hieronder)."}]}, {"id": "setup", "heading": "Kiro CLI opzetten voor designwerk, vanaf nul", "blocks": [{"kind": "p", "text": "Hier is het volledige pad van een schone machine naar een Kiro CLI die UI kan bouwen en verifiëren."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Kiro CLI (see kiro.dev/docs/cli for the macOS/Linux/Windows command)\n\n# 2. Authenticate — opens your browser to complete sign-in\nkiro-cli login   # choose Builder ID, Google, GitHub, or your organization\n\n# 3. Confirm you are signed in\nkiro-cli whoami\n\n# 4. Start an interactive session in your project\ncd your-project\nkiro-cli chat\n\n# 5. Wire MCP servers (optional, e.g. for design handoff)\nkiro-cli mcp add ..."}, {"kind": "image", "src": "/agents/kiro-design/kiro-design-setup-flow.webp", "alt": "Stappenplan in vijf stappen: installeren, authenticeren, steering toevoegen, een skill toevoegen, verifiëren", "caption": "De opzetvolgorde: installeren → authenticeren → steering en een design-spec toevoegen → een skill toevoegen → browserverificatie inschakelen."}, {"kind": "steps", "items": [{"label": "Codeer je designregels", "body": "Plaats je tokens, primitieven en conventies in steering files zodat de agent ze elke run leest, en output overeenkomt met een merk in plaats van terug te vallen op een generieke look."}, {"label": "Voeg browserverificatie toe", "body": "Bedraad een Playwright- of browser-MCP-server zodat Kiro rendert in een echte browser en zijn output controleert over breakpoints heen in plaats van alleen te bevestigen dat de build slaagt."}]}]}, {"id": "screenshot-workflow", "heading": "De screenshot-naar-UI-workflow", "blocks": [{"kind": "p", "text": "De designlus met de meeste hefboomwerking met Kiro CLI is het omzetten van een referentieafbeelding in werkende, responsieve UI en daarop itereren tot het overeenkomt — door de spec eerst de intentie te laten vastleggen, en dan daartegen te bouwen."}, {"kind": "ol", "items": ["Begin met de duidelijkste visuele referenties die je hebt — en neem meerdere staten mee (desktop en mobiel, hover, leeg, laden), niet slechts één hero-shot.", "Laat Kiro een spec en designdocument schrijven vanuit je prompt, en review het plan voordat hij bouwt — dit is waar je lay-out- en scope-problemen vroeg vangt.", "Bewaar je designsysteem en conventies in steering files, en vertel Kiro waar de tokens en canonieke primitieven leven.", "Draai een dev-server en laat Kiro renderen in een echte browser, met formaataanpassing naar breakpoints om het resultaat te controleren.", "Itereer door Kiro zijn implementatie te laten vergelijken met de referenties — niet alleen bevestigen dat het bouwt."]}, {"kind": "p", "text": "Open een interactieve sessie en geef vooraf concrete beperkingen, zodat de spec die hij schrijft je echte intentie weerspiegelt:"}, {"kind": "code", "lang": "bash", "code": "kiro-cli chat\n# in the prompt:\n> Here are my references: reference-desktop.png and reference-mobile.png.\n  Write a spec, then implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens (see my steering files).\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Houd taken klein en gericht, commit goede iteraties en draai slechte terug (en vertel Kiro wanneer je terugdraait), zodat elke ronde voortbouwt op een schone basis."}]}, {"id": "extend", "heading": "Specs, steering, hooks en MCP", "blocks": [{"kind": "p", "text": "Vier uitbreidingspunten maken Kiro CLI praktisch voor langdurig designwerk, en alle vier passen netjes op een open design-workflow."}, {"kind": "steps", "items": [{"label": "Specs", "body": "Requirements, een designdocument en een gesequenceerde takenlijst — het duurzame verslag van wat een feature moet zijn, te reviewen voor en tijdens de bouw."}, {"label": "Steering files", "body": "Voeg context, codestandaarden en voorkeurs-workflows of -tools toe die de agent elke run leest — de natuurlijke thuisbasis voor je designconventies en tokens."}, {"label": "Agent hooks", "body": "Automatiseringen die afgaan op gebeurtenissen zoals het opslaan van een bestand, en achtergrondtaken zoals controles of docs uitvoeren — een plek om een verificatiestap automatisch af te dwingen."}, {"label": "MCP-servers", "body": "Kiro CLI beheert Model Context Protocol-servers, de overdraagbare manier om externe designcontext en tools binnen te halen die over agents heen werken, niet alleen Kiro."}]}, {"kind": "p", "text": "Dit zijn overdraagbare, multi-agent-mogelijkheden — precies het soort dingen die Open Design is gebouwd om te orkestreren, in plaats van per project opnieuw te creëren."}]}, {"id": "vs", "heading": "Kiro vs Codex vs Claude Code vs Cursor vs Gemini CLI voor design", "blocks": [{"kind": "p", "text": "Er is geen enkele winnaar voor designwerk — elke agent heeft een ander sterk punt, en ervaren teams stapelen ze. Een eerlijke samenvatting:"}, {"kind": "table", "columns": ["Agent", "Designsterkte", "Best voor"], "rows": [["Kiro CLI", "Spec-gestuurde workflow — requirements, designdocument en takenlijst vóór code; steering files en hooks houden builds on-brand", "Gestructureerde, te reviewen builds waarbij intentie en scope worden vastgelegd vóór implementatie"], ["Codex", "Sterke visuele afwerking met een frontend-skill; gesandboxte async builds", "Gedelegeerde async builds en overdraagbare AGENTS.md-regels"], ["Claude Code", "Specifieke designbeslissingen (hex, spacing, type) en codebase-bewuste UX", "Frontend-redenering en refactors met grote context"], ["Cursor", "Visuele bouw-en-zie-lus met live preview en inline bewerkingen", "Strak itereren-en-meekijken UI-werk binnen een IDE"], ["Gemini CLI", "Sterk multimodaal beeldbegrip en een zeer grote context; open-source met een gratis laag", "Screenshot-intensief werk en een heel designsysteem in context houden"]]}, {"kind": "p", "text": "Het terugkerende oordeel van de community is dat smaak van mensen komt: ze vallen allemaal terug op een generieke esthetiek zonder skills, referenties en beperkingen. Dat is het echte probleem om op te lossen — en het heeft de vorm van een designtool, niet van een model."}]}, {"id": "pitfalls", "heading": "Valkuilen, en hoe je de “AI-slop”-look vermijdt", "blocks": [{"kind": "p", "text": "De meest voorkomende klacht over door AI gegenereerd design is dat het er generiek uitziet — zachte gradiënten, zwevende panelen, overdreven afgeronde hoeken, dramatische schaduwen, een Inter-en-paars-sfeer die “schreeuwt dat een AI dit heeft gemaakt.” Andere gemelde problemen zijn kapotte mobiele lay-outs en instructies die in de UI-tekst lekken. Geen van deze is uniek voor Kiro CLI; ze zijn wat er gebeurt wanneer welke agent dan ook draait zonder een samengestelde designcontext — een spec houdt een bouw on-task, maar hij levert geen smaak."}, {"kind": "steps", "items": [{"label": "Voeg een esthetische skill toe", "body": "Een samengestelde design-skill dwingt de agent om zich vast te leggen op een echte richting in plaats van de standaard look."}, {"label": "Verifieer in een echte browser", "body": "Render en controleer zichzelf over breakpoints heen — bedraad het als een hook als je kunt — zodat lay-outs niet stilletjes breken op mobiel."}, {"label": "Lever tokens en referenties aan", "body": "Echte design-tokens en referentie-screenshots zijn de grootste enkele hefboom op outputkwaliteit."}, {"label": "Codeer regels in steering files", "body": "Plaats stijlregels als “geen hero-cards, maximaal twee lettertypes, merk-eerst-hiërarchie” waar de agent ze elke run leest."}]}, {"kind": "p", "text": "Merk op dat elke mitigatie gaat over het geven van een samengestelde designcontext aan de agent. Die context handmatig onderhouden, per project, is het zware werk dat Open Design wegneemt."}]}, {"id": "open-design", "heading": "Ontwerpen met Kiro CLI in Open Design", "blocks": [{"kind": "p", "text": "Open Design is de open-source designlaag waar de bovenstaande workflow steeds om vraagt. Het behandelt Kiro CLI als een first-party adapter en wikkelt hem in een samengestelde bibliotheek van skills en designsystemen, een gestructureerde render-pijplijn en een lokale desktop-UI — zodat de designcontext die Kiro goed maakt er vanaf de eerste ronde is, niet telkens handmatig samengesteld. Open Design is local-first, wat de combinatie simpel houdt: je bestanden en je aanmelding blijven op je machine."}, {"kind": "ol", "items": ["Installeer Open Design en selecteer Kiro CLI als je agent.", "Authenticeer met je AWS Builder ID of andere aanmelding — credentials blijven op je machine en worden nooit via ons doorgesluisd.", "Kies een designsysteem en een skill, en genereer dan decks, prototypes en landingspagina's met consistente smaak.", "Elk artefact en DESIGN.md-bestand leeft in je eigen repo, niet in een gehoste cloud."]}, {"kind": "p", "text": "Dezelfde Kiro CLI-agent, dezelfde aanmelding — plus een echte, overdraagbare, open-source design-workflow eromheen. Open Design is local-first en Apache-2.0, dus niets van je werk of je credentials verlaat je machine."}]}], "faqTitle": "Veelgestelde vragen", "faq": [{"name": "Kan Kiro CLI echt designwerk doen?", "text": "Ja — met een esthetische skill, een designsysteem en echte referentieafbeeldingen in context produceert Kiro CLI responsieve UI van productiekwaliteit, en zijn spec-gestuurde workflow houdt de bouw verantwoordelijk tegenover de uitgesproken intentie. Zonder die context valt hij doorgaans terug op een generieke look, en dat is de kloof die Open Design dicht."}, {"name": "Heb ik een AWS-account nodig om Kiro CLI te gebruiken?", "text": "Nee — Kiro laat je inloggen met een AWS Builder ID, Google, GitHub of je organisatie (AWS IAM Identity Center), en je hebt geen AWS-account nodig om het te gebruiken. Kiro is in preview en gratis om te starten. Open Design sluist je credentials sowieso nooit door."}, {"name": "Wat maakt Kiro CLI specifiek goed voor design?", "text": "Zijn spec-gestuurde workflow: Kiro schrijft requirements, een designdocument en een takenlijst voordat hij codeert, zodat je lay-out en scope corrigeert voordat de bouw zich vastlegt. Steering files dragen je conventies en hooks kunnen controles afdwingen — maar smaak komt nog steeds van het designsysteem, de skill en de referenties die jij aanlevert."}, {"name": "Kiro CLI of Claude Code voor frontend-design?", "text": "Beide zijn sterk. Claude Code staat bekend om specifieke, codebase-bewuste designbeslissingen; het voordeel van Kiro CLI is zijn spec-gestuurde, te reviewen workflow met steering en hooks. Veel teams gebruiken beide — met Open Design kun je van agent wisselen zonder je design-workflow te veranderen."}, {"name": "Hoe verbind ik Kiro CLI met externe designtools?", "text": "Kiro CLI beheert Model Context Protocol (MCP)-servers — gebruik kiro-cli mcp om ze toe te voegen. Een MCP-server kan echte designcontext en tools in de agent brengen zodat gegenereerde code overeenkomt met de bron in plaats van die te benaderen."}, {"name": "Is Open Design verbonden met Amazon of AWS?", "text": "Nee. Kiro is een product van Amazon (AWS); Open Design is een onafhankelijk open-source project dat het ondersteunt als first-party adapter. Kiro is een handelsmerk van Amazon."}, {"name": "Zijn mijn bestanden en credentials veilig?", "text": "Ja — Open Design is local-first en Apache-2.0. Je bestanden, artefacten en DESIGN.md blijven in je eigen repo, en je Kiro-aanmelding wordt rechtstreeks door je agent gebruikt, nooit gerouteerd via Open Design-servers."}], "ctaTitle": "Ontwerp met Kiro CLI, op de open manier.", "ctaBody": "Breng je eigen AWS Builder ID of aanmelding mee, houd elk bestand lokaal, en krijg een samengestelde designbibliotheek rond de agent die je al gebruikt.", "ctaActions": [{"label": "Gebruik Kiro CLI in Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Bekijk alle ondersteunde agents"},
      },
      'kilo': {
        ...en['kilo']!,
        title: "Kilo Code voor design — Open Design",
        description: "Hoe mensen Kilo Code — de open-source, modelonafhankelijke AI-codingagent — gebruiken voor UI- en webdesign: zijn Architect/Code-modi, MCP-ondersteuning, BYOK over vele providers, en hoe Open Design Kilo verandert in een local-first, open-source design-agent.",
        breadcrumb: "Kilo",
        label: "Agent · Kilo",
        heading: "Kilo Code voor design.",
        lead: "Kilo Code is een open-source, modelonafhankelijke AI-codingagent voor je IDE en CLI. Omdat je hem op vrijwel elk model kunt wijzen en je eigen providersleutels kunt meebrengen, wordt hij een echt designtool zodra je hem referenties, conventies en een verificatielus geeft. Open Design verbindt hem met een open-source design-workflow: je providersleutels, je bestanden, local-first.",
        rich: {"heroCtaLead": "Open Design verandert Kilo Code in een local-first, open-source design-agent — je providersleutels, je bestanden, een samengestelde bibliotheek van skills en designsystemen eromheen.", "heroCtaActions": [{"label": "Gebruik Kilo Code in Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Kilo Code is een open-source AI-codingagent die draait in VS Code, JetBrains-IDE's en de terminal. Twee dingen maken hem specifiek interessant voor design: hij is modelonafhankelijk, zodat je hem kunt aansturen met welk frontier-model met beeldverwerking dan ook een screenshot het beste leest; en hij is BYOK over vele providers, zodat je controle over kosten en credentials behoudt. Gecombineerd met de juiste referenties, conventies en een verificatielus bouwt hij echte, responsieve UI. Dit is een praktische, end-to-end gids voor het gebruik van Kilo Code voor UI-, frontend- en designsysteemwerk, en voor het inbedden ervan in een gestructureerde design-workflow met Open Design.", "Het behandelt wat Kilo Code eigenlijk is, waarom een modelonafhankelijke, open agent bij design past, hoe je hem vanaf nul opzet, de screenshot-naar-UI-lus, hoe custom rules en MCP hem uitbreiden, hoe hij zich verhoudt tot Codex, Claude Code, Cursor en Gemini CLI, de valkuilen die AI-output generiek doen lijken, en hoe Open Design de kloof dicht als een open, local-first designlaag — een natuurlijke combinatie, want beide zijn open-source en draaien op je eigen machine."], "heroImage": {"src": "/agents/kilo-design/kilo-design-hero.webp", "alt": "Kilo Code design-feedbacklus: een agent in de IDE en terminal die een referentieafbeelding leest, een browser die de UI rendert, en een werkruimte, met een feedbackpijl die terugloopt", "caption": "De kernlus: Kilo Code leest je referenties in de IDE of CLI, bouwt en verifieert de UI in een echte browser, en itereert daartegen — met het model dat je kiest."}, "tocLabel": "Op deze pagina", "toc": [{"id": "what-is-kilo", "label": "Wat Kilo Code eigenlijk is"}, {"id": "why-design", "label": "Waarom een open, modelonafhankelijke agent bij design past"}, {"id": "setup", "label": "Kilo Code opzetten voor design (vanaf nul)"}, {"id": "screenshot-workflow", "label": "De screenshot-naar-UI-workflow"}, {"id": "extend", "label": "Modi, custom rules en MCP"}, {"id": "vs", "label": "Kilo Code vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Valkuilen en de “AI-slop”-look"}, {"id": "open-design", "label": "Ontwerpen met Kilo Code in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-kilo", "heading": "Wat Kilo Code eigenlijk is", "blocks": [{"kind": "p", "text": "Kilo Code is een open-source AI-codingagent gebouwd door Kilo Code, Inc. Hij draait als een VS Code-extensie, in JetBrains-IDE's en als een command-line-interface — hij leest je repository, bewerkt bestanden, voert opdrachten uit, en plant en verifieert werk vanuit taken in natuurlijke taal in plaats van alleen regels aan te vullen. Zijn bepalende kenmerk is dat hij modelonafhankelijk is: jij kiest welk model hem aanstuurt, en je brengt je eigen providersleutels mee."}, {"kind": "p", "text": "Voor designwerk springen twee eigenschappen eruit. Omdat hij modelonafhankelijk is, kun je hem wijzen op welk sterk model met beeldverwerking dan ook een referentie-screenshot het beste leest en over lay-out redeneert. En omdat hij open-source en BYOK is, kun je precies inspecteren welke context wordt verzonden en credentials en kosten onder je eigen controle houden."}, {"kind": "steps", "items": [{"label": "Agent-modi", "body": "Kilo wordt geleverd met gespecialiseerde modi — Architect voor planning, Code voor bouwen, Debug voor repareren en Ask voor vragen — plus custom modi, zodat je een design kunt plannen en het vervolgens in aparte, gerichte rondes kunt implementeren."}, {"label": "Custom rules + MCP", "body": "Hij leest custom rules op projectniveau voor persistente context en ondersteunt MCP-servers (met een MCP-marktplaats), zodat je externe context kunt toevoegen zoals een live Figma-bestand of designtooling."}, {"label": "Breng je eigen sleutels mee", "body": "Kilo is BYOK over vele providers — Anthropic, OpenAI, Google, OpenRouter en meer — of je kunt Kilo's eigen gateway gebruiken, die 500+ modellen blootstelt tegen providerkosten."}]}, {"kind": "ul", "items": ["Leverancier: Kilo Code, Inc. (open source)", "Credential: je eigen provider-API-sleutel (BYOK — Anthropic, OpenAI, Google, OpenRouter en meer) of Kilo's eigen gateway", "Licentie: open source"]}]}, {"id": "why-design", "heading": "Waarom een open, modelonafhankelijke agent bij design past", "blocks": [{"kind": "p", "text": "Kilo Code's designvoordeel komt voort uit openheid en modelkeuze — maar, zoals bij elke agent, smaak moet nog steeds worden aangeleverd."}, {"kind": "steps", "items": [{"label": "Modelonafhankelijk van opzet", "body": "Omdat jij het model kiest, kun je Kilo aansturen met welk model met beeldverwerking dan ook referentie-screenshots het beste leest — en wisselen wanneer een beter model verschijnt, zonder je workflow te veranderen."}, {"label": "Open en inspecteerbaar", "body": "Kilo is open-source, dus je kunt precies zien welke context en prompts worden verzonden — nuttig wanneer je wilt dat de agent je echte design-primitieven hergebruikt in plaats van eenmalige stijlen te verzinnen."}, {"label": "Conventies in custom rules", "body": "Project-custom-rules (plus een MCP-server voor Figma) wijzen de agent op je tokens, componenten en echte specificaties, zodat hij werkt tegen een merk in plaats van een standaard look."}]}, {"kind": "image", "src": "/agents/kilo-design/kilo-design-taste-triangle.webp", "alt": "Diagram dat toont hoe designsysteem, skill en referentieafbeelding samenkomen tot goede design-output", "caption": "Smaak komt voort uit drie inputs die jij aanlevert: een designsysteem, een skill en echte referentieafbeeldingen."}, {"kind": "p", "text": "De les is dezelfde die elke agent leert: Kilo Code heeft standaard geen smaak. Hij produceert goed design wanneer je hem beperkingen geeft — een designsysteem, een esthetische skill en concrete referenties. Open Design verpakt precies die inputs, en daarom passen de twee bij elkaar (meer hieronder)."}]}, {"id": "setup", "heading": "Kilo Code opzetten voor designwerk, vanaf nul", "blocks": [{"kind": "p", "text": "Hier is het volledige pad van een schone machine naar een Kilo Code die UI kan bouwen en verifiëren."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Kilo Code extension from the VS Code\n#    (or JetBrains) marketplace, or install the CLI.\n\n# 2. Open your project and sign in / add a provider key\ncd your-project\nkilo              # connect your provider (BYOK) or Kilo's gateway\n\n# 3. Add project context\n#    create custom rules for this project's design conventions\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add it from the MCP marketplace / MCP settings"}, {"kind": "image", "src": "/agents/kilo-design/kilo-design-setup-flow.webp", "alt": "Stappenplan in vijf stappen: installeren, authenticeren, custom rules toevoegen, een skill toevoegen, verifiëren", "caption": "De opzetvolgorde: installeren → een provider verbinden → custom rules toevoegen → een skill toevoegen → browserverificatie inschakelen."}, {"kind": "steps", "items": [{"label": "Codeer je designregels", "body": "Plaats je tokens, primitieven en conventies in Kilo's custom rules en wijs de agent erop, zodat output overeenkomt met een merk in plaats van terug te vallen op een generieke look."}, {"label": "Voeg browserverificatie toe", "body": "Bedraad een Playwright- of browser-MCP zodat Kilo rendert in een echte browser en zijn output controleert over breakpoints heen in plaats van alleen te bevestigen dat de build slaagt."}]}]}, {"id": "screenshot-workflow", "heading": "De screenshot-naar-UI-workflow", "blocks": [{"kind": "p", "text": "De designlus met de meeste hefboomwerking met Kilo Code is het omzetten van een referentieafbeelding in werkende, responsieve UI en daarop itereren tot het overeenkomt — leunend op een model met beeldverwerking om output te vergelijken met de referentie."}, {"kind": "ol", "items": ["Begin met de duidelijkste visuele referenties die je hebt — en neem meerdere staten mee (desktop en mobiel, hover, leeg, laden), niet slechts één hero-shot.", "Wees specifiek in de prompt; vage prompts leveren generieke UI op, zelfs met een sterk model.", "Bewaar je designsysteem en conventies in Kilo's custom rules, en vertel de agent waar de tokens en canonieke primitieven leven.", "Draai een dev-server en laat Kilo renderen in een echte browser, met formaataanpassing naar breakpoints om het resultaat te controleren.", "Itereer door Kilo zijn implementatie te laten vergelijken met de screenshots — niet alleen bevestigen dat het bouwt."]}, {"kind": "p", "text": "Gebruik de Architect-modus om de bouw te plannen, wissel dan naar de Code-modus en voeg je referenties toe met concrete beperkingen:"}, {"kind": "code", "lang": "bash", "code": "# Plan in Architect mode, then build in Code mode:\n> Implement this design from @reference-desktop.png and\n  @reference-mobile.png in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens\n  from the custom rules.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the\n  references across breakpoints."}, {"kind": "p", "text": "Houd prompts klein en gericht, commit goede iteraties en draai slechte terug (en vertel Kilo wanneer je terugdraait), zodat elke ronde voortbouwt op een schone basis."}]}, {"id": "extend", "heading": "Modi, custom rules en MCP", "blocks": [{"kind": "p", "text": "Drie uitbreidingspunten maken Kilo Code praktisch voor langdurig designwerk, en alle drie passen netjes op een open design-workflow."}, {"kind": "steps", "items": [{"label": "Modi (Architect → Code)", "body": "Plan de structuur van een scherm in de Architect-modus, implementeer die dan in de Code-modus en repareer problemen in de Debug-modus — waarbij designintentie wordt gescheiden van implementatie. Custom modi laten je een eigen design-reviewronde coderen."}, {"label": "Custom rules", "body": "Project-custom-rules zijn de duurzame thuisbasis voor je designconventies — tokens, primitieven en reviewchecklists — gelezen bij elke run zodat de agent werkt tegen je merk."}, {"label": "MCP-servers", "body": "Kilo ondersteunt MCP-servers via zijn marktplaats — de overdraagbare manier om designcontext en externe tools binnen te halen, het meest relevant een Figma MCP-server, die over agents heen werken, niet alleen Kilo."}]}, {"kind": "p", "text": "Dit zijn overdraagbare, multi-agent-mogelijkheden — precies het soort dingen die Open Design is gebouwd om te orkestreren, in plaats van per project opnieuw te creëren."}]}, {"id": "vs", "heading": "Kilo Code vs Codex vs Claude Code vs Cursor vs Gemini CLI voor design", "blocks": [{"kind": "p", "text": "Er is geen enkele winnaar voor designwerk — elke agent heeft een ander sterk punt, en ervaren teams stapelen ze. Een eerlijke samenvatting:"}, {"kind": "table", "columns": ["Agent", "Designsterkte", "Best voor"], "rows": [["Kilo Code", "Open-source en modelonafhankelijk met BYOK over vele providers; Architect/Code-modi en MCP", "Je eigen model per taak kiezen en kosten en credentials onder je controle houden"], ["Codex", "Sterke visuele afwerking met een frontend-skill; gesandboxte async builds", "Gedelegeerde async builds en overdraagbare AGENTS.md-regels"], ["Claude Code", "Specifieke designbeslissingen (hex, spacing, type) en codebase-bewuste UX", "Frontend-redenering en refactors met grote context"], ["Cursor", "Visuele bouw-en-zie-lus met live preview en inline bewerkingen", "Strak itereren-en-meekijken UI-werk binnen een IDE"], ["Gemini CLI", "Sterk multimodaal beeldbegrip en een context van 1M tokens", "Screenshot-intensief werk en een heel designsysteem in context houden"]]}, {"kind": "p", "text": "Het terugkerende oordeel van de community is dat smaak van mensen komt: ze vallen allemaal terug op een generieke esthetiek zonder skills, referenties en beperkingen. Dat is het echte probleem om op te lossen — en het heeft de vorm van een designtool, niet van een model."}]}, {"id": "pitfalls", "heading": "Valkuilen, en hoe je de “AI-slop”-look vermijdt", "blocks": [{"kind": "p", "text": "De meest voorkomende klacht over door AI gegenereerd design is dat het er generiek uitziet — zachte gradiënten, zwevende panelen, overdreven afgeronde hoeken, dramatische schaduwen, een Inter-en-paars-sfeer die “schreeuwt dat een AI dit heeft gemaakt.” Andere gemelde problemen zijn kapotte mobiele lay-outs en instructies die in de UI-tekst lekken. Geen van deze is uniek voor Kilo Code; ze zijn wat er gebeurt wanneer welke agent dan ook draait zonder een samengestelde designcontext."}, {"kind": "steps", "items": [{"label": "Voeg een esthetische skill toe", "body": "Een samengestelde design-skill dwingt de agent om zich vast te leggen op een echte richting in plaats van de standaard look."}, {"label": "Verifieer in een echte browser", "body": "Gebruik een model met beeldverwerking om te renderen en zichzelf te controleren over breakpoints heen zodat lay-outs niet stilletjes breken op mobiel."}, {"label": "Lever tokens en referenties aan", "body": "Echte design-tokens en referentie-screenshots zijn de grootste enkele hefboom op outputkwaliteit."}, {"label": "Codeer regels in custom rules", "body": "Plaats stijlregels als “geen hero-cards, maximaal twee lettertypes, merk-eerst-hiërarchie” waar de agent ze elke run leest."}]}, {"kind": "p", "text": "Merk op dat elke mitigatie gaat over het geven van een samengestelde designcontext aan de agent. Die context handmatig onderhouden, per project, is het zware werk dat Open Design wegneemt."}]}, {"id": "open-design", "heading": "Ontwerpen met Kilo Code in Open Design", "blocks": [{"kind": "p", "text": "Open Design is de open-source designlaag waar de bovenstaande workflow steeds om vraagt. Het behandelt Kilo Code als een first-party adapter en wikkelt hem in een samengestelde bibliotheek van skills en designsystemen, een gestructureerde render-pijplijn en een lokale desktop-UI — zodat de designcontext die Kilo goed maakt er vanaf de eerste ronde is, niet telkens handmatig samengesteld. Beide zijn open-source en local-first, wat de combinatie een natuurlijke match maakt."}, {"kind": "ol", "items": ["Installeer Open Design en selecteer Kilo Code als je agent.", "Authenticeer met je eigen providersleutel (BYOK) of Kilo's gateway — credentials blijven op je machine en worden nooit via ons doorgesluisd.", "Kies een designsysteem en een skill, en genereer dan decks, prototypes en landingspagina's met consistente smaak.", "Elk artefact en DESIGN.md-bestand leeft in je eigen repo, niet in een gehoste cloud."]}, {"kind": "p", "text": "Dezelfde Kilo Code-agent, dezelfde sleutels — plus een echte, overdraagbare, open-source design-workflow eromheen. Het is local-first en open-source, dus niets van je werk of je credentials verlaat je machine."}]}], "faqTitle": "Veelgestelde vragen", "faq": [{"name": "Kan Kilo Code echt designwerk doen?", "text": "Ja — met een esthetische skill, een designsysteem en echte referentieafbeeldingen in context produceert Kilo Code responsieve UI van productiekwaliteit, en een model met beeldverwerking verifieert output tegen referenties. Zonder die context valt hij doorgaans terug op een generieke look, en dat is de kloof die Open Design dicht."}, {"name": "Moet ik betalen om met Kilo Code te ontwerpen?", "text": "Kilo Code is open-source en gratis te installeren. Je brengt je eigen provider-API-sleutel mee (BYOK) en betaalt die provider rechtstreeks, of gebruikt Kilo's eigen gateway tegen providerkosten. Open Design sluist je credentials sowieso nooit door."}, {"name": "Wat maakt Kilo Code specifiek goed voor design?", "text": "Hij is modelonafhankelijk en open-source, zodat je hem kunt aansturen met welk model met beeldverwerking dan ook referentie-screenshots het beste leest, precies kunt inspecteren welke context wordt verzonden, en kosten en credentials onder je controle kunt houden. Smaak komt nog steeds van het designsysteem, de skill en de referenties die jij aanlevert."}, {"name": "Kilo Code of Claude Code voor frontend-design?", "text": "Beide zijn sterk. Claude Code staat bekend om specifieke, codebase-bewuste designbeslissingen; het voordeel van Kilo Code is dat hij open-source en modelonafhankelijk is met BYOK, zodat jij het model kiest. Veel teams gebruiken beide — met Open Design kun je van agent wisselen zonder je design-workflow te veranderen."}, {"name": "Hoe verbind ik Kilo Code met Figma?", "text": "Voeg een Figma MCP-server toe vanuit Kilo's MCP-marktplaats of MCP-instellingen. Kilo kan dan echte designcontext binnenhalen — componenten, variabelen, lay-outdata — zodat de gegenereerde code overeenkomt met de bron in plaats van die te benaderen."}, {"name": "Is Open Design verbonden met Kilo Code?", "text": "Nee. Kilo Code is een product van Kilo Code, Inc.; Open Design is een onafhankelijk open-source project dat het ondersteunt als first-party adapter. Beide zijn toevallig open-source, maar het zijn aparte projecten."}, {"name": "Zijn mijn bestanden en credentials veilig?", "text": "Ja — Open Design is local-first en open-source. Je bestanden, artefacten en DESIGN.md blijven in je eigen repo, en je provider-credentials worden rechtstreeks door je agent gebruikt, nooit gerouteerd via Open Design-servers."}], "ctaTitle": "Ontwerp met Kilo Code, op de open manier.", "ctaBody": "Breng je eigen providersleutel mee, houd elk bestand lokaal, en krijg een samengestelde designbibliotheek rond de agent die je al gebruikt.", "ctaActions": [{"label": "Gebruik Kilo Code in Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Bekijk alle ondersteunde agents"},
      },
      'vibe': {
        ...en['vibe']!,
        title: "Mistral Vibe CLI voor design — Open Design",
        description: "Hoe mensen Mistral's Vibe CLI gebruiken voor UI- en webdesign — zijn open-weights Devstral-codingmodellen, agentische multi-file bewerking, config.toml, MCP en ACP — en hoe Open Design Vibe CLI verandert in een local-first, open-source design-agent.",
        breadcrumb: "Mistral Vibe CLI",
        label: "Agent · Mistral Vibe CLI",
        heading: "Mistral Vibe CLI voor design.",
        lead: "Mistral Vibe CLI is Mistral AI's open-source terminal-codingagent, aangedreven door de Devstral-modelfamilie. Hij bewerkt bestanden, voert opdrachten uit en werkt via het Agent Client Protocol — wat hem een echt designtool maakt zodra je hem referenties, conventies en een verificatielus geeft. Open Design verbindt hem met een open-source design-workflow: je Mistral-API-sleutel (BYOK) of lokale modellen, je bestanden, local-first.",
        rich: {"heroCtaLead": "Open Design verandert Mistral Vibe CLI in een local-first, open-source design-agent — je Mistral-API-sleutel of lokale Devstral-modellen, je bestanden, een samengestelde bibliotheek van skills en designsystemen eromheen.", "heroCtaActions": [{"label": "Gebruik Vibe CLI in Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Mistral Vibe CLI is Mistral AI's open-source (Apache-2.0) codingagent voor de terminal. Hij scant de bestandsstructuur en Git-status van je project voor context, en verkent, bewerkt en voert dan wijzigingen uit over je codebase vanuit taken in natuurlijke taal. Twee dingen maken hem specifiek interessant voor design: hij wordt aangedreven door Mistrals Devstral-codingmodellen, onderdeel van een open-weights-ecosysteem dat je lokaal of in de cloud kunt draaien; en hij spreekt het Agent Client Protocol (ACP), zodat hij past in editors en tools in plaats van alleen in één terminal te leven. Gecombineerd met de juiste referenties, conventies en een verificatielus bouwt hij echte, responsieve UI. Dit is een praktische, end-to-end gids voor het gebruik van Vibe CLI voor UI-, frontend- en designsysteemwerk, en voor het inbedden ervan in een gestructureerde design-workflow met Open Design.", "Het behandelt wat Vibe CLI eigenlijk is, waarom een open-weights codingagent bij design past, hoe je hem vanaf nul opzet, de referentie-naar-UI-lus, hoe config.toml, MCP en ACP hem uitbreiden, hoe hij zich verhoudt tot Codex, Claude Code, Cursor en Gemini CLI, de valkuilen die AI-output generiek doen lijken, en hoe Open Design de kloof dicht als een open, local-first designlaag — een natuurlijke combinatie, want beide zijn open-source en draaien op je eigen machine."], "heroImage": {"src": "/agents/vibe-design/vibe-design-hero.webp", "alt": "Mistral Vibe CLI design-feedbacklus: een terminal-agent die een referentie leest, een browser die de UI rendert, en een werkruimte, met een feedbackpijl die terugloopt", "caption": "De kernlus: Vibe CLI leest je referenties in de terminal, bouwt en verifieert de UI in een echte browser, en itereert daartegen — aangedreven door Mistrals Devstral-codingmodellen."}, "tocLabel": "Op deze pagina", "toc": [{"id": "what-is-vibe", "label": "Wat Mistral Vibe CLI eigenlijk is"}, {"id": "why-design", "label": "Waarom een open-weights codingagent bij design past"}, {"id": "setup", "label": "Vibe CLI opzetten voor design (vanaf nul)"}, {"id": "screenshot-workflow", "label": "De referentie-naar-UI-workflow"}, {"id": "extend", "label": "config.toml, MCP en ACP"}, {"id": "vs", "label": "Vibe CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Valkuilen en de “AI-slop”-look"}, {"id": "open-design", "label": "Ontwerpen met Vibe CLI in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-vibe", "heading": "Wat Mistral Vibe CLI eigenlijk is", "blocks": [{"kind": "p", "text": "Mistral Vibe CLI is een open-source (Apache-2.0) codingagent die Mistral AI uitbrengt voor de terminal. Hij biedt een interactieve chatinterface met tools voor bestandsmanipulatie, code zoeken, versiebeheer en opdrachtuitvoering, en hij scant automatisch de bestandsstructuur en Git-status van je project om de agent relevante context te geven. Hij wordt aangedreven door Mistrals Devstral-codingmodellen — hij plant en verifieert werk vanuit taken in natuurlijke taal in plaats van alleen regels aan te vullen."}, {"kind": "p", "text": "Voor designwerk springen twee eigenschappen eruit. Hij draait op Mistrals open-weights Devstral-familie (Devstral 2 en de kleinere Devstral Small 2), zodat je de agent kunt draaien tegen de Mistral-API in de cloud of tegen lokale modellen — handig voor privacygevoelig of offline designwerk. En hij spreekt het Agent Client Protocol, zodat dezelfde agent editors en tools kan aansturen, niet alleen één terminalsessie."}, {"kind": "steps", "items": [{"label": "Configuratiebestanden", "body": "Vibe CLI wordt geconfigureerd via een config.toml-bestand (op projectniveau ./.vibe/config.toml, met een fallback op ~/.vibe/config.toml). Het is een praktische plek om je providers, modelkeuze en projectinstellingen te coderen."}, {"label": "Ingebouwde tools + MCP", "body": "Hij wordt geleverd met tools voor bestanden, zoeken, versiebeheer en opdrachtuitvoering, en ondersteunt MCP-servers (geconfigureerd onder een [[mcp_servers]]-sectie) om externe context toe te voegen zoals een live Figma-bestand."}, {"label": "BYOK of lokaal", "body": "Authenticeer met een Mistral-API-sleutel uit de Mistral-console, of wijs hem op lokale/compatibele modellen zodat hij volledig offline werkt."}]}, {"kind": "ul", "items": ["Leverancier: Mistral AI", "Credential: Mistral-API-sleutel (BYOK) uit de Mistral-console, of lokale / compatibele modellen", "Licentie: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Waarom een open-weights codingagent bij design past", "blocks": [{"kind": "p", "text": "Vibe CLI's designvoordeel komt voort uit zijn open-weights modelfamilie en zijn protocolbereik — maar, zoals bij elke agent, smaak moet nog steeds worden aangeleverd."}, {"kind": "steps", "items": [{"label": "Devstral-codingmodellen", "body": "Vibe draait op Mistrals Devstral-familie, coding-afgestemde modellen gebouwd voor agentisch, multi-file werk — zodat de agent bewerkt over een echte frontend-codebase in plaats van geïsoleerde snippets uit te stoten."}, {"label": "Open-weights en lokaal-vriendelijk", "body": "Devstral Small 2 is klein genoeg om op consumentenhardware te draaien, zodat designwerk volledig lokaal en offline kan blijven — referenties en code hoeven je machine nooit te verlaten."}, {"label": "Conventies in config.toml + context", "body": "Projectconfig en je eigen instructies wijzen de agent op je tokens, componenten en echte specificaties, zodat hij werkt tegen een merk in plaats van een standaard look."}]}, {"kind": "image", "src": "/agents/vibe-design/vibe-design-taste-triangle.webp", "alt": "Diagram dat toont hoe designsysteem, skill en referentieafbeelding samenkomen tot goede design-output", "caption": "Smaak komt voort uit drie inputs die jij aanlevert: een designsysteem, een skill en echte referentieafbeeldingen."}, {"kind": "p", "text": "De les is dezelfde die elke agent leert: Vibe CLI heeft standaard geen smaak. Hij produceert goed design wanneer je hem beperkingen geeft — een designsysteem, een esthetische skill en concrete referenties. Open Design verpakt precies die inputs, en daarom passen de twee bij elkaar (meer hieronder)."}]}, {"id": "setup", "heading": "Vibe CLI opzetten voor designwerk, vanaf nul", "blocks": [{"kind": "p", "text": "Hier is het volledige pad van een schone machine naar een Vibe CLI die UI kan bouwen en verifiëren."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Mistral Vibe CLI\nuv tool install mistral-vibe\n# or: pip install mistral-vibe\n\n# 2. Run the setup wizard to register your API key\nvibe --setup     # saves config to ~/.vibe/config.toml and ~/.vibe/.env\n#    or set it directly:  export MISTRAL_API_KEY=...\n\n# 3. Start Vibe in your project\ncd your-project\nvibe\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add an [[mcp_servers]] entry in your config.toml"}, {"kind": "image", "src": "/agents/vibe-design/vibe-design-setup-flow.webp", "alt": "Stappenplan in vijf stappen: installeren, authenticeren, config.toml configureren, een skill toevoegen, verifiëren", "caption": "De opzetvolgorde: installeren → authenticeren → config.toml configureren → een skill toevoegen → browserverificatie inschakelen."}, {"kind": "steps", "items": [{"label": "Codeer je designregels", "body": "Bewaar je tokens, primitieven en conventies waar de agent ze leest en wijs Vibe erop, zodat output overeenkomt met een merk in plaats van terug te vallen op een generieke look."}, {"label": "Voeg browserverificatie toe", "body": "Bedraad een Playwright- of browser-MCP zodat Vibe rendert in een echte browser en zijn output controleert over breakpoints heen in plaats van alleen te bevestigen dat de build slaagt."}]}]}, {"id": "screenshot-workflow", "heading": "De referentie-naar-UI-workflow", "blocks": [{"kind": "p", "text": "De designlus met de meeste hefboomwerking met Vibe CLI is het omzetten van een duidelijke referentie in werkende, responsieve UI en daarop itereren tot het overeenkomt — leunend op de tools van de agent om zijn eigen output te renderen, inspecteren en corrigeren."}, {"kind": "ol", "items": ["Begin met de duidelijkste referenties die je hebt — en beschrijf meerdere staten (desktop en mobiel, hover, leeg, laden), niet slechts één hero-shot.", "Wees specifiek in de prompt; vage prompts leveren generieke UI op, zelfs met een sterk model.", "Bewaar je designsysteem en conventies waar Vibe ze leest, en vertel hem waar de tokens en canonieke primitieven leven.", "Draai een dev-server en laat Vibe renderen in een echte browser, met formaataanpassing naar breakpoints om het resultaat te controleren.", "Itereer door Vibe zijn implementatie te laten vergelijken met de referenties — niet alleen bevestigen dat het bouwt."]}, {"kind": "p", "text": "Verwijs naar bestanden met @ (Vibe vult bestandspaden automatisch aan) en stuur slash-commando's aan met /, en geef dan concrete beperkingen:"}, {"kind": "code", "lang": "bash", "code": "vibe\n# in the prompt:\n> @design-spec.md @tokens.css\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, render it in the browser, and iterate until\n  it matches the references across breakpoints."}, {"kind": "p", "text": "Houd prompts klein en gericht, commit goede iteraties en draai slechte terug (en vertel Vibe wanneer je terugdraait), zodat elke ronde voortbouwt op een schone basis."}]}, {"id": "extend", "heading": "config.toml, MCP en ACP", "blocks": [{"kind": "p", "text": "Drie uitbreidingspunten maken Vibe CLI praktisch voor langdurig designwerk, en alle drie passen netjes op een open design-workflow."}, {"kind": "steps", "items": [{"label": "config.toml", "body": "Projectregels en provider-/modelinstellingen leven in een config.toml (op projectniveau, met een ~/.vibe-fallback). Het is de duurzame thuisbasis voor hoe de agent in je project is bedraad, gelezen bij elke run."}, {"label": "MCP-servers", "body": "Configureer MCP-servers in je config.toml ([[mcp_servers]], met HTTP-, streamable-HTTP- en stdio-transporten) — de overdraagbare manier om designcontext en externe tools binnen te halen, het meest relevant de Figma MCP-server, die over agents heen werken, niet alleen Vibe."}, {"label": "Agent Client Protocol", "body": "Vibe spreekt ACP, zodat dezelfde agent kan worden aangestuurd vanuit editors en andere ACP-clients. Dit is precies hoe Open Design hem integreert — via ACP met de vibe-acp-binary."}]}, {"kind": "p", "text": "Dit zijn overdraagbare, multi-agent-mogelijkheden — precies het soort dingen die Open Design is gebouwd om te orkestreren, in plaats van per project opnieuw te creëren."}]}, {"id": "vs", "heading": "Vibe CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI voor design", "blocks": [{"kind": "p", "text": "Er is geen enkele winnaar voor designwerk — elke agent heeft een ander sterk punt, en ervaren teams stapelen ze. Een eerlijke samenvatting:"}, {"kind": "table", "columns": ["Agent", "Designsterkte", "Best voor"], "rows": [["Mistral Vibe CLI", "Open-weights Devstral-codingmodellen die je lokaal kunt draaien; Apache-2.0 en ACP-native", "Privacygevoelig of offline designwerk en een open-weights stack"], ["Codex", "Sterke visuele afwerking met een frontend-skill; gesandboxte async builds", "Gedelegeerde async builds en overdraagbare AGENTS.md-regels"], ["Claude Code", "Specifieke designbeslissingen (hex, spacing, type) en codebase-bewuste UX", "Frontend-redenering en refactors met grote context"], ["Cursor", "Visuele bouw-en-zie-lus met live preview en inline bewerkingen", "Strak itereren-en-meekijken UI-werk binnen een IDE"], ["Gemini CLI", "Sterk multimodaal beeldbegrip en een zeer groot contextvenster", "Screenshot-intensief werk en een heel designsysteem in context houden"]]}, {"kind": "p", "text": "Het terugkerende oordeel van de community is dat smaak van mensen komt: ze vallen allemaal terug op een generieke esthetiek zonder skills, referenties en beperkingen. Dat is het echte probleem om op te lossen — en het heeft de vorm van een designtool, niet van een model."}]}, {"id": "pitfalls", "heading": "Valkuilen, en hoe je de “AI-slop”-look vermijdt", "blocks": [{"kind": "p", "text": "De meest voorkomende klacht over door AI gegenereerd design is dat het er generiek uitziet — zachte gradiënten, zwevende panelen, overdreven afgeronde hoeken, dramatische schaduwen, een Inter-en-paars-sfeer die “schreeuwt dat een AI dit heeft gemaakt.” Andere gemelde problemen zijn kapotte mobiele lay-outs en instructies die in de UI-tekst lekken. Geen van deze is uniek voor Vibe CLI; ze zijn wat er gebeurt wanneer welke agent dan ook draait zonder een samengestelde designcontext."}, {"kind": "steps", "items": [{"label": "Voeg een esthetische skill toe", "body": "Een samengestelde design-skill dwingt de agent om zich vast te leggen op een echte richting in plaats van de standaard look."}, {"label": "Verifieer in een echte browser", "body": "Laat Vibe renderen en zichzelf controleren over breakpoints heen zodat lay-outs niet stilletjes breken op mobiel."}, {"label": "Lever tokens en referenties aan", "body": "Echte design-tokens en referentie-screenshots zijn de grootste enkele hefboom op outputkwaliteit."}, {"label": "Codeer regels in config en context", "body": "Plaats stijlregels als “geen hero-cards, maximaal twee lettertypes, merk-eerst-hiërarchie” waar de agent ze elke run leest."}]}, {"kind": "p", "text": "Merk op dat elke mitigatie gaat over het geven van een samengestelde designcontext aan de agent. Die context handmatig onderhouden, per project, is het zware werk dat Open Design wegneemt."}]}, {"id": "open-design", "heading": "Ontwerpen met Vibe CLI in Open Design", "blocks": [{"kind": "p", "text": "Open Design is de open-source designlaag waar de bovenstaande workflow steeds om vraagt. Het behandelt Mistral Vibe CLI als een first-party adapter — en stuurt hem aan via ACP met de vibe-acp-binary — en wikkelt hem in een samengestelde bibliotheek van skills en designsystemen, een gestructureerde render-pijplijn en een lokale desktop-UI. Zo is de designcontext die Vibe goed maakt er vanaf de eerste ronde, niet telkens handmatig samengesteld. Beide zijn open-source en local-first, wat de combinatie een natuurlijke match maakt."}, {"kind": "ol", "items": ["Installeer Open Design en selecteer Mistral Vibe CLI als je agent.", "Authenticeer met je Mistral-API-sleutel (BYOK) of wijs Vibe op lokale modellen — credentials blijven op je machine en worden nooit via ons doorgesluisd.", "Kies een designsysteem en een skill, en genereer dan decks, prototypes en landingspagina's met consistente smaak.", "Elk artefact en DESIGN.md-bestand leeft in je eigen repo, niet in een gehoste cloud."]}, {"kind": "p", "text": "Dezelfde Vibe CLI-agent, dezelfde sleutel — plus een echte, overdraagbare, open-source design-workflow eromheen. Het is local-first en Apache-2.0, dus niets van je werk of je credentials verlaat je machine."}]}], "faqTitle": "Veelgestelde vragen", "faq": [{"name": "Kan Mistral Vibe CLI echt designwerk doen?", "text": "Ja — met een esthetische skill, een designsysteem en echte referenties in context produceert Vibe CLI responsieve UI van productiekwaliteit, en zijn Devstral-modellen bewerken over een echte frontend-codebase. Zonder die context valt hij doorgaans terug op een generieke look, en dat is de kloof die Open Design dicht."}, {"name": "Hoe authenticeer ik Vibe CLI?", "text": "Draai de setup-wizard met vibe --setup om een Mistral-API-sleutel te registreren (uit de Mistral-console), of stel MISTRAL_API_KEY in je omgeving in. Hij kan ook draaien tegen lokale of compatibele modellen, volledig offline. Open Design sluist je credentials sowieso nooit door."}, {"name": "Wat maakt Vibe CLI specifiek goed voor design?", "text": "Hij is een Apache-2.0, ACP-native agent aangedreven door Mistrals open-weights Devstral-codingmodellen — zodat je hem lokaal kunt draaien voor privacygevoelig werk en kunt bewerken over een echte codebase. Maar smaak komt nog steeds van het designsysteem, de skill en de referenties die jij aanlevert."}, {"name": "Vibe CLI of Claude Code voor frontend-design?", "text": "Beide zijn sterk. Claude Code staat bekend om specifieke, codebase-bewuste designbeslissingen; het voordeel van Vibe CLI is een open-weights Devstral-stack die je lokaal kunt draaien en een Apache-2.0-licentie. Veel teams gebruiken beide — met Open Design kun je van agent wisselen zonder je design-workflow te veranderen."}, {"name": "Hoe verbind ik Vibe CLI met Figma?", "text": "Voeg de Figma MCP-server toe als een [[mcp_servers]]-entry in je config.toml. Vibe kan dan echte designcontext binnenhalen — componenten, variabelen, lay-outdata — zodat de gegenereerde code overeenkomt met de bron in plaats van die te benaderen."}, {"name": "Is Open Design verbonden met Mistral AI?", "text": "Nee. Mistral Vibe CLI is een product van Mistral AI; Open Design is een onafhankelijk open-source project dat het ondersteunt als first-party adapter, aangestuurd via ACP. Mistral is een handelsmerk van Mistral AI."}, {"name": "Zijn mijn bestanden en credentials veilig?", "text": "Ja — Open Design is local-first en Apache-2.0. Je bestanden, artefacten en DESIGN.md blijven in je eigen repo, en je Mistral-credentials worden rechtstreeks door je agent gebruikt, nooit gerouteerd via Open Design-servers."}], "ctaTitle": "Ontwerp met Mistral Vibe CLI, op de open manier.", "ctaBody": "Breng je eigen Mistral-API-sleutel of lokale modellen mee, houd elk bestand lokaal, en krijg een samengestelde designbibliotheek rond de agent die je al gebruikt.", "ctaActions": [{"label": "Gebruik Vibe CLI in Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Bekijk alle ondersteunde agents"},
      },
      'qoder': {
        ...en['qoder']!,
        title: "Qoder CLI voor design — Open Design",
        description: "Hoe mensen Qoder CLI — Alibaba's agentische codingplatform — gebruiken voor UI- en webdesign: zijn agent- en quest-modi, diep repository-begrip en repo-wiki, en Lite/Efficient/Auto-modeltiers — en hoe Open Design Qoder CLI verandert in een local-first, open-source design-agent.",
        breadcrumb: "Qoder CLI",
        label: "Agent · Qoder CLI",
        heading: "Qoder CLI voor design.",
        lead: "Qoder CLI is de terminal-agent van Qoder, Alibaba's agentische codingplatform. Hij begrijpt een hele repository — architectuur, patronen en de conventies vastgelegd in zijn repo-wiki — en draait spec-gestuurd, autonoom werk, wat hem een echt designtool maakt zodra je hem referenties, conventies en een verificatielus geeft. Open Design verbindt hem met een open-source design-workflow: je Qoder-account, je bestanden, local-first.",
        rich: {"heroCtaLead": "Open Design verandert Qoder CLI in een local-first, open-source design-agent — je Qoder-account, je bestanden, een samengestelde bibliotheek van skills en designsystemen eromheen.", "heroCtaActions": [{"label": "Gebruik Qoder CLI in Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Qoder CLI is de terminal-agent van Qoder, Alibaba's agentische codingplatform. Twee dingen maken hem specifiek interessant voor design: hij bouwt diepe context op je repository — architectuur, designpatronen en de conventies die hij distilleert in een repository-wiki — zodat hij je echte primitieven hergebruikt in plaats van eenmalige stijlen te verzinnen; en hij draait spec-gestuurde, autonome quests die een taak van begin tot eind plannen, implementeren en verifiëren in plaats van alleen regels aan te vullen. Gecombineerd met de juiste referenties, conventies en een verificatielus bouwt hij echte, responsieve UI. Dit is een praktische, end-to-end gids voor het gebruik van Qoder CLI voor UI-, frontend- en designsysteemwerk, en voor het inbedden ervan in een gestructureerde design-workflow met Open Design.", "Het behandelt wat Qoder CLI eigenlijk is, waarom zijn repo-begrip en agentische quests bij design passen, hoe je hem vanaf nul opzet, de referentie-naar-UI-lus, hoe rules, MCP en de repo-wiki hem uitbreiden, hoe hij zich verhoudt tot Codex, Claude Code, Cursor en Gemini CLI, de valkuilen die AI-output generiek doen lijken, en hoe Open Design de kloof dicht als een open, local-first designlaag rond de agent die je al gebruikt."], "heroImage": {"src": "/agents/qoder-design/qoder-design-hero.webp", "alt": "Qoder CLI design-feedbacklus: een terminal-agent die een referentieafbeelding leest met repo-wiki-context, een browser die de UI rendert, en een werkruimte, met een feedbackpijl die terugloopt", "caption": "De kernlus: Qoder CLI leest je referenties en repo-context in de terminal, bouwt en verifieert de UI in een echte browser, en itereert daartegen."}, "tocLabel": "Op deze pagina", "toc": [{"id": "what-is-qoder", "label": "Wat Qoder CLI eigenlijk is"}, {"id": "why-design", "label": "Waarom agentisch + repo-context bij design passen"}, {"id": "setup", "label": "Qoder CLI opzetten voor design (vanaf nul)"}, {"id": "screenshot-workflow", "label": "De referentie-naar-UI-workflow"}, {"id": "extend", "label": "Rules, MCP en de repo-wiki"}, {"id": "vs", "label": "Qoder CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Valkuilen en de “AI-slop”-look"}, {"id": "open-design", "label": "Ontwerpen met Qoder CLI in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-qoder", "heading": "Wat Qoder CLI eigenlijk is", "blocks": [{"kind": "p", "text": "Qoder is een agentisch codingplatform van Alibaba — een AI-ontwikkelomgeving, beschikbaar als een desktop-app en een CLI, die echte codebases begrijpt en ontwikkeltaken van begin tot eind afhandelt. Qoder CLI brengt die engine naar de terminal: hij leest je repository, bewerkt bestanden, voert shell-opdrachten uit en werkt door taken vanuit natuurlijke taal in plaats van alleen regels aan te vullen. Hij logt in met een Qoder-account."}, {"kind": "p", "text": "Voor designwerk springen twee eigenschappen eruit. Qoder bouwt diepe context op je repository — architectuur, designpatronen en conventies gedistilleerd in een repository-wiki — zodat hij output verankert in je echte primitieven. En hij draait een agentische, specificatie-gestuurde workflow: je schetst wat je wilt en hij plant, implementeert en verifieert het werk, ook over meerdere stappen heen."}, {"kind": "steps", "items": [{"label": "Agent- en Quest-modi", "body": "De Agent-modus is conversationeel pair-programmeren met human-in-the-loop-checkpoints; de Quest-modus delegeert langer, meerstaps werk aan een autonome agent die plant, implementeert en zichzelf verifieert — de natuurlijke plek om een spec-gestuurde designtaak over te dragen."}, {"label": "Repo-wiki + MCP", "body": "Qoder distilleert je codebase tot een repository-wiki van architectuur en conventies, en ondersteunt MCP-servers om externe context binnen te halen zoals een live Figma-bestand."}, {"label": "Modeltiers", "body": "Qoder CLI biedt Lite-, Efficient- en Auto-tiers; Auto laat zijn scheduler een model per taak kiezen, zodat je modelselectie niet handmatig beheert."}]}, {"kind": "ul", "items": ["Leverancier: Alibaba", "Credential: Qoder-account (inloggen via browser, of een Qoder personal access token voor niet-interactief gebruik)", "Modeltiers: Lite, Efficient, Auto"]}]}, {"id": "why-design", "heading": "Waarom een agentische, repo-bewuste agent bij design past", "blocks": [{"kind": "p", "text": "Qoder CLI's designvoordeel komt voort uit twee eigenschappen — maar, zoals bij elke agent, smaak moet nog steeds worden aangeleverd."}, {"kind": "steps", "items": [{"label": "Diep repository-begrip", "body": "Omdat Qoder context bouwt op je hele codebase en die distilleert in een repo-wiki, hergebruikt de agent je bestaande componenten en tokens in plaats van voor elk scherm eenmalige stijlen te verzinnen."}, {"label": "Spec-gestuurde, autonome quests", "body": "De Quest-modus verandert een geschreven specificatie in een geplant, geïmplementeerd en zelf-geverifieerd resultaat, zodat een designtaak van begin tot eind draait in plaats van te stoppen bij een eerste concept."}, {"label": "Conventies die de agent leest", "body": "Projectregels (plus de Figma MCP-server) wijzen de agent op je tokens, componenten en echte specificaties, zodat hij werkt tegen een merk in plaats van een standaard look."}]}, {"kind": "image", "src": "/agents/qoder-design/qoder-design-taste-triangle.webp", "alt": "Diagram dat toont hoe designsysteem, skill en referentieafbeelding samenkomen tot goede design-output", "caption": "Smaak komt voort uit drie inputs die jij aanlevert: een designsysteem, een skill en echte referentieafbeeldingen."}, {"kind": "p", "text": "De les is dezelfde die elke agent leert: Qoder CLI heeft standaard geen smaak. Hij produceert goed design wanneer je hem beperkingen geeft — een designsysteem, een esthetische skill en concrete referenties. Open Design verpakt precies die inputs, en daarom passen de twee bij elkaar (meer hieronder)."}]}, {"id": "setup", "heading": "Qoder CLI opzetten voor designwerk, vanaf nul", "blocks": [{"kind": "p", "text": "Hier is het volledige pad van een schone machine naar een Qoder CLI die UI kan bouwen en verifiëren."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Qoder CLI (Node 20+)\nnpm install -g @qoder-ai/qodercli\n# (macOS/Linux via Homebrew also available)\n\n# 2. Verify the install\nqodercli --version\n\n# 3. Start it in your project and sign in on first run\ncd your-project\nqodercli          # then /login — sign in via browser or a Qoder access token\n\n# 4. Pick a model tier for the session\n#    Lite, Efficient, or Auto (Auto lets the scheduler choose per task)"}, {"kind": "image", "src": "/agents/qoder-design/qoder-design-setup-flow.webp", "alt": "Stappenplan in vijf stappen: installeren, authenticeren, rules configureren, een skill toevoegen, verifiëren", "caption": "De opzetvolgorde: installeren → inloggen → projectregels configureren → een skill toevoegen → browserverificatie inschakelen."}, {"kind": "steps", "items": [{"label": "Codeer je designregels", "body": "Plaats je tokens, primitieven en conventies waar de agent ze leest, zodat output overeenkomt met een merk in plaats van terug te vallen op een generieke look. Qoder's repo-wiki helpt die context actueel te houden."}, {"label": "Voeg browserverificatie toe", "body": "Bedraad een Playwright- of browser-MCP zodat Qoder rendert in een echte browser en zijn output controleert over breakpoints heen in plaats van alleen te bevestigen dat de build slaagt."}]}]}, {"id": "screenshot-workflow", "heading": "De referentie-naar-UI-workflow", "blocks": [{"kind": "p", "text": "De designlus met de meeste hefboomwerking met Qoder CLI is het omzetten van een referentie in werkende, responsieve UI en daarop itereren tot het overeenkomt — leunend op de repo-context van de agent en een echte verificatielus om output te vergelijken met de referentie."}, {"kind": "ol", "items": ["Begin met de duidelijkste visuele referenties die je hebt — en neem meerdere staten mee (desktop en mobiel, hover, leeg, laden), niet slechts één hero-shot.", "Wees specifiek in de prompt; vage prompts leveren generieke UI op, zelfs met een capabele agent.", "Wijs Qoder op je designsysteem en conventies, en vertel hem waar de tokens en canonieke primitieven leven.", "Draai een dev-server en laat Qoder renderen in een echte browser, met formaataanpassing naar breakpoints om het resultaat te controleren.", "Itereer door Qoder zijn implementatie te laten vergelijken met de referenties — niet alleen bevestigen dat het bouwt."]}, {"kind": "p", "text": "Schrijf de taak als een duidelijke spec en laat een quest die uitvoeren, en geef concrete beperkingen:"}, {"kind": "code", "lang": "bash", "code": "qodercli\n# in the prompt:\n> Implement this design from reference-desktop.png and\n  reference-mobile.png in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Houd prompts klein en gericht, commit goede iteraties en draai slechte terug (en vertel Qoder wanneer je terugdraait), zodat elke ronde voortbouwt op een schone basis."}]}, {"id": "extend", "heading": "Rules, MCP en de repo-wiki", "blocks": [{"kind": "p", "text": "Drie uitbreidingspunten maken Qoder CLI praktisch voor langdurig designwerk, en alle drie passen netjes op een open design-workflow."}, {"kind": "steps", "items": [{"label": "Projectregels", "body": "Codeer je designconventies als duurzame projectregels die de agent elke run leest — de thuisbasis voor tokens, primitieven en reviewchecklists."}, {"label": "MCP-servers", "body": "MCP is de overdraagbare manier om designcontext en externe tools binnen te halen, het meest relevant de Figma MCP-server, en het werkt over agents heen, niet alleen Qoder."}, {"label": "De repo-wiki", "body": "Qoder's repository-wiki distilleert architectuur en conventies automatisch, zodat de agent je echte componenten blijft hergebruiken in plaats van de codebase bij elke taak opnieuw te leren."}]}, {"kind": "p", "text": "Dit zijn overdraagbare, multi-agent-mogelijkheden — precies het soort dingen die Open Design is gebouwd om te orkestreren, in plaats van per project opnieuw te creëren."}]}, {"id": "vs", "heading": "Qoder CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI voor design", "blocks": [{"kind": "p", "text": "Er is geen enkele winnaar voor designwerk — elke agent heeft een ander sterk punt, en ervaren teams stapelen ze. Een eerlijke samenvatting:"}, {"kind": "table", "columns": ["Agent", "Designsterkte", "Best voor"], "rows": [["Qoder CLI", "Diep repository-begrip met een repo-wiki en spec-gestuurde, autonome quests; Lite/Efficient/Auto-tiers", "Repo-context-intensief werk en het delegeren van meerstaps, spec-gestuurde builds"], ["Codex", "Sterke visuele afwerking met een frontend-skill; gesandboxte async builds", "Gedelegeerde async builds en overdraagbare AGENTS.md-regels"], ["Claude Code", "Specifieke designbeslissingen (hex, spacing, type) en codebase-bewuste UX", "Frontend-redenering en refactors met grote context"], ["Cursor", "Visuele bouw-en-zie-lus met live preview en inline bewerkingen", "Strak itereren-en-meekijken UI-werk binnen een IDE"], ["Gemini CLI", "Sterk multimodaal beeldbegrip en een context van 1M tokens; gratis laag", "Screenshot-intensief werk en een heel designsysteem in context houden"]]}, {"kind": "p", "text": "Het terugkerende oordeel van de community is dat smaak van mensen komt: ze vallen allemaal terug op een generieke esthetiek zonder skills, referenties en beperkingen. Dat is het echte probleem om op te lossen — en het heeft de vorm van een designtool, niet van een model."}]}, {"id": "pitfalls", "heading": "Valkuilen, en hoe je de “AI-slop”-look vermijdt", "blocks": [{"kind": "p", "text": "De meest voorkomende klacht over door AI gegenereerd design is dat het er generiek uitziet — zachte gradiënten, zwevende panelen, overdreven afgeronde hoeken, dramatische schaduwen, een Inter-en-paars-sfeer die “schreeuwt dat een AI dit heeft gemaakt.” Andere gemelde problemen zijn kapotte mobiele lay-outs en instructies die in de UI-tekst lekken. Geen van deze is uniek voor Qoder CLI; ze zijn wat er gebeurt wanneer welke agent dan ook draait zonder een samengestelde designcontext."}, {"kind": "steps", "items": [{"label": "Voeg een esthetische skill toe", "body": "Een samengestelde design-skill dwingt de agent om zich vast te leggen op een echte richting in plaats van de standaard look."}, {"label": "Verifieer in een echte browser", "body": "Render en controleer zichzelf over breakpoints heen zodat lay-outs niet stilletjes breken op mobiel."}, {"label": "Lever tokens en referenties aan", "body": "Echte design-tokens en referentie-screenshots zijn de grootste enkele hefboom op outputkwaliteit."}, {"label": "Codeer regels die de agent leest", "body": "Plaats stijlregels als “geen hero-cards, maximaal twee lettertypes, merk-eerst-hiërarchie” in projectregels en de repo-wiki, waar de agent ze elke run leest."}]}, {"kind": "p", "text": "Merk op dat elke mitigatie gaat over het geven van een samengestelde designcontext aan de agent. Die context handmatig onderhouden, per project, is het zware werk dat Open Design wegneemt."}]}, {"id": "open-design", "heading": "Ontwerpen met Qoder CLI in Open Design", "blocks": [{"kind": "p", "text": "Open Design is de open-source designlaag waar de bovenstaande workflow steeds om vraagt. Het behandelt Qoder CLI als een first-party adapter en wikkelt hem in een samengestelde bibliotheek van skills en designsystemen, een gestructureerde render-pijplijn en een lokale desktop-UI — zodat de designcontext die Qoder goed maakt er vanaf de eerste ronde is, niet telkens handmatig samengesteld. Open Design is local-first, dus je werk blijft op je eigen machine."}, {"kind": "ol", "items": ["Installeer Open Design en selecteer Qoder CLI als je agent.", "Authenticeer met je Qoder-account — credentials blijven op je machine en worden nooit via ons doorgesluisd.", "Kies een designsysteem en een skill, en genereer dan decks, prototypes en landingspagina's met consistente smaak.", "Elk artefact en DESIGN.md-bestand leeft in je eigen repo, niet in een gehoste cloud."]}, {"kind": "p", "text": "Dezelfde Qoder CLI-agent, hetzelfde account — plus een echte, overdraagbare, open-source design-workflow eromheen. Het is local-first en Apache-2.0, dus niets van je werk of je credentials verlaat je machine."}]}], "faqTitle": "Veelgestelde vragen", "faq": [{"name": "Kan Qoder CLI echt designwerk doen?", "text": "Ja — met een esthetische skill, een designsysteem en echte referentieafbeeldingen in context produceert Qoder CLI responsieve UI van productiekwaliteit, en zijn diepe repository-begrip helpt hem je echte componenten te hergebruiken. Zonder die context valt hij doorgaans terug op een generieke look, en dat is de kloof die Open Design dicht."}, {"name": "Hoe authenticeer ik Qoder CLI?", "text": "Draai qodercli en gebruik /login om in te loggen met je Qoder-account via de browser, of lever een Qoder personal access token aan voor niet-interactieve omgevingen. Open Design sluist je credentials nooit door — de agent gebruikt ze rechtstreeks."}, {"name": "Wat maakt Qoder CLI specifiek goed voor design?", "text": "Twee dingen: hij bouwt diepe context op je repository — architectuur, conventies en een repo-wiki — zodat hij je echte primitieven hergebruikt, en zijn spec-gestuurde quests draaien een designtaak van begin tot eind. Beide helpen, maar smaak komt nog steeds van het designsysteem, de skill en de referenties die jij aanlevert."}, {"name": "Wat zijn de Lite-, Efficient- en Auto-modeltiers?", "text": "Qoder CLI laat je een modeltier kiezen: Lite, Efficient of Auto. Auto laat Qoder's scheduler een model per taak kiezen, zodat je modelselectie niet handmatig beheert. Kies de tier die bij de klus past; Auto is een verstandige standaard."}, {"name": "Hoe verbind ik Qoder CLI met Figma?", "text": "Voeg de Figma MCP-server toe aan Qoder's MCP-configuratie. Qoder kan dan echte designcontext binnenhalen — componenten, variabelen, lay-outdata — zodat de gegenereerde code overeenkomt met de bron in plaats van die te benaderen."}, {"name": "Is Open Design verbonden met Qoder of Alibaba?", "text": "Nee. Qoder is een product van Alibaba; Open Design is een onafhankelijk open-source project dat het ondersteunt als first-party adapter. Qoder is een handelsmerk van zijn respectieve eigenaar."}, {"name": "Zijn mijn bestanden en credentials veilig?", "text": "Ja — Open Design is local-first en Apache-2.0. Je bestanden, artefacten en DESIGN.md blijven in je eigen repo, en je Qoder-credentials worden rechtstreeks door je agent gebruikt, nooit gerouteerd via Open Design-servers."}], "ctaTitle": "Ontwerp met Qoder CLI, op de open manier.", "ctaBody": "Breng je eigen Qoder-account mee, houd elk bestand lokaal, en krijg een samengestelde designbibliotheek rond de agent die je al gebruikt.", "ctaActions": [{"label": "Gebruik Qoder CLI in Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Bekijk alle ondersteunde agents"},
      },
    },
  };
}
